import type { QAItem } from '../interview-data'

export const TOOLS_MISC_DATA: QAItem[] = [
  // === STATE MANAGEMENT: Redux & RTK (601-615) ===
  { id: 601, category: "State Management", subcategory: "Redux", level: "beginner", q: "Redux là gì? Tại sao chúng ta cần sử dụng Redux?", a: "Redux là thư viện quản lý state tập trung cho JavaScript, thường dùng với React. Nó lưu toàn bộ state ứng dụng trong một store duy nhất, giúp dễ dàng theo dõi, debug và chia sẻ state giữa các component không liên kết trực tiếp. Ví dụ thực tế: trong app có UserProfile ở header và ShoppingCart ở sidebar cùng cần thông tin user đang đăng nhập — không cần prop drilling qua nhiều cấp, cả hai đọc thẳng từ Redux store. Redux đặc biệt có giá trị khi dùng Redux DevTools để time-travel debug, replay lại từng action để tái hiện bug. Pitfall: nhiều team dùng Redux cho mọi thứ kể cả state local của form — điều đó làm code phức tạp không cần thiết, chỉ nên dùng Redux cho state thật sự cần chia sẻ toàn app." },
  { id: 602, category: "State Management", subcategory: "Redux", level: "beginner", q: "Ba nguyên tắc cốt lõi của Redux là gì?", a: "Ba nguyên tắc cốt lõi của Redux: (1) Single source of truth — toàn bộ state nằm trong một store duy nhất, giúp đồng bộ data giữa các component và dễ serialize/restore state (ví dụ: lưu state vào localStorage rồi hydrate lại khi reload). (2) State is read-only — không được mutate state trực tiếp, chỉ thay đổi qua dispatch action, điều này tạo ra audit trail rõ ràng cho mọi thay đổi, là nền tảng để Redux DevTools time-travel hoạt động. (3) Changes are made with pure functions — reducer phải là pure function, cùng input luôn cho cùng output, không có side effects. Pitfall phổ biến: vi phạm nguyên tắc (3) bằng cách gọi API hoặc `Date.now()` trong reducer — side effects phải nằm trong middleware (thunk/saga). Nhiều developer mới cũng vi phạm nguyên tắc (2) bằng cách `state.items.push(item)` trong Redux thuần — chỉ Redux Toolkit với Immer mới cho phép cú pháp này." },
  { id: 603, category: "State Management", subcategory: "Redux", level: "beginner", q: "Action trong Redux là gì? Cấu trúc của một action như thế nào?", a: "Action là plain JavaScript object mô tả sự kiện xảy ra trong ứng dụng, bắt buộc có trường `type` (string định danh) và thường có `payload` chứa dữ liệu. Ví dụ: `{ type: 'cart/addItem', payload: { id: 1, name: 'iPhone', qty: 1 } }`. Quy ước đặt tên `type` theo format `domain/eventName` giúp dễ đọc trong DevTools. Action creator là function trả về action object: `const addItem = (item) => ({ type: 'cart/addItem', payload: item })` — giúp tránh typo và tái sử dụng. Với Redux Toolkit, `createSlice` tự động tạo action creators và action types, không cần viết tay. Pitfall: đừng đặt non-serializable values vào action (Promise, class instance, function) vì sẽ phá vỡ DevTools time-travel và middleware như `redux-persist`." },
  { id: 604, category: "State Management", subcategory: "Redux", level: "beginner", q: "Reducer trong Redux là gì? Cách viết một reducer đúng chuẩn?", a: "Reducer là pure function nhận `(state, action)` và trả về state mới — không được mutate state trực tiếp mà phải tạo bản sao mới. Ví dụ đúng: `case 'ADD_TODO': return [...state, action.payload]` thay vì `state.push(action.payload)`. Pure function nghĩa là không có side effects, không gọi API, không random — cùng input luôn cho cùng output, điều này giúp Redux DevTools time-travel hoạt động được. Luôn có `default: return state` để tránh trả về `undefined` khi action không khớp. Với Redux Toolkit, dùng Immer bên trong nên được phép viết `state.todos.push(item)` mà vẫn immutable thật sự." },
  { id: 605, category: "State Management", subcategory: "Redux", level: "beginner", q: "Store trong Redux là gì? Các phương thức chính của store là gì?", a: "Store là object trung tâm lưu trữ toàn bộ state tree của ứng dụng, được tạo bằng `configureStore()` (RTK) hoặc `createStore()` (legacy). Ba phương thức chính: `getState()` trả về state hiện tại, `dispatch(action)` gửi action qua middleware rồi đến reducer để cập nhật state, `subscribe(listener)` đăng ký callback được gọi sau mỗi dispatch. Trong thực tế với React, bạn hiếm khi gọi trực tiếp các phương thức này vì `react-redux` đã wrap chúng qua `useSelector` (thay getState + subscribe) và `useDispatch` (thay dispatch). Pitfall: chỉ nên có MỘT store duy nhất trong app — nhiều store phá vỡ nguyên tắc single source of truth và làm DevTools không hoạt động đúng. Với RTK, `configureStore` tự động setup Redux DevTools, thunk middleware, và development checks (phát hiện accidental mutation)." },
  { id: 606, category: "State Management", subcategory: "Redux", level: "intermediate", q: "Redux Toolkit (RTK) là gì? Tại sao nên dùng RTK thay vì Redux thuần?", a: "Redux Toolkit (RTK) là bộ công cụ chính thức và là cách duy nhất được khuyến nghị để viết Redux hiện đại — Redux thuần giờ được coi là legacy. RTK giải quyết 3 vấn đề lớn của Redux thuần: (1) quá nhiều boilerplate (actions, action types, reducers, combineReducers riêng biệt) → `createSlice` gộp tất cả vào một chỗ. (2) Immutable update phức tạp (`{...state, nested: {...state.nested, value: newVal}}`) → Immer bên trong cho phép viết `state.nested.value = newVal`. (3) Async logic verbose → `createAsyncThunk` xử lý pending/fulfilled/rejected tự động. Thêm RTK Query cho data fetching và caching, cạnh tranh trực tiếp với React Query. Ví dụ thực tế: 1 feature Redux thuần cần 4-5 files (types, actions, reducer, selectors, thunks), RTK chỉ cần 1 file slice. Pitfall: khi migrate từ Redux thuần sang RTK, đừng rewrite toàn bộ — RTK tương thích ngược, migrate từng slice một." },
  { id: 607, category: "State Management", subcategory: "RTK", level: "intermediate", q: "createSlice trong RTK hoạt động như thế nào?", a: "`createSlice` là API quan trọng nhất của RTK, nhận object gồm `name` (prefix cho action types), `initialState`, và `reducers` (object chứa các reducer functions). Nó tự động tạo action creators và action types — ví dụ: reducer `increment` trong slice tên 'counter' tạo ra action type `counter/increment` và action creator `counterSlice.actions.increment()`. Bên trong dùng Immer nên viết `state.value += 1` thay vì `return { ...state, value: state.value + 1 }` — code ngắn hơn 3-4 lần với nested state. Export 2 thứ: `counterSlice.actions` (dùng trong component dispatch) và `counterSlice.reducer` (dùng trong configureStore). Pitfall thường gặp: trong reducers của createSlice, hoặc mutate state HOẶC return state mới, KHÔNG làm cả hai — Immer sẽ throw error. Ví dụ sai: `state.items.push(item); return state;`." },
  { id: 608, category: "State Management", subcategory: "RTK", level: "intermediate", q: "createAsyncThunk được dùng để làm gì? Các trạng thái lifecycle của nó là gì?", a: "`createAsyncThunk` tạo thunk action creator xử lý async logic (API calls), tự động dispatch 3 lifecycle actions: `pending` (request bắt đầu → show loading), `fulfilled` (thành công → update data), `rejected` (thất bại → show error). Ví dụ: `createAsyncThunk('users/fetch', async (userId, { rejectWithValue }) => { try { return await api.getUser(userId) } catch (err) { return rejectWithValue(err.response.data) } })`. Xử lý trong slice dùng `extraReducers` với builder pattern: `builder.addCase(fetchUser.pending, (state) => { state.loading = true })`. Pitfall: luôn dùng `rejectWithValue` thay vì throw error trực tiếp — nếu không, error object không serializable và DevTools hiển thị sai. Cũng nên dùng `condition` option để cancel thunk nếu data đã có trong cache, tránh duplicate API calls. Với RTK Query, nhiều use case của createAsyncThunk có thể thay thế hoàn toàn mà không cần viết reducer." },
  { id: 609, category: "State Management", subcategory: "RTK", level: "intermediate", q: "Selector trong Redux là gì? Tại sao nên dùng createSelector?", a: "Selector là function nhận toàn bộ Redux state và trích xuất/tính toán phần data cần thiết, ví dụ: `const selectActiveTodos = state => state.todos.filter(t => !t.completed)`. Vấn đề: `filter()` tạo array mới mỗi lần gọi → `useSelector` thấy reference khác → component re-render dù data không đổi. `createSelector` từ Reselect giải quyết bằng memoization: chỉ tính toán lại khi input selectors trả về giá trị khác. Ví dụ: `createSelector([selectTodos, selectFilter], (todos, filter) => todos.filter(t => t.status === filter))` — nếu todos và filter không đổi, trả về kết quả cached. Pitfall phổ biến: tạo selector bên trong component khiến memoization không hoạt động vì selector mới được tạo mỗi render — luôn định nghĩa selector bên ngoài component hoặc dùng `useMemo`. Trong app lớn, selector composition (selector dùng selector khác) giúp tái sử dụng logic tính toán." },
  { id: 610, category: "State Management", subcategory: "RTK", level: "advanced", q: "RTK Query là gì? Lợi ích so với cách fetch data thủ công?", a: "RTK Query là data fetching và caching layer tích hợp sẵn trong Redux Toolkit, cạnh tranh trực tiếp với React Query/SWR. Ưu điểm so với fetch thủ công: tự động quản lý loading/error/success states (không cần viết 3 cases trong reducer), cache data theo endpoint + params, tự động refetch khi args thay đổi, deduplication (10 components cùng gọi `useGetUserQuery(1)` chỉ 1 request). Cache invalidation qua tag system: `providesTags: ['Post']` ở query và `invalidatesTags: ['Post']` ở mutation — khi mutation xong, tất cả queries với tag 'Post' tự động refetch. So với React Query: RTK Query tích hợp sẵn Redux store (không cần thêm thư viện), nhưng React Query có API linh hoạt hơn và không bắt buộc dùng Redux. Pitfall: nếu project đã dùng React Query, thêm RTK Query tạo 2 cache layers trùng lặp — chọn một." },
  { id: 611, category: "State Management", subcategory: "RTK", level: "advanced", q: "Cách định nghĩa API với createApi trong RTK Query như thế nào?", a: "`createApi` là core API của RTK Query, định nghĩa toàn bộ endpoints cho một base URL. Cấu hình `baseQuery` (thường `fetchBaseQuery({ baseUrl: '/api' })`) xác định cách gọi API, có thể custom để thêm auth headers hay handle token refresh. Mỗi endpoint là query (GET) hoặc mutation (POST/PUT/DELETE), tự động tạo hooks: `getUsers` → `useGetUsersQuery()`, `addUser` → `useAddUserMutation()`. Cache invalidation dùng tag system: `tagTypes: ['User']`, query `providesTags: ['User']`, mutation `invalidatesTags: ['User']` — khi add user xong, danh sách users tự refetch. Ví dụ: `endpoints: (builder) => ({ getUsers: builder.query({ query: () => '/users', providesTags: ['User'] }), addUser: builder.mutation({ query: (body) => ({ url: '/users', method: 'POST', body }), invalidatesTags: ['User'] }) })`. Pitfall: chỉ nên có MỘT `createApi` per base URL, dùng `injectEndpoints` để code-split endpoints ra nhiều files." },
  { id: 612, category: "State Management", subcategory: "Redux", level: "intermediate", q: "Redux middleware là gì? Cho ví dụ về middleware phổ biến?", a: "Middleware là function nằm giữa `dispatch(action)` và reducer, có thể inspect, modify, delay, hoặc cancel action trước khi đến reducer. Flow: `dispatch → middleware1 → middleware2 → reducer`. Middleware phổ biến: `redux-thunk` (cho phép dispatch function thay vì object, xử lý async — RTK include mặc định), `redux-saga` (dùng generator functions cho complex async flows như race conditions, cancellation, debounce), `redux-logger` (log action type, prev state, next state — hữu ích cho debug). Ví dụ custom middleware: `const logger = store => next => action => { console.log(action.type); return next(action) }`. Pitfall: thứ tự middleware quan trọng — thunk phải ở đầu để dispatch(function) được xử lý trước khi đến middleware khác. Với RTK, `configureStore` tự setup thunk + serialization check + immutability check, chỉ cần thêm custom middleware qua `middleware` option nếu cần." },
  { id: 613, category: "State Management", subcategory: "Redux", level: "advanced", q: "Redux DevTools hoạt động như thế nào? Tính năng time-travel debugging là gì?", a: "Redux DevTools là browser extension record toàn bộ action history theo timeline — mỗi action được log kèm payload, prev state và next state diff. Time-travel mechanism: DevTools lưu snapshot state sau mỗi action; bạn có thể 'jump' đến bất kỳ snapshot bằng click vào action trong history list, app render lại đúng state tại thời điểm đó mà không cần reload hay reproduce thủ công. Tính năng chính: (1) Action log với filter theo type, (2) State diff highlighting thay đổi màu xanh/đỏ, (3) Replay — chạy lại từng action từ đầu, (4) Skip action — loại bỏ action cụ thể để test what-if, (5) Import/export state JSON để share bug reproduction, (6) Dispatcher panel để dispatch action thủ công. Workflow thực tế: user báo bug ở màn hình checkout → export state JSON từ session của họ → import vào DevTools của developer → jump từng action để tìm chính xác điểm gây ra bug. Yêu cầu quan trọng: state và action payload PHẢI serializable — không được là Date, Function, Promise hay class instance — vi phạm khiến DevTools crash. RTK tích hợp sẵn serializability check ở development mode để cảnh báo ngay khi có non-serializable data." },
  { id: 614, category: "State Management", subcategory: "Redux", level: "intermediate", q: "useSelector và useDispatch hook trong React-Redux hoạt động như thế nào?", a: "useSelector nhận selector function, subscribe vào Redux store, và dùng strict === comparison (reference equality) để quyết định có re-render không. Pitfall quan trọng: nếu selector trả về object/array mới mỗi lần gọi — ví dụ `useSelector(s => s.items.filter(...))` — reference luôn khác nên component re-render liên tục dù data không đổi. Fix: dùng `shallowEqual` từ react-redux làm argument thứ hai (`useSelector(selector, shallowEqual)`) để so sánh từng property, hoặc dùng `createSelector` (Reselect) để memoize. useDispatch trả về stable dispatch reference — không bao giờ thay đổi giữa các render, an toàn khi đặt vào dependency array. So sánh với connect() HOC cũ: connect() dùng shallowEqual mặc định nên ít gặp re-render issue hơn, nhưng code verbose (mapStateToProps, mapDispatchToProps) và wrap component trong HOC gây khó debug. useSelector/useDispatch code gọn hơn 50% nhưng developer phải tự xử lý equality. Ví dụ pitfall thực tế: `useSelector(s => ({ a: s.a, b: s.b }))` tạo object mới mỗi render → infinite re-render loop khi có dispatch trong useEffect — fix bằng 2 useSelector riêng biệt hoặc shallowEqual." },
  { id: 615, category: "State Management", subcategory: "Redux", level: "advanced", q: "Khi nào nên dùng Redux và khi nào không cần?", a: "Framework decision: DÙNG Redux khi (1) shared state cần ở nhiều component cách xa nhau — ví dụ user auth info cần ở Header, Sidebar, Feed và Modal đồng thời; (2) state logic phức tạp với nhiều actions tương tác — shopping cart có coupon, discount, tax, shipping tính toán lẫn nhau; (3) cần action history/audit trail — ứng dụng financial, collaborative editing cần biết ai làm gì lúc nào; (4) team đã quen Redux với codebase lớn — migration cost cao hơn benefit. KHÔNG dùng Redux khi: (1) chủ yếu là server state — dùng React Query thay, Redux cho server data là over-engineering; (2) state chỉ local trong 1-2 component — useState là đủ; (3) app nhỏ hoặc team mới — learning curve Redux + RTK không cần thiết. Alternatives landscape: Zustand cho global client state đơn giản (~8KB, zero boilerplate), Jotai cho atomic fine-grained state, React Query cho server state (thay thế 80% Redux use cases), Context API cho low-frequency updates như theme/locale. Rule of thumb: nếu đang viết Redux chủ yếu để cache API data, hãy dùng React Query — Redux nên chỉ còn cho UI state thật sự global như auth, cart, notification preferences." },

  // === STATE MANAGEMENT: Zustand (616-625) ===
  { id: 616, category: "State Management", subcategory: "Zustand", level: "beginner", q: "Zustand là gì? So sánh với Redux về độ phức tạp?", a: "Zustand là thư viện quản lý state nhỏ gọn cho React, không yêu cầu boilerplate như Redux — không cần actions, reducers, dispatch, hay Provider wrapper. API chỉ gồm hàm `create` trả về một hook, state và actions định nghĩa cùng chỗ. Bundle size ~1KB so với Redux Toolkit ~40KB khi đầy đủ. Ví dụ tạo store đơn giản: `const useStore = create(set => ({ count: 0, inc: () => set(s => ({ count: s.count + 1 })) }))`, dùng trong component: `const count = useStore(s => s.count)`. Pitfall quan trọng: luôn dùng selector khi lấy state (`useStore(s => s.count)` thay vì `useStore()`) để tránh re-render không cần thiết khi phần state khác thay đổi." },
  { id: 617, category: "State Management", subcategory: "Zustand", level: "beginner", q: "Cách tạo một store với Zustand như thế nào?", a: "Dùng `create` từ 'zustand', truyền vào initializer function nhận `(set, get)` và trả về object chứa cả state lẫn actions trong cùng một chỗ. `set()` merge partial state (không cần spread toàn bộ như Redux). `get()` đọc state hiện tại từ bên trong action. Ví dụ đầy đủ: `const useCartStore = create((set, get) => ({ items: [], total: 0, addItem: (item) => set((s) => ({ items: [...s.items, item], total: s.total + item.price })), clearCart: () => set({ items: [], total: 0 }), getItemCount: () => get().items.length }))`. Store trả về là một React hook, dùng trực tiếp: `const items = useCartStore(s => s.items)` hoặc `const addItem = useCartStore(s => s.addItem)`. Không cần Provider, không cần dispatch — gọi action như gọi function bình thường: `addItem(product)`. So sánh với Redux: 1 file slice Zustand thay thế được actions + actionTypes + reducer + selectors + thunk." },
  { id: 618, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "Cách định nghĩa actions trong Zustand store?", a: "Actions trong Zustand là plain functions sống cùng state trong store object — không có action types, không dispatch, không reducers. Có 3 pattern chính: (1) Partial update với set: `increment: () => set(s => ({ count: s.count + 1 }))`. (2) Computed values dùng get() để đọc state hiện tại bên trong action: `addItem: (item) => { const existing = get().items.find(i => i.id === item.id); set(s => ({ items: existing ? s.items.map(i => i.id === item.id ? {...i, qty: i.qty+1} : i) : [...s.items, item] })) }`. (3) Async actions — không cần thunk middleware, viết async/await trực tiếp: `fetchUser: async (id) => { set({ loading: true }); const user = await api.getUser(id); set({ user, loading: false }) }`. Multiple state updates trong một set call tự động batched. Pitfall: `set` merge shallow — nested object phải tự spread: `set(s => ({ config: { ...s.config, theme: 'dark' } }))`." },
  { id: 619, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "Zustand khác Redux như thế nào về kiến trúc?", a: "Kiến trúc khác nhau căn bản: Redux theo Flux pattern — action object → dispatch → middleware → reducer → new state; Zustand không có khái niệm action types hay reducers — chỉ là functions gọi set(). Redux bắt buộc: Provider wrapper, combineReducers, action creators, selectors riêng biệt, middleware để async. Zustand không cần gì trong số đó. Redux enforces một flow dữ liệu nghiêm ngặt (tốt cho team lớn, audit), Zustand flexible hơn (tốt cho DX và speed). Về middleware: Redux có ecosystem middleware phong phú (thunk, saga, logger, sentry), Zustand có middleware nhẹ hơn (devtools, persist, immer) nhưng đủ dùng cho hầu hết cases. Về DevTools: cả hai đều kết nối được Redux DevTools Extension. Khi Zustand tỏa sáng: prototype nhanh, app vừa, team nhỏ. Khi Redux tỏa sáng: large team cần consistency, cần RTK Query, cần full audit trail, cần time-travel debugging end-to-end." },
  { id: 620, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "Làm thế nào để tránh re-render không cần thiết trong Zustand?", a: "Zustand mặc định dùng strict === equality để so sánh — nếu selector trả về primitive (number, string, boolean) thì không vấn đề gì. Vấn đề xảy ra khi selector trả về object/array mới mỗi lần: `useStore(s => ({ a: s.a, b: s.b }))` tạo object mới mỗi render → component luôn re-render. Giải pháp: (1) Tách thành 2 selectors riêng: `const a = useStore(s => s.a); const b = useStore(s => s.b)`. (2) Dùng `useShallow` hook từ 'zustand/react/shallow' để shallow compare object/array: `const { a, b } = useStore(useShallow(s => ({ a: s.a, b: s.b })))`. (3) Dùng `createSelectors` pattern để auto-generate per-property selectors. Auto-selector pattern: `const createSelectors = (store) => { const s = store; s.use = {}; Object.keys(s.getState()).forEach(k => { s.use[k] = () => s(x => x[k]) }); return s }` → dùng `useStore.use.count()`. Pitfall khác: gọi `useStore()` không truyền selector → subscribe toàn bộ store, re-render khi bất kỳ state nào thay đổi." },
  { id: 621, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "Zustand middleware là gì? Cho ví dụ về devtools middleware?", a: "Zustand middleware dùng pattern higher-order function wrap store creator. Import từ 'zustand/middleware'. Compose nhiều middleware bằng cú pháp lồng nhau: `create(devtools(immer(persist(storeCreator, persistOptions)), devtoolsOptions))` — thứ tự quan trọng: devtools nên ở ngoài cùng để capture đúng actions. Middleware phổ biến: (1) `devtools` — kết nối Redux DevTools Extension, đặt tên action cho mỗi set call: `set(updater, false, 'addItem')` để log đẹp trong DevTools; (2) `immer` — cho phép mutate state trực tiếp trong set: `set(s => { s.items.push(item) })` thay vì phải spread; (3) `persist` — lưu/khôi phục state vào storage; (4) `subscribeWithSelector` — cho phép subscribe vào một phần state với selector và equality function, hữu ích cho side effects. Custom middleware: function nhận `(config) => (set, get, api) => config(set, get, api)` với logic thêm vào trước/sau set." },
  { id: 622, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "persist middleware trong Zustand hoạt động như thế nào?", a: "Middleware `persist` từ 'zustand/middleware' serialize state thành JSON rồi lưu vào storage, rehydrate khi app khởi động. Config quan trọng: `name` (storage key, bắt buộc), `partialize` để chọn phần state cần persist — tránh lưu thừa: `partialize: (s) => ({ user: s.user, theme: s.theme })` (không lưu loading/error states), `storage` để override engine: `createJSONStorage(() => sessionStorage)` hoặc custom AsyncStorage cho React Native. `onRehydrateStorage` là lifecycle hook chạy khi rehydrate: `onRehydrateStorage: () => (state, error) => { if (error) console.error('hydration failed', error) }`. `version` + `migrate` để handle schema changes giữa các app versions: `version: 2, migrate: (persistedState, version) => { if (version === 1) return { ...persistedState, newField: 'default' } }`. Pitfall: persist không merge deep — nếu cấu trúc state thay đổi giữa releases mà không có migrate, rehydrate sẽ cho state không hợp lệ." },
  { id: 623, category: "State Management", subcategory: "Zustand", level: "advanced", q: "Cách chia nhỏ Zustand store thành nhiều slices?", a: "Slice pattern giúp tổ chức store lớn thành các modules độc lập. Mỗi slice là một `StateCreator` function: `const createCartSlice = (set, get) => ({ items: [], addItem: (item) => set(s => ({ items: [...s.items, item] })), clearCart: () => set({ items: [] }) })`. Tương tự: `const createUserSlice = (set) => ({ user: null, setUser: (u) => set({ user: u }), logout: () => set({ user: null }) })`. Combine trong create: `const useBoundStore = create((...a) => ({ ...createCartSlice(...a), ...createUserSlice(...a) }))`. Với TypeScript: dùng `StateCreator<BoundStore, [], [], CartSlice>` để type đúng — BoundStore là type của toàn bộ combined store, CartSlice là type của slice này. Slice có thể cross-reference nhau qua `get()`: `const createOrderSlice = (set, get) => ({ checkout: () => { const { items } = get(); const { user } = get(); return api.order(user.id, items) } })`. Pitfall: tên state/action không được trùng giữa các slices — spread object sẽ overwrite." },
  { id: 624, category: "State Management", subcategory: "Zustand", level: "advanced", q: "Cách sử dụng Zustand với TypeScript để có type safety?", a: "Pattern chuẩn với TypeScript: định nghĩa type cho toàn bộ store trước, rồi pass vào generic. Zustand v4+ dùng curried create: `create<StoreType>()((set, get) => ({...}))` — dấu `()` thứ hai bắt buộc để TypeScript infer đúng. Ví dụ: `interface CartStore { items: CartItem[]; total: number; addItem: (item: CartItem) => void; clearCart: () => void }` → `const useCartStore = create<CartStore>()((set, get) => ({ items: [], total: 0, addItem: (item) => set(s => ({ items: [...s.items, item], total: s.total + item.price })), clearCart: () => set({ items: [], total: 0 }) }))`. Với slices dùng `StateCreator` type: `type CartSlice = { items: CartItem[]; addItem: (item: CartItem) => void }; const createCartSlice: StateCreator<BoundStore, [], [], CartSlice> = (set) => ({...})`. Infer store type từ store: `type StoreState = ReturnType<typeof useStore.getState>`. Pitfall: không nên dùng `create` mà không có generic — mất type safety và set nhận `any`." },
  { id: 625, category: "State Management", subcategory: "Zustand", level: "advanced", q: "Khi nào nên chọn Zustand thay vì Redux Toolkit?", a: "Nuanced comparison: Developer Experience — Zustand thắng rõ rệt: zero config, zero boilerplate, học trong 30 phút. RTK phức tạp hơn nhưng có structure rõ ràng hơn. Ecosystem: RTK thắng — có RTK Query (data fetching + caching tích hợp), middleware ecosystem phong phú, tài liệu extensive. DevTools: cả hai đều kết nối Redux DevTools Extension, nhưng RTK log actions chi tiết hơn (mỗi action có type rõ ràng), Zustand cần đặt tên manual trong devtools middleware. Team size: Zustand tốt cho team nhỏ (flexibility, speed), RTK tốt hơn cho team lớn (enforced patterns, code reviews dễ hơn khi có conventions). Learning curve: Zustand ~2h, RTK ~2 ngày (createSlice, createAsyncThunk, RTK Query, tags system). Middleware: RTK có thunk/saga/logger ecosystem rộng hơn, Zustand middleware nhẹ nhàng hơn. Kết luận thực tế: nếu không cần RTK Query và team < 5 người → Zustand. Nếu cần data fetching layer tích hợp Redux hoặc team lớn cần consistency → RTK." },

  // === STATE MANAGEMENT: React Query (626-640) ===
  { id: 626, category: "State Management", subcategory: "React Query", level: "beginner", q: "React Query (TanStack Query) là gì? Mục đích chính của nó là gì?", a: "React Query (nay là TanStack Query v5) là thư viện quản lý server state cho React, giải quyết bài toán mà useState + useEffect không làm tốt: fetching, caching, synchronizing và updating data từ API. Ví dụ thực tế: không cần React Query, bạn phải tự viết loading state, error handling, cache, deduplication, refetch khi focus window, retry khi fail — React Query làm tất cả tự động. Khác biệt cốt lõi với Redux: Redux quản lý client state (UI state, form state), React Query quản lý server state (data từ API có thể thay đổi bởi người khác bất kỳ lúc nào). Trong thực tế, 80% Redux code trong các dự án là để fetch và cache API data — React Query thay thế hoàn toàn phần đó." },
  { id: 627, category: "State Management", subcategory: "React Query", level: "beginner", q: "useQuery hook hoạt động như thế nào? Các tham số cơ bản là gì?", a: "useQuery là hook chính để đọc data, nhận 2 tham số bắt buộc: `queryKey` (mảng định danh duy nhất, ví dụ `['todos', { status: 'active' }]`) và `queryFn` (async function trả về data, ví dụ `() => fetch('/api/todos').then(r => r.json())`). Trả về object gồm: `data` (kết quả), `isLoading` (true lần fetch đầu), `isFetching` (true khi đang fetch kể cả background), `isError`/`error` (lỗi), `isSuccess`, `status`. Cơ chế: component mount → check cache theo queryKey → nếu có data fresh thì dùng luôn, nếu stale thì vừa show cached data vừa refetch background. Đây là pattern stale-while-revalidate." },
  { id: 628, category: "State Management", subcategory: "React Query", level: "intermediate", q: "useMutation hook dùng để làm gì? Cách xử lý optimistic updates?", a: "useMutation xử lý write operations (POST/PUT/DELETE) — khác useQuery chỉ đọc. Cung cấp `mutate()` (fire-and-forget) hoặc `mutateAsync()` (trả về Promise). States: `isPending`, `isError`, `isSuccess`, `data`, `error`. Optimistic update flow: (1) `onMutate`: cancel ongoing queries, snapshot data cũ, set cache mới ngay → UI cập nhật tức thì. (2) `onError`: nhận snapshot từ onMutate context, rollback cache. (3) `onSettled`: invalidate queries để sync với server. Ví dụ thực tế: user like bài viết → heart đỏ ngay lập tức (optimistic), nếu API fail → rollback heart về trắng." },
  { id: 629, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Cache invalidation trong React Query hoạt động như thế nào?", a: "Cache invalidation là cơ chế đánh dấu data đã cũ (stale) để trigger refetch. Cách dùng: `queryClient.invalidateQueries({ queryKey: ['todos'] })` — tất cả queries có key bắt đầu bằng 'todos' bị đánh dấu stale. Nếu component đang mount thì refetch ngay, nếu không thì refetch khi component mount lại. Thường gọi sau mutation thành công: thêm todo mới → invalidate todo list → list tự động refetch. Ngoài ra có `queryClient.setQueryData()` để update cache trực tiếp mà không cần refetch — hữu ích khi mutation trả về data mới." },
  { id: 630, category: "State Management", subcategory: "React Query", level: "intermediate", q: "staleTime và gcTime (cacheTime) trong React Query là gì? Sự khác biệt?", a: "Hai config quan trọng nhất quyết định caching behavior. **staleTime** (mặc định 0): thời gian data được coi là 'fresh' — trong khoảng này component mount mới sẽ dùng cached data mà KHÔNG refetch. Ví dụ: `staleTime: 5 * 60 * 1000` (5 phút) → trong 5 phút, navigate qua lại giữa các page sẽ show cached data ngay, không loading. **gcTime** (mặc định 5 phút): thời gian data ở lại trong cache SAU KHI không còn component nào subscribe. Khi hết gcTime, data bị xóa khỏi memory. Quan hệ: staleTime quyết định 'khi nào refetch', gcTime quyết định 'khi nào xóa cache'. staleTime nên ≤ gcTime." },
  { id: 631, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Tại sao React Query được coi là giải pháp 'server state' không phải 'global state'?", a: "Có 2 loại state khác biệt bản chất: **Client state** (theme, sidebar open, form input) — thuộc sở hữu hoàn toàn của client, đồng bộ ngay lập tức, không bao giờ 'stale'. **Server state** (user profile, todo list, product catalog) — thuộc sở hữu của server, có thể bị thay đổi bởi người khác, cần đồng bộ liên tục, luôn có khả năng 'stale'. Redux trộn lẫn 2 loại này vào 1 store, dẫn đến phức tạp không cần thiết (loading states, error states, normalization). React Query tách biệt: nó CHỈ quản lý server state với caching, background refetch, retry, deduplication. Client state dùng useState/useReducer/Zustand. Kết quả: giảm 50-80% Redux code trong hầu hết projects." },
  { id: 632, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Cách cấu hình React Query với QueryClient và QueryClientProvider?", a: "QueryClient là singleton quản lý toàn bộ cache và config. Tạo BÊN NGOÀI component để tránh re-create mỗi render. defaultOptions áp dụng cho tất cả queries/mutations trừ khi override per-query: `new QueryClient({ defaultOptions: { queries: { staleTime: 60_000, gcTime: 5 * 60_000, retry: 2, retryDelay: (attempt) => Math.min(1000 * 2 ** attempt, 30_000), refetchOnWindowFocus: false } } })`. Retry strategy: mặc định retry 3 lần với exponential backoff, có thể set `retry: (count, error) => error.status !== 404 && count < 3` để không retry 404. Error handling defaults: từ v5 không còn `onError` global — dùng `QueryCache` listener: `new QueryClient({ queryCache: new QueryCache({ onError: (error) => toast.error(error.message) }) })`. staleTime strategy theo loại data: static data (currencies, countries) → `Infinity`, user data → 5 phút, real-time data → 0. Trong Next.js App Router, tạo QueryClient trong server component và dùng `makeQueryClient()` factory pattern để mỗi request có instance riêng tránh data leaking giữa users." },
  { id: 633, category: "State Management", subcategory: "React Query", level: "intermediate", q: "refetchOnWindowFocus trong React Query là gì? Khi nào nên tắt nó?", a: "refetchOnWindowFocus là behavior mặc định: khi user chuyển tab rồi quay lại, React Query tự động refetch tất cả stale queries. Mục đích: đảm bảo data luôn fresh — ví dụ user đang xem dashboard, chuyển qua Slack 5 phút, quay lại thì data cập nhật mới nhất. Nên tắt (`refetchOnWindowFocus: false`) khi: (1) data ít thay đổi (config, static content), (2) refetch gây UX tệ (reset scroll, flash loading), (3) API có rate limit. Có thể set global qua `defaultOptions` hoặc per-query. Tương tự có `refetchOnReconnect` (khi mạng khôi phục) và `refetchInterval` (polling định kỳ)." },
  { id: 634, category: "State Management", subcategory: "React Query", level: "advanced", q: "Prefetching trong React Query hoạt động như thế nào?", a: "Prefetching là kỹ thuật fetch data trước khi user cần, giúp loại bỏ loading state. Client-side pattern: prefetch on hover để khi user click vào link thì data đã sẵn sàng — `const handleMouseEnter = () => queryClient.prefetchQuery({ queryKey: ['post', id], queryFn: () => fetchPost(id), staleTime: 30_000 })`. Server-side với Next.js App Router: `const queryClient = new QueryClient(); await queryClient.prefetchQuery({ queryKey: ['posts'], queryFn: fetchPosts }); const dehydratedState = dehydrate(queryClient); return <HydrationBoundary state={dehydratedState}><PostList /></HydrationBoundary>` — client nhận data đã fetch sẵn, không có loading flash. `prefetchInfiniteQuery` cho infinite scroll pages: pre-load trang đầu tiên trên server, user thấy content ngay. Prefetch trong route handler (Next.js): đặt prefetch logic trong layout.tsx để data sẵn sàng trước khi page.tsx render. Pitfall: prefetchQuery không throw error (khác fetchQuery), query silently fails — luôn check error state ở component level." },
  { id: 635, category: "State Management", subcategory: "React Query", level: "advanced", q: "Infinite queries trong React Query là gì? Dùng cho pagination như thế nào?", a: "`useInfiniteQuery` là hook chuyên biệt cho infinite scroll và load-more pagination — thay vì fetch 1 page, nó quản lý nhiều pages trong 1 query. Cấu hình: `queryFn` nhận `pageParam` (cursor hoặc page number), `getNextPageParam` trả về param cho page tiếp theo (return undefined khi hết data). Kết quả: `data.pages` là mảng chứa data từng page, `data.pageParams` lưu params đã dùng. Gọi `fetchNextPage()` khi user scroll tới cuối (dùng IntersectionObserver). Ví dụ: social feed, product listing, chat history. Có thêm `fetchPreviousPage()` cho bi-directional infinite scroll." },
  { id: 636, category: "State Management", subcategory: "React Query", level: "advanced", q: "Dependent queries trong React Query là gì?", a: "Dependent query (hay serial query) là query mà việc thực thi phụ thuộc vào kết quả của query khác. Dùng `enabled` option để kiểm soát: ví dụ fetch user trước, rồi mới fetch posts của user đó — `useQuery({ queryKey: ['posts', userId], queryFn: () => fetchPosts(userId), enabled: !!userId })`. Khi userId chưa có (query user chưa xong), enabled = false nên posts query không chạy. Khi userId có giá trị, enabled = true → tự động fetch. React Query handle loading states đúng cho cả chain: component thấy isLoading = true cho tới khi query cuối cùng hoàn thành. Tránh lạm dụng dependent queries vì tạo waterfall — nếu queries độc lập, chạy parallel tốt hơn." },
  { id: 637, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Cách xử lý error trong React Query?", a: "React Query v5 thay đổi error handling so với v4: `onError` callback bị deprecated, thay bằng `throwOnError` hoặc `meta`. Retry strategies: mặc định retry 3 lần, exponential backoff — override: `retry: (failureCount, error) => error.status !== 401 && failureCount < 3` để không retry auth errors. Global error handling với QueryCache observer: `new QueryClient({ queryCache: new QueryCache({ onError: (error, query) => { if (query.meta?.showErrorToast) toast.error(error.message) } }) })` — per-query opt-in: `useQuery({ ..., meta: { showErrorToast: true } })`. Error Boundary integration: `throwOnError: true` khiến query throw error lên Error Boundary thay vì return `isError`. Hoặc dùng `useSuspenseQuery` — tự động throw lên Error Boundary. `error.message` vs `error.response.data`: với fetch API, HTTP errors không tự throw — phải check `if (!res.ok) throw new Error(res.statusText)` trong queryFn. Pitfall v5: `onError` ở useMutation vẫn hoạt động nhưng global `onError` trong defaultOptions đã bị xóa." },
  { id: 638, category: "State Management", subcategory: "React Query", level: "intermediate", q: "QueryKey trong React Query nên được thiết kế như thế nào?", a: "QueryKey design là nền tảng của cache architecture. Rules: (1) Include ALL dependencies — bất cứ biến nào dùng trong queryFn phải có trong key: `['todos', userId, { status, page, sort }]`. (2) Dùng array, không dùng string thuần — array cho phép fuzzy matching khi invalidate. (3) Hierarchy từ general đến specific: `['todos']` → `['todos', todoId]` → `['todos', todoId, 'comments']`. Factory pattern (best practice): `const todoKeys = { all: ['todos'] as const, lists: () => [...todoKeys.all, 'list'] as const, list: (filters) => [...todoKeys.lists(), filters] as const, detail: (id) => [...todoKeys.all, 'detail', id] as const }` — dùng: `useQuery({ queryKey: todoKeys.detail(id) })`, invalidate: `queryClient.invalidateQueries({ queryKey: todoKeys.lists() })`. Fuzzy matching rules: `invalidateQueries({ queryKey: ['todos'] })` invalidates tất cả keys bắt đầu bằng 'todos' — cả `['todos', 1]` lẫn `['todos', { status: 'active' }]`. Serialization: React Query serialize key thành stable string cho cache lookup — objects được serialized theo key order." },
  { id: 639, category: "State Management", subcategory: "React Query", level: "advanced", q: "Optimistic updates trong React Query thực hiện như thế nào?", a: "Optimistic update flow đầy đủ: khi user thực hiện action, update UI ngay lập tức trước khi API confirm, rollback nếu API fail. Implementation: `onMutate: async (newTodo) => { await queryClient.cancelQueries({ queryKey: ['todos'] }); const snapshot = queryClient.getQueryData(['todos']); queryClient.setQueryData(['todos'], (old) => [...old, { ...newTodo, id: 'temp-' + Date.now() }]); return { snapshot } }`. `onError: (err, newTodo, context) => { queryClient.setQueryData(['todos'], context.snapshot) }`. `onSettled: () => { queryClient.invalidateQueries({ queryKey: ['todos'] }) }`. Quan trọng: `cancelQueries` trước khi optimistic update — tránh race condition khi background refetch overwrite optimistic state. Context pattern: onMutate return value trở thành `context` trong onError/onSettled. Khi nào dùng optimistic vs simple invalidation: optimistic cho actions user expect instant feedback (like, follow, toggle), simple invalidation cho actions phức tạp hơn (payment, create order) vì rollback UX tệ hơn là loading nhỏ. Pitfall: optimistic ID ('temp-123') cần được replace bằng real ID sau khi server confirm — onSettled invalidate để refetch với real data." },
  { id: 640, category: "State Management", subcategory: "React Query", level: "advanced", q: "Cách kết hợp React Query với Next.js Server Components?", a: "Next.js App Router pattern với React Query: Server Components fetch data và dehydrate cache, Client Components nhận hydrated cache — không có loading flash. Pattern đầy đủ: (1) Tạo `getQueryClient()` factory với `cache()` từ React để mỗi request server có QueryClient riêng (tránh data leak giữa users). (2) Server Component: `const queryClient = getQueryClient(); await queryClient.prefetchQuery({ queryKey: ['posts'], queryFn: fetchPosts }); return <HydrationBoundary state={dehydrate(queryClient)}><PostList /></HydrationBoundary>`. (3) Client Component dùng `useQuery` bình thường — nhận data từ hydrated cache ngay, không request thêm nếu data còn fresh. Streaming hydration: có thể dùng với Suspense để stream từng phần page. RSC considerations: không thể dùng React Query hooks trong RSC (chỉ là async functions) — hooks chỉ trong Client Components. Nên prefetch ở server những gì quan trọng cho initial render, lazy load phần ít quan trọng hơn ở client. Pitfall: nếu không dùng `cache()` cho QueryClient factory, server-side QueryClient sẽ được share giữa requests → data leaking." },

  // === STATE MANAGEMENT: React Query Nâng Cao (1056-1070) ===
  { id: 1056, category: "State Management", subcategory: "React Query", level: "beginner", q: "QueryClientProvider là gì? Tại sao cần wrap app bằng nó?", a: "QueryClientProvider là React Context Provider cung cấp QueryClient instance cho toàn bộ component tree. QueryClient là 'bộ não' quản lý cache, chứa tất cả cached data, query states, và config. Mọi `useQuery`/`useMutation` bên trong đều cần access QueryClient. Setup: tạo `const queryClient = new QueryClient()` BÊN NGOÀI component (tránh re-create mỗi render), wrap app bằng `<QueryClientProvider client={queryClient}>`. Có thể cấu hình defaultOptions cho tất cả queries: `new QueryClient({ defaultOptions: { queries: { staleTime: 60_000, retry: 2 } } })`. Trong Next.js App Router, đặt ở root layout nhưng cần 'use client' wrapper." },
  { id: 1057, category: "State Management", subcategory: "React Query", level: "beginner", q: "Sự khác biệt giữa isLoading và isFetching trong useQuery?", a: "Đây là câu phỏng vấn rất phổ biến. **isLoading** (hay `status === 'pending'`): true CHỈ khi fetch lần đầu VÀ chưa có cached data — dùng để show loading skeleton/spinner toàn trang. **isFetching**: true MỌI KHI đang fetch, kể cả background refetch khi đã có cached data — dùng để show subtle indicator (spinning icon nhỏ, progress bar mờ). Ví dụ thực tế: user vào trang Products lần đầu → isLoading=true, show skeleton. User navigate đi rồi quay lại → có cached data nên isLoading=false (show data cũ ngay), nhưng isFetching=true (đang refetch background). Thêm `isRefetching` = isFetching && !isLoading (đang refetch có data cũ)." },
  { id: 1058, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Placeholder data và initial data trong React Query khác gì nhau?", a: "Hai option này phục vụ mục đích khác nhau. `placeholderData`: data tạm thời để fill UI trong khi fetch, KHÔNG được lưu vào cache, không có timestamp, `isPlaceholderData: true` để component biết đang hiển thị placeholder. Dùng khi: muốn show skeleton data có structure (ví dụ array 5 empty items), hoặc `placeholderData: (prev) => prev` để giữ data page trước khi chuyển page (keepPreviousData pattern). `initialData`: được treat như real cached data — có `dataUpdatedAt`, ảnh hưởng staleTime (nếu initialData đủ fresh thì không refetch ngay). Dùng khi: data đã có từ nguồn khác (ví dụ đã fetch list, giờ dùng item từ list làm initialData cho detail query: `initialData: () => queryClient.getQueryData(['todos'])?.find(t => t.id === id)`, `initialDataUpdatedAt: () => queryClient.getQueryDataState(['todos'])?.dataUpdatedAt`). Pitfall: dùng sai `initialData` với hardcoded value sẽ ngăn query refetch vì React Query nghĩ data còn fresh — luôn kết hợp với `initialDataUpdatedAt: 0` nếu muốn force refetch." },
  { id: 1059, category: "State Management", subcategory: "React Query", level: "intermediate", q: "select option trong useQuery dùng để làm gì?", a: "`select` là transform function chạy sau khi queryFn trả về data, trước khi component nhận — không ảnh hưởng gì đến cache (cache vẫn lưu raw data). Re-render optimization: React Query memoize select result — component chỉ re-render khi `select(data)` trả về giá trị khác (dùng structural equality). Ví dụ: nhiều components dùng cùng query `['todos']` nhưng mỗi component có `select` khác nhau — `select: d => d.filter(t => !t.done)` (incomplete) và `select: d => d.filter(t => t.done)` (complete) — component nào chỉ re-render khi phần data của nó thay đổi. Patterns thực tế: (1) Pick fields: `select: d => ({ name: d.name, avatar: d.avatar })` giảm re-render khi các field khác thay đổi. (2) Sort/filter: `select: d => [...d].sort((a,b) => b.date - a.date)`. (3) Normalize: `select: d => Object.fromEntries(d.map(i => [i.id, i]))`. Pitfall: nếu `select` là inline arrow function, memoization không hoạt động vì function reference thay đổi mỗi render — stabilize bằng useCallback hoặc định nghĩa outside component." },
  { id: 1060, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Parallel queries và useQueries trong React Query là gì?", a: "Parallel queries là kỹ thuật fetch nhiều API endpoints cùng lúc thay vì tuần tự (waterfall). Cách 1: gọi nhiều `useQuery` hooks trong cùng component — React Query tự động chạy chúng parallel. Cách 2: `useQueries` hook nhận mảng query configs, hữu ích khi số lượng queries dynamic (ví dụ fetch details cho danh sách product IDs). Kết quả trả về mảng objects, mỗi object giống useQuery result. Ví dụ: dashboard cần user info + notifications + stats → 3 useQuery hooks chạy song song, tổng thời gian = query chậm nhất (thay vì cộng dồn). Lưu ý: React Suspense mode sẽ waterfall nếu mỗi query ở component khác nhau — dùng `useSuspenseQueries` để parallel trong Suspense." },
  { id: 1061, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Cách cancel queries trong React Query khi component unmount?", a: "React Query cung cấp `signal` (AbortSignal) qua queryFn context — pass signal vào fetch để enable cancellation: `queryFn: ({ signal }) => fetch(\`/api/users/${id}\`, { signal })`. Khi component unmount hoặc queryKey thay đổi, React Query tự động abort signal → browser hủy pending request. Với axios: `queryFn: ({ signal }) => axios.get(\`/api/users/${id}\`, { signal })` — axios v0.22+ support AbortSignal trực tiếp. Custom fetch wrapper: `async function fetchWithCancel(url, { signal }) { const res = await fetch(url, { signal }); if (!res.ok) throw new Error(res.statusText); return res.json() }`. Cancellation xảy ra khi: (1) component unmount trước khi fetch xong (user navigate đi), (2) queryKey thay đổi nhanh (search input) — request cũ bị cancel khi key mới, (3) `queryClient.cancelQueries()` được gọi manual (thường trong optimistic update onMutate). Pitfall: nếu queryFn không dùng signal, query vẫn complete dù component unmount — data được cache nhưng component đã gone, React Query tự discard result. Không dùng signal gây lãng phí bandwidth nhưng không gây bug." },
  { id: 1062, category: "State Management", subcategory: "React Query", level: "advanced", q: "Query Filters trong React Query là gì? Dùng ở đâu?", a: "Query Filters là pattern matching system cho phép target nhóm queries khi thao tác hàng loạt. Dùng trong `invalidateQueries`, `refetchQueries`, `removeQueries`, `cancelQueries`. Filter options: `queryKey` (fuzzy match — `['todos']` match cả `['todos', 1]`), `type` ('active' = đang có subscriber, 'inactive' = cached nhưng không ai dùng, 'all'), `stale` (true/false), `fetchStatus` ('fetching'/'paused'/'idle'). Ví dụ thực tế: user logout → `queryClient.removeQueries({ type: 'all' })` xóa toàn bộ cache. Hoặc: mutation thành công → `invalidateQueries({ queryKey: ['todos'], type: 'active' })` chỉ refetch todos đang hiển thị." },
  { id: 1063, category: "State Management", subcategory: "React Query", level: "advanced", q: "useSuspenseQuery khác gì useQuery? Khi nào dùng?", a: "`useSuspenseQuery` tích hợp React Suspense — thay vì return `isLoading`/`isError`, nó throw Promise (cho Suspense boundary bắt) hoặc throw Error (cho Error Boundary bắt). Kết quả: `data` luôn defined (TypeScript happy), không cần if/else cho loading/error states. Code gọn hơn: component chỉ chứa happy path. Suspense boundary ở parent xử lý loading, ErrorBoundary xử lý error. Khi nào dùng: project đã adopt Suspense pattern, muốn tách loading UI khỏi component logic. Khi nào KHÔNG dùng: cần kiểm soát loading state chi tiết, cần show partial data trong khi fetch. Lưu ý: nhiều useSuspenseQuery trong 1 component sẽ waterfall — dùng `useSuspenseQueries` để parallel." },
  { id: 1064, category: "State Management", subcategory: "React Query", level: "advanced", q: "persistQueryClient trong React Query dùng để làm gì?", a: "persistQueryClient cho phép serialize toàn bộ React Query cache vào storage, restore khi user reload → data hiển thị ngay lập tức không cần fetch lại. Setup: `import { persistQueryClient } from '@tanstack/react-query-persist-client'; import { createSyncStoragePersister } from '@tanstack/query-sync-storage-persister'`. `const persister = createSyncStoragePersister({ storage: window.localStorage }); persistQueryClient({ queryClient, persister, maxAge: 1000 * 60 * 60 * 24 })` — maxAge là thời gian data được phép restore (default 24h). Với React Native dùng `createAsyncStoragePersister` cho AsyncStorage. IndexedDB persister cho data lớn hơn localStorage limit (5MB). Khi app load: nếu persisted data còn trong maxAge, hydrate vào cache ngay → queries show cached data, background refetch nếu stale. `buster` option để invalidate toàn bộ persisted cache khi deploy version mới (thay đổi cấu trúc data). Pitfall: không persist sensitive data (tokens, personal info) vì localStorage không mã hóa. Dùng `dehydrateOptions.shouldDehydrateQuery` để filter queries nào được persist." },
  { id: 1065, category: "State Management", subcategory: "React Query", level: "advanced", q: "Mutation side effects: onMutate, onSuccess, onError, onSettled hoạt động ra sao?", a: "useMutation cung cấp 4 lifecycle callbacks, có thể set ở cả mutation level và per-mutate() call level (per-call override mutation level). `onMutate(variables)`: chạy synchronously trước khi mutation request gửi đi — dùng để optimistic update cache, return value trở thành `context` trong onError/onSettled. Nếu return Promise, mutation chờ resolve. `onSuccess(data, variables, context)`: chạy khi API thành công với response data — thường dùng để invalidate related queries: `queryClient.invalidateQueries({ queryKey: ['todos'] })` hoặc setQueryData với response. `onError(error, variables, context)`: chạy khi API fail — context từ onMutate dùng để rollback: `queryClient.setQueryData(['todos'], context.previousTodos)`. `onSettled(data, error, variables, context)`: luôn chạy sau onSuccess hoặc onError (như finally) — an toàn để invalidate queries ở đây vì chạy cả khi success lẫn error. Thứ tự: onMutate → [mutationFn] → onSuccess/onError → onSettled. Pitfall: nếu cả mutation-level và call-level đều có onSuccess, cả hai đều chạy — mutation-level chạy trước." },
  { id: 1066, category: "State Management", subcategory: "React Query", level: "intermediate", q: "keepPreviousData (placeholderData với identity function) dùng khi nào?", a: "keepPreviousData là v3/v4 API, trong v5 thay bằng `placeholderData: (previousData) => previousData` (identity function). Khi queryKey thay đổi (page 1 → page 2), thay vì show loading + clear data cũ, React Query giữ nguyên data của page 1 trong khi fetch page 2 — `isPlaceholderData: true` cho biết đang hiển thị data cũ. UX impact lớn với pagination: user thấy page 1 vẫn hiển thị (có thể mờ đi để indicate loading), page 2 load xong thì replace — không có flash trắng. Kết hợp với prefetch để UX hoàn hảo: `useEffect(() => { if (!isPlaceholderData && hasNextPage) { queryClient.prefetchQuery({ queryKey: ['todos', page + 1], queryFn: () => fetchTodos(page + 1) }) } }, [data, page, isPlaceholderData, queryClient])`. Cũng hữu ích với filter/search: khi user gõ query search, giữ previous results trong khi tìm kiếm mới → không flash empty. Pitfall: nếu dùng `select` transform, previousData cũng đã qua select — types match đúng." },
  { id: 1067, category: "State Management", subcategory: "React Query", level: "advanced", q: "React Query DevTools là gì? Cách sử dụng?", a: "React Query DevTools (`@tanstack/react-query-devtools`) là công cụ debug chuyên dụng, hiển thị floating panel trong browser. Tính năng: xem tất cả queries và trạng thái real-time (fresh/stale/inactive/fetching), inspect cached data dạng JSON tree, xem query timing (khi nào fetch, bao lâu), manual trigger refetch/invalidate/remove/reset từng query, xem subscribers count. Setup: `import { ReactQueryDevtools } from '@tanstack/react-query-devtools'` → đặt `<ReactQueryDevtools initialIsOpen={false} />` bên trong QueryClientProvider. Tự động ẩn trong production build (tree-shaken). Rất hữu ích khi debug cache issues: tại sao data stale, query nào đang fetch, cache hit hay miss. Là 1 trong những lý do developer chọn React Query — visibility vào cache layer mà Redux DevTools không cho." },
  { id: 1068, category: "State Management", subcategory: "React Query", level: "advanced", q: "Cách xử lý race conditions trong React Query?", a: "Race condition xảy ra khi nhiều requests cùng lúc và response muộn hơn override response mới hơn — vấn đề kinh điển với useEffect + fetch. React Query giải quyết ở nhiều tầng: (1) Cancellation: khi queryKey thay đổi (ví dụ search input), React Query abort request cũ nếu queryFn nhận và dùng signal — `queryFn: ({ signal }) => fetch(url, { signal })`. (2) Deduplication: nếu query đang fetch và component khác request cùng queryKey, React Query không gửi thêm request mà share kết quả — chỉ 1 request. (3) Strict mode safety: React Query không commit kết quả của request đã bị replace bởi request mới hơn. (4) `enabled` pattern cho dependent queries: `enabled: !!userId` đảm bảo không fetch với stale userId. Comparison với useEffect: với useEffect bạn phải manually track và cancel với cleanup function `return () => { cancelled = true }` hoặc AbortController — dễ leak và dễ có bugs. React Query làm tất cả điều này tự động miễn là queryFn sử dụng signal." },
  { id: 1069, category: "State Management", subcategory: "React Query", level: "intermediate", q: "enabled option trong useQuery dùng để làm gì?", a: "`enabled` option kiểm soát khi nào query được phép chạy — là boolean hoặc function trả về boolean. Khi `enabled: false`, query ở trạng thái 'disabled': không auto-fetch, status là 'pending' với `fetchStatus: 'idle'` (không phải loading). Khi enabled chuyển từ false sang true, query tự động fetch ngay. Use cases: (1) Dependent queries — chỉ fetch khi dependency sẵn sàng: `enabled: !!userId && !!orgId`. (2) Lazy queries — chỉ fetch khi user trigger: `const [enabled, setEnabled] = useState(false)` → button onClick: `setEnabled(true)`. (3) Conditional skip — skip query dựa trên route hay feature flag. (4) Pause queries khi offline: `enabled: isOnline`. Pattern với TypeScript: khi `enabled: !!userId`, TypeScript vẫn thấy `userId` có thể undefined trong queryFn — workaround: `queryFn: () => fetchUser(userId!)` hoặc `queryFn: () => fetchUser(userId as string)`. Pitfall: `enabled: someExpensiveCheck()` gọi mỗi render — wrap trong useMemo nếu check tốn kém. isLoading với disabled query: `isLoading` = true nếu enabled=false và chưa có data (status=pending) — check `fetchStatus === 'idle'` để phân biệt disabled vs loading." },
  { id: 1070, category: "State Management", subcategory: "React Query", level: "advanced", q: "So sánh React Query với SWR? Khi nào chọn cái nào?", a: "So sánh chi tiết React Query (TanStack Query v5) vs SWR v2: Bundle size — SWR ~4KB, React Query ~13KB (nhưng features nhiều hơn 3x). API philosophy — SWR ưu tiên simplicity và convention, React Query ưu tiên control và flexibility. Mutations: React Query có `useMutation` hook đầy đủ (onMutate, onSuccess, onError, onSettled, optimistic updates), SWR không có mutation hook — thường dùng thư viện khác hoặc tự viết. DevTools: React Query có DevTools panel chi tiết, SWR không có DevTools chính thức. Infinite queries: cả hai có, nhưng React Query có `getNextPageParam` + `getPreviousPageParam` linh hoạt hơn. Prefetching + SSR: React Query có dehydrate/HydrationBoundary pattern rõ ràng hơn, SWR có `fallback` prop đơn giản hơn. Cache key: React Query dùng array (type-safe, fuzzy match), SWR dùng string/function. Offline support: React Query có `networkMode` option, SWR basic. Kết luận: chọn SWR khi app chủ yếu read-only data fetching, team muốn đơn giản, bundle size quan trọng, dùng nhiều với Next.js pages router. Chọn React Query khi cần mutations phức tạp, optimistic updates, DevTools cho debugging, team cần full-featured solution." },

  // === STATE MANAGEMENT: Recoil & Jotai (641-650) ===
  { id: 641, category: "State Management", subcategory: "Recoil", level: "intermediate", q: "Recoil là gì? Khái niệm atom trong Recoil là gì?", a: "Recoil là thư viện atomic state management từ Meta, thiết kế để giải quyết vấn đề fine-grained reactivity mà Redux và Context API không làm tốt. Atom là đơn vị state nhỏ nhất, độc lập, tương tự useState nhưng có thể chia sẻ giữa nhiều component. Ví dụ: `const darkModeAtom = atom({ key: 'darkMode', default: false })` — component nào dùng `useRecoilState(darkModeAtom)` chỉ re-render khi atom đó thay đổi, không bị ảnh hưởng bởi atoms khác. Đây là ưu điểm lớn so với Redux store monolithic hay Context làm re-render toàn cây. Tuy nhiên Recoil vẫn đang beta và ít được adopt hơn Zustand hay Jotai trong projects mới." },
  { id: 642, category: "State Management", subcategory: "Recoil", level: "intermediate", q: "Selector trong Recoil là gì? Khác gì với atom?", a: "Selector là derived state — pure function tính toán từ atoms/selectors khác, tự động memoize và chỉ re-compute khi dependencies thay đổi (dependency graph tự động). Ví dụ: `const totalPriceSelector = selector({ key: 'totalPrice', get: ({get}) => get(cartAtom).reduce((sum, item) => sum + item.price, 0) })`. Khác atom ở chỗ: không có initial value, không ghi trực tiếp (ngoại trừ writeable selector dùng thêm `set` function). Async selector: trả về Promise trong `get`, component tự suspend — `const userSelector = selector({ key: 'user', get: async ({get}) => await fetchUser(get(userIdAtom)) })`. Về memoization: Recoil giữ cache theo tổ hợp dependency values, giống Reselect nhưng không cần khai báo thủ công input selectors. Khác Redux selectors (Reselect) ở chỗ tự track dependencies và support async natively, còn Reselect chỉ sync và phải liệt kê inputs." },
  { id: 643, category: "State Management", subcategory: "Recoil", level: "intermediate", q: "Cách đọc và ghi atom trong Recoil component?", a: "Ba hooks chính với performance implications khác nhau: `useRecoilState(atom)` trả về `[value, setter]` — component subscribe vào atom, re-render mỗi khi value thay đổi (dùng khi cần cả đọc lẫn ghi trong cùng component). `useRecoilValue(atom)` chỉ đọc — cũng subscribe và re-render khi value thay đổi, dùng cho display-only components. `useSetRecoilState(atom)` chỉ trả về setter function, KHÔNG subscribe vào atom — component sẽ KHÔNG re-render khi atom thay đổi, đây là điểm quan trọng về performance: ví dụ nút 'Add to Cart' chỉ cần ghi vào cartAtom mà không cần đọc giá trị nên dùng `useSetRecoilState` để tránh re-render không cần thiết. `useResetRecoilState(atom)` reset về defaultValue. Subscription model: mỗi atom có danh sách subscribers, khi atom thay đổi chỉ notify đúng những components đang subscribe, không gây re-render waterfall như Context." },
  { id: 644, category: "State Management", subcategory: "Jotai", level: "intermediate", q: "Jotai là gì? So sánh với Recoil?", a: "Jotai là thư viện atomic state management tương tự Recoil nhưng nhỏ gọn hơn (~3KB vs ~21KB) và API đơn giản hơn đáng kể. Điểm khác biệt chính: Jotai không yêu cầu `key` string duy nhất cho mỗi atom (Recoil bắt buộc, dễ gây conflict trong large codebase), không cần `RecoilRoot` wrapper (Jotai dùng WeakMap nên hoạt động không cần Provider). Cú pháp gần với useState hơn: `const countAtom = atom(0)`, trong component: `const [count, setCount] = useAtom(countAtom)`. Jotai cũng hỗ trợ derived atoms, async atoms với Suspense, và có thể dùng `atomWithStorage` để persist. Trong thực tế 2024-2026, Jotai được adopt nhiều hơn Recoil vì Recoil vẫn chưa ra stable release và Meta giảm investment." },
  { id: 645, category: "State Management", subcategory: "Jotai", level: "intermediate", q: "Cách tạo và sử dụng atom trong Jotai?", a: "Primitive atom: `const countAtom = atom(0)` — trong component dùng `useAtom(countAtom)` trả về `[value, setValue]`. Derived read-only: `const doubleAtom = atom(get => get(countAtom) * 2)` — dùng `useAtomValue`. Derived read-write: `atom(get => get(baseAtom), (get, set, newVal) => set(baseAtom, newVal * 2))`. `atomWithStorage('key', defaultVal)` từ `jotai/utils` tự đồng bộ localStorage, handle SSR hydration. `atomWithDefault(get => get(otherAtom))` tạo atom có thể override nhưng mặc định derive. Architecture Provider-less: Jotai dùng WeakMap lưu state theo atom object reference thay vì string key như Recoil — atoms tự nhiên unique, hỗ trợ code-split, không lo duplicate key. `useAtomValue` (chỉ đọc) và `useSetAtom` (chỉ ghi, không subscribe, không re-render) là hooks tối ưu performance." },
  { id: 646, category: "State Management", subcategory: "Jotai", level: "advanced", q: "Async atoms trong Jotai hoạt động như thế nào?", a: "Async read atom: `const userAtom = atom(async (get) => { const id = get(userIdAtom); return await fetchUser(id); })` — component dùng `useAtomValue(userAtom)` sẽ tự suspend trong khi fetch (cần bọc `<Suspense>`). Đây là tích hợp với React Suspense tự nhiên nhất trong các state libs. `loadable(userAtom)` từ `jotai/utils` trả về `{ state: 'loading'|'hasData'|'hasError', data, error }` — tránh Suspense khi cần kiểm soát loading UI thủ công. `atomWithQuery` từ `jotai-tanstack-query` tích hợp TanStack Query vào atom: `const postsAtom = atomWithQuery(() => ({ queryKey: ['posts'], queryFn: fetchPosts }))`. Pitfall: async atom re-fetch mỗi khi dependency atom thay đổi, không có built-in stale-time như React Query — dùng `atomWithQuery` nếu cần caching strategy phức tạp." },
  { id: 647, category: "State Management", subcategory: "Recoil", level: "advanced", q: "AtomFamily và selectorFamily trong Recoil là gì?", a: "atomFamily (Recoil): `const todoItemAtom = atomFamily({ key: 'TodoItem', default: id => ({ id, text: '', done: false }) })` — mỗi id tạo một atom độc lập: `useRecoilState(todoItemAtom(42))`. selectorFamily tương tự cho selectors có tham số: `const filteredTodosSelector = selectorFamily({ key: 'FilteredTodos', get: (filter) => ({get}) => get(todoListAtom).filter(t => t.status === filter) })`. Serialization của params: params phải serializable (string/number/plain object), vì Recoil dùng `JSON.stringify` để tạo cache key — object params phải có thứ tự properties nhất quán. Memory management: atoms trong family không bị GC tự động khi component unmount — trong app lớn cần dùng `useRecoilCallback` để cleanup hoặc dùng `effects` để reset. Jotai tương đương: `atomFamily` từ `jotai/utils`, đơn giản hơn và params có thể dùng Map nên linh hoạt hơn." },
  { id: 648, category: "State Management", subcategory: "Recoil", level: "advanced", q: "So sánh bundle size và performance giữa Recoil, Jotai và Zustand?", a: "Bundle size (minified+gzipped): Jotai ~3KB, Zustand ~1KB (core) đến ~8KB với middleware, Recoil ~21KB. Re-render characteristics: tất cả đều fine-grained — chỉ re-render component subscribe đúng atom/slice thay đổi, khác Context API re-render cả cây. Jotai vs Zustand về perf: Jotai atomic model tốt cho graph-shaped state với nhiều derived values, Zustand tốt hơn khi cần batch updates và ít derived state. Memory: Recoil giữ cache selector theo dependency combinations — large selector graphs có thể tốn memory. Tree-shaking: Jotai và Zustand tree-shakeable tốt (ESM-first), Recoil ít hơn do internal atom registry global. Benchmark thực tế (js-framework-benchmark): cả ba tương đương nhau về raw render speed, bottleneck thường là React reconciliation chứ không phải state library. Khuyến nghị 2025: Zustand cho simplicity+tiny bundle, Jotai cho fine-grained atomic state, tránh Recoil cho project mới." },
  { id: 649, category: "State Management", subcategory: "Jotai", level: "intermediate", q: "Jotai Provider là gì? Khi nào cần dùng?", a: "Provider-less (mặc định): Jotai dùng global WeakMap store — mọi component trong app share cùng atom values mà không cần wrap Provider. Khi nào cần Provider: (1) Testing — `<Provider store={createStore()}>` tạo isolated store mỗi test, tránh state leak giữa tests; (2) Micro-frontend — mỗi app widget có store riêng; (3) Reset toàn bộ atoms khi component unmount (ví dụ modal dialog). Store API: `const myStore = createStore(); myStore.get(atom); myStore.set(atom, value); myStore.sub(atom, callback)` — dùng để interact với atoms ngoài React (WebSocket handlers, analytics). Tradeoff: Provider-less tiện nhưng dễ gây test pollution nếu không reset; with-Provider an toàn hơn cho testing nhưng cần boilerplate. `<Provider store={store}>` cũng là cách implement DevTools hoặc persist toàn bộ store state." },
  { id: 650, category: "State Management", subcategory: "Recoil", level: "advanced", q: "Khi nào nên dùng atomic state management (Recoil/Jotai) thay vì Redux/Zustand?", a: "Decision matrix — dùng Atomic (Jotai/Recoil) khi: (1) State có cấu trúc graph, nhiều derived values từ base atoms (ví dụ: cart total, filtered lists, computed stats đều derive từ cùng nguồn); (2) Cần fine-grained updates — 1000 items list, mỗi item là 1 atom, chỉ item thay đổi mới re-render; (3) State không nhất thiết phải centralized — features khác nhau sở hữu atoms riêng; (4) Cần co-locate state với components sử dụng nó. Dùng Redux/Zustand khi: cần single source of truth có thể serialize/rehydrate, cần time-travel debugging, team quen với flux pattern, cần middleware pipeline (logging, side effects). Real use cases Atomic: collaborative editor (mỗi doc element là atom), form builder (mỗi field là atom), dashboard với nhiều widgets độc lập. Pitfall: atomic state khó debug hơn khi dependencies phức tạp — không có Redux DevTools tương đương để xem toàn bộ state graph." },

  // === NODE.JS: Cơ Bản (651-660) ===
  { id: 651, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "Node.js là gì? Điểm khác biệt với JavaScript trên trình duyệt?", a: "Node.js là runtime environment cho phép chạy JavaScript trên server, được xây dựng trên V8 engine của Chrome và thư viện C++ libuv xử lý async I/O. Khác biệt cốt lõi với browser JS: không có DOM, window, document, localStorage — thay vào đó có `fs` (đọc/ghi file), `http` (tạo server), `path`, `os`, `crypto` và hàng nghìn npm packages. Ví dụ thực tế: `const fs = require('fs'); fs.readFile('data.json', 'utf8', (err, data) => console.log(data))` — đây là code không thể chạy trong browser. Node.js dùng event loop single-threaded nên xử lý hàng nghìn concurrent connections hiệu quả với I/O-heavy workloads như API server, real-time chat. Không phù hợp cho CPU-intensive tasks như video encoding vì block event loop." },
  { id: 652, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "V8 engine là gì? Vai trò của nó trong Node.js?", a: "V8 là JavaScript engine mã nguồn mở của Google viết bằng C++, được dùng trong Chrome và là trái tim của Node.js. Điểm khác biệt quan trọng: V8 không interpret JS từng dòng mà dùng JIT (Just-In-Time) compilation — biên dịch JS thành native machine code ngay lúc chạy, cho tốc độ nhanh gần bằng C++. Node.js nhúng V8 vào C++ runtime và bổ sung thêm libuv (async I/O), các built-in modules (fs, http, crypto...) để tạo thành môi trường chạy JS hoàn chỉnh ngoài browser. Thực tế ảnh hưởng đến dev: V8 có hidden class optimization — object có cùng shape (thứ tự properties) sẽ dùng chung internal class và chạy nhanh hơn, nên tránh thêm properties động vào object sau khi tạo trong hot paths." },
  { id: 653, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "Event-driven architecture trong Node.js nghĩa là gì?", a: "Event-driven architecture nghĩa là code phản ứng với events thay vì chạy tuần tự từ trên xuống. Trong Node.js, thay vì blocking chờ đợi I/O xong, bạn đăng ký callback và Node.js tiếp tục xử lý việc khác — khi I/O hoàn thành, event được emit và callback được gọi. Ví dụ cụ thể: `server.on('request', (req, res) => {...})` — server không blocking chờ từng request mà lắng nghe event 'request' liên tục. Điều này cho phép một thread đơn xử lý hàng nghìn connections đồng thời vì hầu hết thời gian Node.js không làm gì cả, chỉ chờ I/O. Pitfall: nếu bạn chạy heavy computation đồng bộ (vòng lặp triệu lần), event loop bị block và mọi requests khác phải chờ — đây là lý do Node.js không phù hợp cho CPU-intensive work." },
  { id: 654, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "Non-blocking I/O trong Node.js là gì? Tại sao quan trọng?", a: "Non-blocking I/O hoạt động nhờ libuv delegate I/O operations cho OS kernel hoặc thread pool: khi gọi `fs.readFile()`, Node.js đăng ký callback rồi trả control về event loop ngay lập tức, OS xử lý I/O ở background, khi xong thêm callback vào event queue để event loop xử lý. So với blocking model Apache (thread-per-request): Apache cấp 1 thread/request, thread block khi chờ DB query — 1000 concurrent requests cần 1000 threads (~1GB RAM). Node.js single-threaded xử lý 1000 requests trên 1 thread vì hầu hết thời gian chờ I/O là idle. Throughput thực tế: Node.js thường đạt 10k-50k req/s cho I/O-heavy API, so với Apache ~1k-5k req/s. Khi nào blocking xảy ra accidentaly: `fs.readFileSync()`, `JSON.parse(largeData)`, vòng lặp tính toán nặng, `crypto.pbkdf2Sync()` — tất cả đều block event loop và làm tất cả requests khác phải chờ. Solution: Worker Threads cho CPU-intensive, luôn dùng async variants." },
  { id: 655, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "npm là gì? Phân biệt npm install, npm install --save-dev?", a: "npm (Node Package Manager) là công cụ quản lý packages mặc định đi kèm Node.js, với registry hơn 2 triệu packages. Phân biệt quan trọng: `npm install react` cài vào `dependencies` — những gì cần thiết để app chạy trên production. `npm install --save-dev jest typescript eslint` cài vào `devDependencies` — chỉ cần trong quá trình development, không được bundle vào production build. Ví dụ thực tế: khi deploy lên server, chạy `npm install --production` sẽ bỏ qua devDependencies, giảm đáng kể dung lượng `node_modules`. Pitfall hay gặp: cài nhầm package production vào devDependencies (app crash trên server) hoặc ngược lại (bloat production bundle). Ngoài npm còn có pnpm (nhanh hơn, tiết kiệm disk) và yarn đang được dùng phổ biến." },
  { id: 656, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "package.json là gì? Các trường quan trọng trong package.json?", a: "package.json là manifest file của Node.js project. `scripts` hỗ trợ lifecycle hooks: `preinstall`/`postinstall` chạy trước/sau npm install, `prebuild`/`postbuild` bao quanh `build` — dùng để codegen, copy assets. `engines: { node: '>=18.0.0' }` báo CI/CD và người dùng version Node cần thiết, npm cảnh báo nếu không match. Entry points: `main` (CJS fallback), `module` (ESM cho bundlers hỗ trợ), `exports` (field mới nhất — conditional exports theo environment): `{ '.': { import: './dist/index.mjs', require: './dist/index.cjs' } }`. `type: 'module'` đặt default module system là ESM cho tất cả `.js` files. `workspaces: ['packages/*']` cho monorepo — npm install một lần, symlink packages. `peerDependencies` khai báo packages host app phải cung cấp (tránh duplicate React trong component libraries)." },
  { id: 657, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "package-lock.json là gì? Tại sao nên commit file này?", a: "package-lock.json lưu exact versions + integrity hashes (sha512) của tất cả packages kể cả transitive dependencies — đảm bảo install reproducible trên mọi máy/CI. `npm install` cập nhật lock file nếu package.json thay đổi; `npm ci` (clean install) xóa node_modules rồi install chính xác từ lock file, không bao giờ update lock — dùng trong CI/CD để đảm bảo deterministic builds. Khi nào xóa và regenerate: khi lock file bị corrupt, sau major Node.js upgrade, hoặc khi muốn update tất cả dependencies lên latest compatible. Integrity field: `'integrity': 'sha512-abc...'` — npm verify hash sau download, phát hiện supply chain attacks (tampered packages). Tương đương: `yarn.lock` (Yarn), `pnpm-lock.yaml` (pnpm) — cùng mục đích nhưng format khác nhau. Quan trọng: KHÔNG commit lock file của library packages lên npm registry (chỉ commit lock của applications)." },
  { id: 658, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "CommonJS modules (require/module.exports) và ES Modules (import/export) trong Node.js khác nhau như thế nào?", a: "CommonJS (CJS): `require()` load synchronous và blocking — có thể require() ở bất kỳ đâu trong code kể cả trong if/function, module.exports là bất kỳ giá trị gì, không hỗ trợ tree-shaking. ESM: `import` phải ở top-level (static analysis), load asynchronous cho phép parallel fetch, tree-shakeable vì bundlers biết chính xác exports nào được dùng. ESM exclusive features: top-level `await`, import.meta.url, dynamic `import()`. Interop challenges: CJS có thể `require()` ESM file? Không được, phải dùng dynamic `import()`. ESM có thể import CJS? Có, nhưng chỉ default import. Dual package hazard: publish cả CJS lẫn ESM cùng package — nếu app load cả hai, sẽ có 2 instances của module (state, class không share được). Giải pháp: conditional exports trong package.json. `type: 'module'` trong package.json = tất cả `.js` là ESM, CJS phải đổi thành `.cjs`. Node.js 22+ hỗ trợ `--experimental-require-module` để require() ESM." },
  { id: 659, category: "Node.js", subcategory: "Cơ Bản", level: "intermediate", q: "process object trong Node.js cung cấp những gì?", a: "process là global object không cần require. `process.env`: chứa environment variables — KHÔNG bao giờ log toàn bộ `process.env` vì chứa secrets; validate với zod/envalid ngay startup để fail fast nếu thiếu. `process.argv`: array `[nodePath, scriptPath, ...userArgs]` — dùng `yargs` hoặc `commander` để parse thay vì thủ công. Signal handling: `process.on('SIGTERM', gracefulShutdown)` — xử lý khi container/PM2 dừng process (close DB connections, finish in-flight requests); `SIGINT` = Ctrl+C. `process.memoryUsage()` trả về `{ rss, heapTotal, heapUsed, external }` — monitor memory leaks bằng cách log định kỳ. `process.hrtime.bigint()` cho high-resolution timestamps (nanoseconds) để benchmark code. `process.exit(1)` exit với error code — quan trọng cho CI pipelines biết lệnh fail. `process.on('uncaughtException')` và `process.on('unhandledRejection')` — log error rồi `process.exit(1)`, không recover vì process state có thể corrupt." },
  { id: 660, category: "Node.js", subcategory: "Cơ Bản", level: "intermediate", q: "Sự khác biệt giữa __dirname và __filename trong Node.js?", a: "`__dirname` cho đường dẫn tuyệt đối đến thư mục chứa file đang chạy, `__filename` cho đường dẫn đến chính file đó. Ví dụ thực tế: `path.join(__dirname, 'templates', 'email.html')` để đọc file template bất kể app được chạy từ thư mục nào — nếu dùng đường dẫn tương đối `'./templates/email.html'` sẽ resolve từ `process.cwd()` (thư mục làm việc hiện tại) và có thể sai khi chạy từ nơi khác. Pitfall quan trọng với ES Modules: `__dirname` và `__filename` không tồn tại trong file `.mjs` hoặc khi `type: module` trong package.json. Thay thế: `import { fileURLToPath } from 'url'; import { dirname } from 'path'; const __filename = fileURLToPath(import.meta.url); const __dirname = dirname(__filename)`." },

  // === NODE.JS: Event Loop & Async (661-670) ===
  { id: 661, category: "Node.js", subcategory: "Event Loop", level: "intermediate", q: "Event loop trong Node.js hoạt động như thế nào?", a: "Event loop là vòng lặp liên tục xử lý callbacks theo 6 phases: (1) Timers: thực thi callbacks của `setTimeout`/`setInterval` đã đến hạn; (2) Pending callbacks: I/O errors từ vòng trước; (3) Idle/prepare: internal use; (4) Poll: fetch I/O events mới — nếu queue empty và không có timers pending, block tại đây chờ I/O; (5) Check: `setImmediate` callbacks; (6) Close callbacks: `socket.on('close')`. Giữa MỖI phase, Node.js xử lý toàn bộ microtask queue: Promise callbacks (`then`/`catch`) + `queueMicrotask()` + `process.nextTick()` (nextTick ưu tiên hơn Promise). Starvation: nếu microtask queue không bao giờ empty (Promise resolve tạo Promise mới), event loop không bao giờ qua phase tiếp theo. Ví dụ thực tế execution order: `setTimeout(A, 0)` → `Promise.resolve().then(B)` → `process.nextTick(C)` — thứ tự chạy: C, B, A." },
  { id: 662, category: "Node.js", subcategory: "Event Loop", level: "intermediate", q: "Sự khác biệt giữa setTimeout(fn, 0) và setImmediate() là gì?", a: "setTimeout(fn, 0) thực ra là setTimeout(fn, 1) minimum — chạy trong timers phase nếu timer đã expired. setImmediate() chạy trong check phase (ngay sau poll phase). Ngoài I/O context (ví dụ main script): thứ tự giữa hai cái không đảm bảo — phụ thuộc vào system clock resolution và thời gian setup event loop. Trong I/O callback context: setImmediate() LUÔN chạy trước setTimeout(fn, 0) — vì I/O callback chạy ở poll phase, sau poll là check phase (setImmediate), sau đó mới quay lại timers phase. Ví dụ: `fs.readFile(file, () => { setImmediate(() => console.log('immediate')); setTimeout(() => console.log('timeout'), 0); })` — luôn in 'immediate' trước 'timeout'. Practical implication: khi muốn chạy code sau I/O operation hiện tại mà trước timers, dùng setImmediate." },
  { id: 663, category: "Node.js", subcategory: "Event Loop", level: "advanced", q: "process.nextTick() khác setImmediate() như thế nào?", a: "process.nextTick() không thuộc bất kỳ phase nào của event loop — callbacks được đặt vào nextTick queue và chạy ngay sau synchronous code hiện tại kết thúc, trước khi event loop tiếp tục phase tiếp theo (kể cả trước Promise microtasks). setImmediate() thuộc check phase. Thứ tự ưu tiên: synchronous code → nextTick queue → Promise microtasks → event loop phases (timers → poll → check/setImmediate). Starvation danger: recursive `process.nextTick()` sẽ block event loop mãi mãi — không bao giờ cho I/O callbacks chạy. Node.js docs khuyên dùng `setImmediate()` thay nextTick trong hầu hết trường hợp. Khi nextTick phù hợp: emit event sau constructor return (để listener đăng ký kịp), propagate error asynchronously trong API mà phải consistent async. Khi setImmediate phù hợp: chia nhỏ heavy computation qua nhiều iterations mà vẫn cho I/O xen vào." },
  { id: 664, category: "Node.js", subcategory: "Async", level: "intermediate", q: "Callback hell là gì? Cách giải quyết?", a: "Callback hell (pyramid of doom) — ví dụ thực: `fs.readFile('a.txt', (err, data) => { if(err) throw err; db.query(data, (err, rows) => { if(err) throw err; sendEmail(rows[0], (err) => { if(err) throw err; console.log('done') }) }) })` — 3 cấp lồng nhau, error handling lặp lại, logic khó theo dõi. Giải pháp Promise chaining: `readFile('a.txt').then(data => db.query(data)).then(rows => sendEmail(rows[0])).catch(err => console.error(err))` — flat hơn nhưng còn awkward với multi-value. Giải pháp async/await: `try { const data = await readFile('a.txt'); const rows = await db.query(data); await sendEmail(rows[0]); } catch(err) { console.error(err); }` — đọc như synchronous code, try/catch natural. Error propagation khác nhau: callback phải check `err` mỗi cấp thủ công, một missed check = silent failure; Promise/async throw tự động bubble up đến .catch/try-catch. Pitfall async/await: `await` trong vòng lặp `for...of` sẽ chạy sequential — dùng `Promise.all(items.map(item => process(item)))` để parallel." },
  { id: 665, category: "Node.js", subcategory: "Async", level: "intermediate", q: "Promise trong Node.js hoạt động như thế nào? Các states của Promise?", a: "Promise là object đại diện cho async operation, có 3 states không thể revert: pending → fulfilled/rejected. Microtask queue: `.then()` callbacks được đặt vào microtask queue (ưu tiên cao hơn setTimeout), chạy sau synchronous code nhưng trước event loop phases. Static methods quan trọng: `Promise.all([p1,p2])` — chờ tất cả resolve, reject ngay khi 1 cái reject (fail-fast); `Promise.allSettled([p1,p2])` — chờ tất cả settle bất kể kết quả, trả về `[{status, value/reason}]` — dùng khi muốn biết kết quả từng cái; `Promise.race([p1,p2])` — resolve/reject theo cái đầu tiên settle (dùng cho timeout pattern); `Promise.any([p1,p2])` — resolve khi 1 cái fulfilled, reject chỉ khi tất cả reject. Error handling chain: nếu không có `.catch()`, unhandled rejection — Node.js 15+ crash process mặc định. `Promise.resolve(value)` tạo fulfilled promise ngay, hữu ích để normalize sync/async APIs. Pitfall: error swallowing trong `.then(onFulfilled)` không có `.catch()` — luôn chain `.catch()` hoặc dùng try/catch với await." },
  { id: 666, category: "Node.js", subcategory: "Async", level: "intermediate", q: "async/await trong Node.js là gì? Lợi ích so với Promise chains?", a: "async/await là syntactic sugar trên Promise — `async function` luôn return Promise, `await` pause execution của function đó (không block thread) cho đến khi Promise settle. Error handling: try/catch bắt rejected Promise như exception thông thường — `try { const data = await fetch(url).then(r => r.json()); } catch(e) { /* network error, JSON parse error */ }`. Parallel execution: sequential `await a(); await b()` tổng thời gian = a + b; parallel `const [ra, rb] = await Promise.all([a(), b()])` tổng thời gian = max(a, b). Pitfall #1 — sequential await trong loop: `for (const id of ids) { await fetchUser(id); }` chạy tuần tự, chậm. Fix: `await Promise.all(ids.map(id => fetchUser(id)))`. Pitfall #2 — error không được handle: `async function foo() { await riskyOp(); }` gọi `foo()` mà không await/catch = unhandled rejection. Top-level await: ESM modules hỗ trợ `await` ở top level (ngoài function) — hữu ích cho dynamic imports, DB init. Khi debug: stack traces của async/await rõ ràng hơn Promise chains nhiều." },
  { id: 667, category: "Node.js", subcategory: "Streams", level: "advanced", q: "Streams trong Node.js là gì? Có những loại stream nào?", a: "Stream xử lý data theo chunks — memory efficiency cực cao: đọc file 1GB chỉ tốn ~64KB RAM (default highWaterMark) thay vì 1GB. Bốn loại: Readable (fs.createReadStream, HTTP req, process.stdin), Writable (fs.createWriteStream, HTTP res, process.stdout), Duplex (TCP socket — đọc và ghi độc lập), Transform (zlib.createGzip, crypto.createCipher — transform data flow through). `pipeline()` API (Node.js 10+) thay thế `.pipe()`: `await pipeline(readStream, transformStream, writeStream)` — tự cleanup và propagate errors (`.pipe()` không handle errors tốt). Stream consumers với `for await...of`: `for await (const chunk of readableStream) { process(chunk); }` — ergonomic nhất. Ví dụ thực: serve 1GB file với 0 timeout và thấp RAM: `const src = fs.createReadStream(filePath); const gzip = zlib.createGzip(); await pipeline(src, gzip, res)` — data chảy qua, không buffer toàn bộ. Backpressure: khi Writable chậm hơn Readable, `pipeline` tự pause Readable tránh OOM — đây là lý do không dùng `.pipe()` thủ công trong production." },
  { id: 668, category: "Node.js", subcategory: "Streams", level: "advanced", q: "pipe() trong Node.js streams là gì?", a: "pipe() kết nối Readable stream với Writable stream, tự động quản lý flow và backpressure. Dữ liệu chảy từ source đến destination theo chunks, không cần load toàn bộ vào memory. Ví dụ: `fs.createReadStream('file').pipe(gzip).pipe(response)` để stream file nén đến HTTP response." },
  { id: 669, category: "Node.js", subcategory: "Buffers", level: "intermediate", q: "Buffer trong Node.js là gì? Khi nào cần dùng?", a: "Buffer là class built-in xử lý binary data — vùng nhớ raw bytes nằm ngoài V8 heap. JavaScript thuần không có kiểu dữ liệu binary, Buffer lấp đầy khoảng trống này cho Node.js. Cần dùng khi: đọc file binary (ảnh, PDF, executable), xử lý network packets TCP/UDP, mã hóa/giải mã base64 (`Buffer.from('hello').toString('base64')`), tính hash với `crypto.createHash`. Ví dụ thực tế: upload ảnh qua API, `req.body` là Buffer chứa raw bytes của file, cần convert hoặc pipe trực tiếp lên S3. Pitfall: `Buffer.allocUnsafe(size)` nhanh hơn nhưng chứa dữ liệu cũ trong bộ nhớ — chỉ dùng khi sẽ ghi đè toàn bộ ngay sau đó, dùng `Buffer.alloc(size)` (zero-filled) cho trường hợp thông thường." },
  { id: 670, category: "Node.js", subcategory: "Event Loop", level: "advanced", q: "Libuv là gì? Vai trò trong Node.js?", a: "Libuv là C library đa nền tảng cung cấp event loop, async I/O và thread pool cho Node.js. Hai loại operations: (1) OS-native async (không dùng thread pool): network I/O (TCP/UDP) — dùng epoll (Linux), kqueue (macOS), IOCP (Windows), cực efficient; (2) Thread pool operations (dùng 4 threads mặc định vì OS không hỗ trợ async đầy đủ): file system I/O (fs.readFile), DNS lookup (dns.lookup — không phải dns.resolve), crypto operations (pbkdf2, scrypt, randomBytes). Thread pool size: tăng bằng env var `UV_THREADPOOL_SIZE=16` (max 1024) — quan trọng khi app làm nhiều file I/O hoặc crypto đồng thời, 4 threads mặc định tạo bottleneck. Ví dụ vấn đề: app gọi 10 `dns.lookup()` đồng thời, 4 threads xử lý 4 cái, 6 cái còn lại queue — tăng UV_THREADPOOL_SIZE hoặc dùng `dns.resolve()` (network I/O, không dùng thread pool). Libuv abstract sự khác biệt giữa OS — cùng Node.js code chạy trên Linux epoll và Windows IOCP mà không cần sửa." },

  // === NODE.JS: HTTP & Express (671-680) ===
  { id: 671, category: "Node.js", subcategory: "HTTP", level: "beginner", q: "Cách tạo HTTP server với module http trong Node.js?", a: "Module `http` là built-in, không cần cài thêm: `const server = http.createServer((req, res) => { res.writeHead(200, { 'Content-Type': 'application/json' }); res.end(JSON.stringify({ ok: true })); }); server.listen(3000)`. `req` chứa method, url, headers và là Readable stream (đọc body qua `req.on('data', chunk => ...)`). `res` là Writable stream — phải gọi `res.end()` để kết thúc, không thì client treo mãi. Trong thực tế hiếm ai dùng `http` module trực tiếp vì rất verbose — Express, Fastify, Hono wrap lại với routing, middleware, body parsing tiện hơn nhiều. Tuy nhiên hiểu `http` module giúp debug networking issues và hiểu cách các framework hoạt động bên dưới." },
  { id: 672, category: "Node.js", subcategory: "Express", level: "beginner", q: "Express.js là gì? Tại sao phổ biến trong Node.js ecosystem?", a: "Express là web framework minimal cho Node.js, cung cấp routing và middleware system mà không áp đặt cấu trúc dự án. Phổ biến nhất trong Node.js ecosystem vì: API cực đơn giản (`app.get('/users', handler)`), middleware pipeline linh hoạt cho phép compose nhiều concerns (auth, logging, validation) thành chuỗi, và hệ sinh thái packages khổng lồ như `cors`, `helmet`, `multer`, `passport`. Express cũng là nền tảng để nhiều framework khác xây dựng lên như NestJS. Tuy nhiên nhược điểm là quá minimal — không có validation, ORM, hay structure built-in, dev phải tự lắp ghép. Với TypeScript projects hiện đại, nhiều team chuyển sang NestJS (opinionated, decorator-based) hoặc Fastify (nhanh hơn 2-3x, schema validation built-in)." },
  { id: 673, category: "Node.js", subcategory: "Express", level: "beginner", q: "Middleware trong Express là gì? Cách hoạt động?", a: "Middleware là function signature `(req, res, next)` thực thi tuần tự theo thứ tự đăng ký — thứ tự là tuyệt đối. App-level: `app.use(helmet())` áp dụng cho toàn bộ app. Router-level: `router.use(authMiddleware)` chỉ cho nhóm routes. Error-handling middleware có 4 tham số `(err, req, res, next)` phải đăng ký SAU tất cả routes. Third-party ecosystem: `helmet` (security headers), `morgan` (logging), `compression` (gzip), `passport` (auth strategies). Flow: `next()` chuyển sang middleware tiếp theo, `next(err)` nhảy thẳng tới error handler bỏ qua tất cả non-error middleware, không gọi `next()` và không `res.send()` thì request treo mãi. Pitfall: đặt `express.json()` sau route handler → `req.body` undefined; đặt `cors()` sau route → preflight OPTIONS request trả 404." },
  { id: 674, category: "Node.js", subcategory: "Express", level: "intermediate", q: "Router trong Express là gì? Cách tổ chức routes?", a: "express.Router() tạo mini-app với routes và middleware riêng biệt — giải pháp chính để tổ chức code theo feature. Mounting pattern: `app.use('/api/v1/users', userRouter)` prefix tất cả routes trong router. Route-level middleware: `router.use(authMiddleware)` chỉ áp dụng cho routes trong router đó. Nested routers: `adminRouter.use('/users', adminUserRouter)` để nest sâu hơn. Versioned API pattern: `app.use('/api/v1', v1Router); app.use('/api/v2', v2Router)` — v1 và v2 hoàn toàn độc lập, dễ deprecate. Cấu trúc thực tế: `routes/users.ts` export router, `routes/index.ts` aggregate tất cả routers, `app.ts` chỉ `app.use('/api', mainRouter)`. Pitfall: `router.use(middleware)` sau `router.get(...)` thì route đó không được áp dụng middleware — phải đặt middleware TRƯỚC routes." },
  { id: 675, category: "Node.js", subcategory: "Express", level: "intermediate", q: "REST API trong Express: cách định nghĩa các HTTP methods?", a: "Express map trực tiếp tới HTTP methods với semantics rõ ràng: GET (idempotent, safe — chỉ đọc, không side effects), POST (không idempotent — tạo resource mới, mỗi call tạo record mới), PUT (idempotent — replace toàn bộ resource, gửi thiếu field thì field đó bị null/default), PATCH (idempotent — partial update, chỉ gửi fields cần thay đổi), DELETE (idempotent — xóa, gọi nhiều lần kết quả như nhau). CRUD thực tế: `GET /users` (list), `POST /users` (create, trả 201), `GET /users/:id` (read), `PUT /users/:id` (replace, trả 200), `PATCH /users/:id` (update, trả 200), `DELETE /users/:id` (delete, trả 204 no content). Status codes quan trọng: 200 OK, 201 Created, 204 No Content, 400 Bad Request, 401 Unauthorized, 403 Forbidden, 404 Not Found, 409 Conflict, 422 Unprocessable Entity, 500 Internal Server Error. Content negotiation: `req.accepts('json')` kiểm tra client Accept header. Pitfall: dùng GET với body để filter — không đúng semantics, dùng query params thay thế." },
  { id: 676, category: "Node.js", subcategory: "Express", level: "intermediate", q: "Error handling middleware trong Express hoạt động như thế nào?", a: "Error handling middleware có 4 tham số `(err, req, res, next)` — phải đăng ký CUỐI CÙNG sau tất cả routes. Pattern tốt nhất: tạo custom AppError class `class AppError extends Error { constructor(public statusCode: number, message: string, public isOperational = true) { super(message) } }` — phân biệt operational errors (404, validation fail — dự đoán được) vs programming errors (null reference — bugs). Async error wrapper để tránh try/catch lặp lại: `const asyncHandler = (fn) => (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next)`. Centralized error handler kiểm tra `err.isOperational`: nếu true thì gửi message cho client, nếu false thì log và trả 500 generic. Express 5 async routes tự động forward error nên không cần wrapper nữa. Pitfall: quên `next` tham số thứ 4 → Express không nhận ra là error handler. Không gọi `next()` sau `res.json()` trong error handler → double response error." },
  { id: 677, category: "Node.js", subcategory: "Express", level: "intermediate", q: "CORS trong Express: cách cấu hình cho phép cross-origin requests?", a: "CORS là cơ chế browser bảo vệ user — server phải opt-in cho phép cross-origin requests. Preflight mechanism: browser tự động gửi OPTIONS request trước khi gửi request thật nếu là preflighted request (method không phải GET/POST/HEAD, hoặc header không phải simple header như Content-Type: application/json). Simple requests (GET với simple headers) không cần preflight. Cấu hình production đúng: `cors({ origin: ['https://app.example.com'], methods: ['GET','POST','PUT','PATCH','DELETE'], allowedHeaders: ['Content-Type','Authorization'], credentials: true })` — `credentials: true` bắt buộc khi gửi cookies/Authorization header. Quan trọng: khi `credentials: true`, origin KHÔNG được là `*` — phải liệt kê explicit. Debug tips: (1) kiểm tra response header `Access-Control-Allow-Origin` trong DevTools Network tab, (2) `credentials: true` nhưng server trả `*` → browser chặn, (3) đặt `cors()` TRƯỚC routes để OPTIONS preflight được handle. Pitfall: CORS là browser enforcement — Postman/curl không bị chặn, chỉ browser mới bị." },
  { id: 678, category: "Node.js", subcategory: "Express", level: "intermediate", q: "express.json() và express.urlencoded() middleware dùng để làm gì?", a: "express.json() parse Content-Type application/json thành `req.body` object — built-in từ Express 4.16+, không cần `body-parser` riêng. express.urlencoded({ extended: true }) parse HTML form data (application/x-www-form-urlencoded); `extended: true` dùng `qs` library cho phép nested objects, `extended: false` dùng `querystring` chỉ flat. Size limit mặc định 100kb — thay đổi: `express.json({ limit: '10mb' })`. Security: large payloads gây DoS — luôn set limit hợp lý, không để mặc định cho upload endpoint. Custom content types: `express.json({ type: 'application/vnd.api+json' })`. Raw parser: `express.raw({ type: 'application/octet-stream' })` cho binary. Text parser: `express.text()` cho plain text webhooks. Pitfall: `express.json()` không parse multipart/form-data (file upload) — cần `multer` riêng. Nếu `req.body` là undefined, kiểm tra middleware đã được đăng ký chưa và đúng thứ tự chưa." },
  { id: 679, category: "Node.js", subcategory: "Express", level: "intermediate", q: "Rate limiting trong Express là gì? Cách implement?", a: "Rate limiting bảo vệ API khỏi spam, brute-force và DDoS. Fixed window: đếm requests trong window cố định (0:00-0:15) — dễ bypass bằng cách gửi burst ở cuối window cũ + đầu window mới. Sliding window: window trượt theo thời gian thực, chính xác hơn nhưng cần Redis. `express-rate-limit` dùng fixed window: `rateLimit({ windowMs: 15*60*1000, max: 100, standardHeaders: true, legacyHeaders: false })`. Distributed rate limiting với Redis: `rate-limit-redis` store để share state giữa nhiều server instances — bắt buộc trong cluster/multi-server deployment, nếu dùng in-memory thì mỗi instance có counter riêng, giới hạn thực tế là `max * numInstances`. Rate limit headers trả về client: `RateLimit-Limit`, `RateLimit-Remaining`, `RateLimit-Reset` (standardHeaders: true). Limits khác nhau per endpoint: auth endpoints (5 req/15min), API endpoints (100 req/15min), public endpoints (1000 req/15min). Per-user limits: `keyGenerator: (req) => req.user?.id || req.ip` — authenticated users có limit riêng theo userId thay vì IP. Pitfall: behind reverse proxy thì `req.ip` là IP của proxy — cần `app.set('trust proxy', 1)` để lấy IP thật từ `X-Forwarded-For`." },
  { id: 680, category: "Node.js", subcategory: "Express", level: "advanced", q: "Sự khác biệt giữa Express 4 và Express 5 là gì?", a: "Express 5 (stable 2024): async error handling tự động (throw trong async route tự chuyển đến error handler, không cần try/catch), path matching cải tiến, một số breaking changes về routing syntax. Express 4 yêu cầu wrap async routes với try/catch hoặc dùng `express-async-handler`." },

  // === NODE.JS: Advanced (681-700) ===
  { id: 681, category: "Node.js", subcategory: "Authentication", level: "intermediate", q: "JWT (JSON Web Token) là gì? Cấu trúc của JWT?", a: "JWT là chuẩn mở (RFC 7519) để truyền thông tin an toàn dưới dạng JSON, được ký số để đảm bảo tính toàn vẹn. Gồm 3 phần ngăn cách bởi dấu chấm, mỗi phần base64url-encoded: Header (`{alg: 'HS256', typ: 'JWT'}`), Payload (claims như `{sub: userId, exp: timestamp, role: 'admin'}`), Signature (HMAC của header+payload bằng secret key). Ưu điểm stateless: server không cần lưu session, chỉ cần verify signature — phù hợp microservices và horizontal scaling. Nhược điểm quan trọng: không thể revoke JWT trước khi hết hạn (không có centralized blacklist), nên access token phải có `exp` ngắn (15 phút) kết hợp refresh token. Pitfall phổ biến nhất: lưu JWT trong localStorage thay vì httpOnly cookie — dễ bị XSS đánh cắp." },
  { id: 682, category: "Node.js", subcategory: "Authentication", level: "intermediate", q: "Cách implement JWT authentication trong Express API?", a: "Full auth flow: POST /login → verify credentials → `jwt.sign({ sub: user.id, role: user.role }, secret, { expiresIn: '15m' })` tạo access token + `jwt.sign({ sub: user.id }, refreshSecret, { expiresIn: '7d' })` tạo refresh token → trả access token trong response body, refresh token trong httpOnly cookie (`Set-Cookie: refreshToken=...; HttpOnly; Secure; SameSite=Strict`). Token storage: httpOnly cookie bảo vệ khỏi XSS (JS không đọc được), nhưng cần CSRF protection; localStorage tiện hơn nhưng XSS đánh cắp được — httpOnly cookie là best practice cho web apps. Auth middleware: `const token = req.headers.authorization?.split(' ')[1]; const payload = jwt.verify(token, secret); req.user = payload`. Refresh token rotation: mỗi lần dùng refresh token thì issue cặp mới (access + refresh) và invalidate refresh token cũ — lưu refresh token hash trong DB để có thể revoke. POST /refresh nhận cookie → verify → trả access token mới. POST /logout xóa cookie và blacklist refresh token. Pitfall: không validate `alg` trong header → attacker đổi sang `alg: none`; dùng `{ algorithms: ['HS256'] }` trong verify options." },
  { id: 683, category: "Node.js", subcategory: "Authentication", level: "intermediate", q: "bcrypt là gì? Cách dùng để hash password?", a: "bcrypt được thiết kế đặc biệt cho password hashing — khác hoàn toàn SHA-256/MD5 vốn được tối ưu để NHANH (SHA-256 hash 10 tỷ lần/giây trên GPU, bcrypt cost=12 chỉ ~250 lần/giây). Adaptive cost factor: `saltRounds` (cost) tăng thì thời gian tăng gấp đôi — cost=10 ~100ms, cost=12 ~400ms, cost=14 ~1.6s. Chọn cost sao cho ~250ms trên server của bạn và tăng dần theo năm khi phần cứng mạnh lên. Built-in salt: bcrypt tự tạo random salt unique per password và nhúng vào hash output — tránh rainbow table attacks và đảm bảo cùng password tạo hash khác nhau mỗi lần. Timing attacks: `bcrypt.compare()` là constant-time comparison, không dùng `===` để so sánh hash. Argon2 là alternative hiện đại hơn (winner PHC 2015): argon2id kháng GPU và side-channel attacks tốt hơn, được OWASP khuyến nghị năm 2023+; dùng `argon2` package trong Node.js. Pitfall: hash password trong service layer, không trong model hook — dễ bị double-hash nếu hook chạy lại khi update field khác." },
  { id: 684, category: "Node.js", subcategory: "Authentication", level: "advanced", q: "Access token và Refresh token khác nhau như thế nào?", a: "Access token short-lived (15 phút) gửi trong mỗi request — stateless, server không lưu gì. Refresh token long-lived (7-30 ngày) lưu trong httpOnly cookie, chỉ dùng để lấy access token mới tại endpoint `/auth/refresh`. Rotation strategy: mỗi lần dùng refresh token phải issue cặp token mới và invalidate token cũ (one-time-use) — nếu token cũ bị dùng lại là dấu hiệu bị đánh cắp, revoke toàn bộ session. Token blacklisting: lưu revoked JTI (JWT ID) trong Redis với TTL bằng thời gian còn lại của token — kiểm tra blacklist trong auth middleware. Sliding sessions: mỗi request hợp lệ extend session — issue refresh token mới nếu còn < 1 ngày. Security: lưu hash của refresh token trong DB, không plain text — nếu DB leak thì token vô dụng. Pitfall: không implement rotation → stolen refresh token dùng mãi đến hết hạn; không lưu vào httpOnly cookie → XSS đánh cắp được." },
  { id: 685, category: "Node.js", subcategory: "Performance", level: "advanced", q: "Clustering trong Node.js là gì? Tại sao cần thiết?", a: "Node.js single-threaded chỉ dùng một CPU core — server 16-core lãng phí 15 cores. Cluster module: master process fork N worker processes (thường = số CPU cores: `os.cpus().length`), mỗi worker là Node.js process độc lập, share cùng port. Connection distribution: Linux dùng round-robin (master nhận connection rồi distribute), Windows dùng OS scheduling. IPC communication: `process.send(msg)` từ worker, `worker.on('message', handler)` ở master — dùng để share state nhỏ như worker health. Shared nothing architecture: workers không share memory, mỗi worker có heap riêng — session/cache phải dùng Redis thay vì in-memory. Sticky sessions: cần khi dùng WebSocket — load balancer phải route cùng client đến cùng worker (nginx `ip_hash`). PM2 cluster mode: `pm2 start app.js -i max` tự động quản lý cluster với zero-downtime reload (`pm2 reload app`) — reload từng worker một thay vì restart toàn bộ. Khi nào dùng cluster vs reverse proxy: cluster cho vertical scaling trên một server, Nginx/HAProxy cho horizontal scaling nhiều servers." },
  { id: 686, category: "Node.js", subcategory: "Performance", level: "advanced", q: "Worker Threads trong Node.js là gì? Khác gì với Cluster?", a: "Worker Threads chạy JS trong separate threads trong cùng process — chia sẻ memory qua SharedArrayBuffer, dùng Atomics để synchronize. Cluster tạo separate OS processes — không share memory, overhead IPC cao hơn. Worker Threads API: `const { Worker, isMainThread, parentPort, workerData } = require('worker_threads')`. Main thread: `new Worker('./worker.js', { workerData: { input } })`, lắng nghe `worker.on('message', result => ...)`. Worker thread: `parentPort.postMessage(result)`. Message passing qua `postMessage()` — data được structured clone (deep copy) trừ khi transfer ownership với Transferable (ArrayBuffer). SharedArrayBuffer + Atomics: chia sẻ raw memory không cần copy — dùng cho real-time collaboration, game state. Use cases thực tế: image resizing (sharp library), PDF generation, crypto operations, ML inference, large JSON parsing. Pitfall: Worker Threads không tăng tốc I/O-bound tasks — Node.js event loop đã xử lý I/O async; chỉ dùng cho CPU-bound tasks chiếm event loop > 10ms." },
  { id: 687, category: "Node.js", subcategory: "Architecture", level: "advanced", q: "Microservices architecture với Node.js: ưu và nhược điểm?", a: "Communication patterns: sync REST/gRPC (request-response, coupling chặt hơn, dễ debug) vs async message queue — RabbitMQ/Kafka (loose coupling, resilient, nhưng eventual consistency). Service discovery: mỗi service đăng ký địa chỉ vào registry (Consul, etcd), services khác lookup thay vì hardcode URL — cần thiết khi services scale up/down động. API Gateway: single entry point cho clients, xử lý auth/rate-limiting/routing, tránh clients phải biết topology nội bộ (Kong, AWS API Gateway). Saga pattern cho distributed transactions: Choreography (services emit events, services khác react — loose coupling) vs Orchestration (central saga orchestrator điều phối — dễ debug hơn). Event sourcing: lưu toàn bộ events thay vì current state — audit log hoàn chỉnh, có thể replay để rebuild state. Nhược điểm thực tế: distributed tracing cần setup (Jaeger, Zipkin), network latency thay vì function call, integration tests phức tạp hơn, debugging khó hơn. Pitfall: microservices quá sớm — monolith trước, tách khi có bounded contexts rõ ràng và team đủ lớn." },
  { id: 688, category: "Node.js", subcategory: "Caching", level: "intermediate", q: "Caching trong Node.js API: các chiến lược phổ biến?", a: "Cache-aside (lazy loading): check cache → miss → fetch DB → write cache → return — pattern phổ biến nhất, code: `const cached = await redis.get(key); if (cached) return JSON.parse(cached); const data = await db.query(...); await redis.setex(key, 300, JSON.stringify(data)); return data`. Write-through: write cache + DB đồng thời — data luôn fresh nhưng write chậm hơn. Write-behind: write cache trước, async flush xuống DB — write rất nhanh nhưng risk mất data nếu cache crash. Cache invalidation strategies: TTL (đơn giản, chấp nhận stale data), event-based (on update → delete cache key), versioned keys (`user:${id}:v${version}`). TTL chọn sao cho: data thay đổi ít → TTL dài (1 giờ), data thay đổi nhiều → TTL ngắn (30s) hoặc invalidate on write. Cache warming: pre-populate cache khi startup để tránh cold start — gọi `warmCache()` sau khi server start. Thundering herd problem: nhiều requests đồng thời hit expired key → tất cả cùng query DB → DB quá tải. Fix: probabilistic early expiration (renew cache trước khi hết hạn), mutex lock (chỉ 1 request query DB, còn lại chờ), stale-while-revalidate. Pitfall: cache key collision — luôn dùng namespace `${service}:${resource}:${id}`." },
  { id: 689, category: "Node.js", subcategory: "Error Handling", level: "intermediate", q: "Cách xử lý unhandled Promise rejections trong Node.js?", a: "Node.js 14 trở về trước: unhandled rejection chỉ print warning, process tiếp tục — silent failure nguy hiểm. Node.js 15+: mặc định crash process với exit code 1 — breaking change. Hierarchy xử lý đúng: (1) try/catch trong async functions là chính, (2) `.catch()` chain cho fire-and-forget promises, (3) `process.on('unhandledRejection', (reason) => { logger.error('Unhandled rejection', reason); gracefulShutdown(1); })` là safety net cuối — không phải cơ chế chính. `process.on('uncaughtException', (err) => { logger.error(err); gracefulShutdown(1); })` cho sync throws. Monitoring: gửi đến Sentry trước khi shutdown — `Sentry.captureException(reason); await Sentry.flush(2000)`. Graceful shutdown: stop accepting requests, wait for in-flight, close DB, exit. Dùng ESLint rule `@typescript-eslint/no-floating-promises` để catch missing awaits lúc compile time — tốt hơn runtime detection." },
  { id: 690, category: "Node.js", subcategory: "File System", level: "intermediate", q: "fs module trong Node.js: fs.readFile vs fs.createReadStream khác nhau như thế nào?", a: "fs.readFile() load toàn bộ file vào RAM trước khi callback — file 100MB chiếm ít nhất 100MB heap; 100 concurrent requests = 10GB RAM, dễ OOM crash. fs.createReadStream() đọc theo chunks (default highWaterMark 64KB) — file 100MB chỉ dùng ~64KB RAM bất kể bao nhiêu requests đồng thời. Serve file thực tế: `fs.createReadStream(filePath).pipe(res)` stream thẳng đến TCP buffer không qua RAM. pipeline() API (Node 10+) tốt hơn pipe(): `await pipeline(fs.createReadStream(path), res)` — tự cleanup khi error, tránh memory leak khi client disconnect. Backpressure tự động: pipe/pipeline dừng đọc file khi client chậm, tiếp tục khi TCP buffer drain. Khi nào dùng readFile: config files < 1MB đọc lúc startup, JSON parse một lần. Khi nào dùng createReadStream: file download, log streaming, CSV export, bất kỳ file > vài MB." },
  { id: 691, category: "Node.js", subcategory: "File System", level: "intermediate", q: "Sự khác biệt giữa fs.readFile và fs.readFileSync là gì?", a: "readFileSync blocking — giữ event loop hoàn toàn cho đến khi OS trả data, không xử lý request nào khác trong thời gian đó. readFile non-blocking — gửi I/O request đến libuv thread pool, event loop tự do xử lý requests khác. Impact thực tế: readFileSync đọc file 50ms trên server 1000 req/s → mỗi request xếp hàng bị delay 50ms cộng dồn → latency spike hàng giây. Khi sync chấp nhận được: (1) module initialization trước `server.listen()` — `const config = JSON.parse(fs.readFileSync('config.json', 'utf8'))` chạy một lần duy nhất lúc startup, không có traffic; (2) CLI tools; (3) build scripts. Quy tắc: bất kỳ code nào chạy SAU `server.listen()` trong request path — bắt buộc dùng async. Đo blocking: `node --prof app.js` → `node --prof-process isolate-*.log` → readFileSync trong hot path hiện rõ ràng với % CPU time." },
  { id: 692, category: "Node.js", subcategory: "Environment", level: "beginner", q: "Environment variables trong Node.js: cách dùng và tại sao quan trọng?", a: "Environment variables tách config khỏi code — 12-factor app methodology: config là bất kỳ thứ gì thay đổi giữa environments (dev/staging/prod). Cấu trúc .env file: `DATABASE_URL=postgresql://...`, `JWT_SECRET=...`, `NODE_ENV=development`. dotenv: `require('dotenv').config()` load .env vào process.env, KHÔNG override existing env vars — production inject trực tiếp qua Docker/K8s/CI không cần .env file. dotenv-safe: kiểm tra required vars từ `.env.example` tại startup, throw error nếu thiếu thay vì silent undefined. Config validation với Zod: `const config = z.object({ DATABASE_URL: z.string().url(), PORT: z.coerce.number().default(3000), JWT_SECRET: z.string().min(32) }).parse(process.env)` — fail fast với error rõ ràng. Tạo `config.ts` module export typed config thay vì access `process.env` trực tiếp khắp nơi — dễ test và type-safe. Pitfall: `process.env.PORT` luôn là string, cần coerce sang number; commit .env vào git — dùng `.gitignore` và `.env.example` làm template." },
  { id: 693, category: "Node.js", subcategory: "Performance", level: "advanced", q: "Event loop blocking trong Node.js là gì? Làm thế nào để tránh?", a: "Event loop blocking: synchronous code chiếm CPU lâu khiến event loop không xử lý được I/O callbacks, timers, requests khác. Ví dụ thực tế: (1) `JSON.parse(fs.readFileSync('huge.json'))` — 200MB JSON parse tốn ~2s block hoàn toàn; (2) regex backtracking — `/^(a+)+$/.test('aaaaaaaaab')` chạy exponential time với input độc hại (ReDoS); (3) crypto sync — `crypto.pbkdf2Sync()` trong request handler; (4) nested loops O(n²) trên large arrays. Đo blocking: `node --prof app.js` tạo V8 profile; `clinic doctor -- node app.js` từ clinic.js package hiển thị event loop lag rõ ràng; `perf_hooks` API đo `eventLoopUtilization()`. Fix: chia nhỏ task với `setImmediate()` để yield event loop giữa chunks; offload sang Worker Threads cho CPU-intensive; dùng streaming thay vì load toàn bộ vào memory; `safe-regex` package detect ReDoS vulnerable patterns. Threshold: bất kỳ synchronous operation > 10ms trong request handler là vấn đề cần xem xét." },
  { id: 694, category: "Node.js", subcategory: "Streams", level: "advanced", q: "Backpressure trong Node.js streams là gì? Tại sao quan trọng?", a: "Backpressure: Readable produce data nhanh hơn Writable consume — nếu không xử lý, data buffer trong memory vô hạn cho đến khi OOM crash. highWaterMark: ngưỡng buffer size (default 16KB cho object streams, 16384 bytes cho byte streams) — khi buffer vượt ngưỡng, stream signals slow down. Cơ chế manual: `writable.write(chunk)` trả về `false` khi internal buffer đầy → stop reading; lắng nghe `writable.on('drain', resume)` để tiếp tục. Ví dụ file upload: client upload 1GB/s, DB write chỉ 100MB/s — không có backpressure thì 900MB/s tích lũy trong RAM. `pipe()` tự xử lý nhưng không handle errors tốt. `pipeline()` API (stream/promises): `await pipeline(req, transform, fs.createWriteStream(dest))` — tự xử lý backpressure VÀ cleanup tất cả streams khi error/complete, không leak. Transform streams: implement `_transform(chunk, enc, callback)`, gọi `callback()` khi sẵn sàng nhận chunk tiếp theo — tự nhiên tạo backpressure. Pitfall: `.on('data', handler)` puts stream in flowing mode bỏ qua backpressure — dùng async iteration `for await (const chunk of readable)` thay thế." },
  { id: 695, category: "Node.js", subcategory: "Debugging", level: "intermediate", q: "Cách debug Node.js application?", a: "Breakpoint debugging: `node --inspect app.js` expose debugger tại port 9229; mở `chrome://inspect` → attach. `--inspect-brk` dừng tại dòng đầu tiên — dùng khi debug initialization code. VS Code launch.json: `{ type: 'node', request: 'launch', program: '${workspaceFolder}/src/index.ts', runtimeArgs: ['-r', 'ts-node/register'] }` — breakpoints trong TypeScript với source maps. Memory profiling: Chrome DevTools → Memory tab → Heap Snapshot → so sánh 2 snapshots tìm memory leak; retained size cho thấy objects đang giữ gì. CPU profiling: DevTools → Performance tab → Record → stress → flame graph, tìm hot functions. `clinic doctor -- node app.js`: tự phát hiện event loop delay, I/O issues, memory problems, generate HTML report. `0x app.js`: interactive CPU flamegraph, hiển thị call stacks chiếm CPU. Source maps: `sourceMap: true` trong tsconfig để debugger map JS → TS. Pitfall: `--inspect` trong production mà expose port ra internet → remote code execution vulnerability; bind tới localhost only." },
  { id: 696, category: "Node.js", subcategory: "Architecture", level: "advanced", q: "Event Emitter trong Node.js là gì? Cách dùng?", a: "EventEmitter implement Observer/pub-sub pattern — backbone của Node.js internals (streams, http.Server, process đều extend EventEmitter). API cơ bản: `.on('event', listener)` đăng ký persistent listener, `.once('event', listener)` tự remove sau lần emit đầu tiên, `.emit('event', ...args)` kích hoạt đồng bộ tất cả listeners, `.off('event', listener)` hoặc `.removeListener()` để unsubscribe. Memory leak warning: Node.js warn khi > 10 listeners trên cùng event (`MaxListenersExceededWarning`) — dùng `emitter.setMaxListeners(20)` nếu cố ý, hoặc fix leak. Thường quên `.removeListener()` trong component unmount/cleanup → listeners tích lũy. Error convention: event tên `'error'` đặc biệt — nếu emit `'error'` mà không có listener thì throw uncaughtException crash process. Practical patterns: `class OrderService extends EventEmitter { async createOrder(data) { const order = await db.save(data); this.emit('order:created', order); } }` — services khác lắng nghe event thay vì coupling trực tiếp. `.once()` dùng cho one-time setup: `server.once('listening', () => console.log('ready'))`. Async listeners: EventEmitter không await async listeners — unhandled promise trong listener → silent failure." },
  { id: 697, category: "Node.js", subcategory: "Security", level: "intermediate", q: "Các lỗ hổng bảo mật phổ biến trong Node.js API và cách phòng tránh?", a: "SQL injection (OWASP A03): `db.query('SELECT * FROM users WHERE id = ' + req.params.id)` → attacker truyền `1 OR 1=1` dump toàn bộ DB. Fix: parameterized queries `db.query('SELECT * FROM users WHERE id = $1', [id])` hoặc ORM. NoSQL injection MongoDB: `{ username: req.body.username }` với body `{ username: { $gt: '' } }` bypass auth. Fix: validate với Zod/Joi trước khi query. XSS (A07): lưu `<script>alert(1)</script>` vào DB rồi render unescaped → steal cookies. Fix: escape output, CSP headers, DOMPurify. ReDoS: `/(a+)+/.test(userInput)` với input `'aaaaaaaaab'` → exponential backtracking block event loop hàng giây. Fix: `safe-regex` package kiểm tra pattern, timeout regex execution. Directory traversal: `fs.readFile('/uploads/' + req.query.file)` với `file=../../etc/passwd`. Fix: `path.resolve()` + verify kết quả starts with allowed directory. Prototype pollution: `obj[userKey] = userValue` với key `__proto__` corrupt Object prototype. Fix: `Object.create(null)` cho plain objects, validate keys. Dependency vulnerabilities: `npm audit` + `npm audit fix`, `snyk` cho CI/CD. Helmet.js: một lệnh `app.use(helmet())` set 11 security headers (X-Frame-Options, HSTS, CSP cơ bản, nosniff)." },
  { id: 698, category: "Node.js", subcategory: "Architecture", level: "advanced", q: "Graceful shutdown trong Node.js là gì? Tại sao quan trọng?", a: "Graceful shutdown đảm bảo zero data loss và zero error responses khi deploy/restart. Implementation pattern: `process.on('SIGTERM', async () => { server.close(async () => { await db.disconnect(); await redis.quit(); process.exit(0); }); })` — `server.close()` stop accepting new connections nhưng chờ existing connections finish. Connection draining: set timeout 30s cho in-flight requests — nếu quá timeout force close. Health check: Kubernetes gửi SIGTERM sau khi remove pod khỏi load balancer (readiness probe fails) → khoảng trống 5-10s để LB drain traffic trước khi process nhận SIGTERM — config `terminationGracePeriodSeconds: 30` trong K8s. Kubernetes flow: SIGTERM → preStop hook (sleep 5s để LB drain) → app nhận SIGTERM → graceful shutdown → SIGKILL nếu quá `terminationGracePeriodSeconds`. Track in-flight: `let connections = 0; app.use((req, res, next) => { connections++; res.on('finish', () => connections--); next(); })` — chờ connections về 0 hoặc timeout. Pitfall: không handle SIGINT (Ctrl+C local dev) — thêm cả `process.on('SIGINT', handler)`. Docker `STOPSIGNAL SIGTERM` + `ENTRYPOINT` dùng exec form (không shell) để process nhận signal trực tiếp." },
  { id: 699, category: "Node.js", subcategory: "Testing", level: "intermediate", q: "Cách viết unit tests cho Node.js API với Jest?", a: "Test pyramid cho Node.js API: unit tests (service/utils logic) → integration tests (controller + real DB) → e2e tests (full HTTP). Controller testing với supertest: `const res = await request(app).post('/users').send({ email: 'test@test.com' }); expect(res.status).toBe(201)` — không cần start server, supertest inject request trực tiếp. Service testing: mock DB layer với `jest.mock('../db')` → `(db.findUser as jest.Mock).mockResolvedValue({ id: 1 })` — test business logic độc lập với DB. Middleware testing: gọi middleware với mock `req`, `res`, `next` objects — verify `next()` được gọi hay `res.status()` được set. Integration tests: dùng test DB riêng (`TEST_DATABASE_URL`), chạy migrations trước test suite, truncate tables giữa tests (`afterEach`). Mock strategies: `jest.mock()` cho modules, `jest.spyOn()` cho methods, `jest.useFakeTimers()` cho time-dependent code. Test database setup: `globalSetup` chạy migration một lần, `beforeEach` truncate data, `afterAll` disconnect. Coverage: `jest --coverage` + `coverageThreshold: { global: { lines: 80 } }` enforce minimum. Pitfall: không isolate tests → test order dependent failures; mock tất cả external calls (HTTP, email) để tests deterministic." },
  { id: 700, category: "Node.js", subcategory: "Performance", level: "advanced", q: "PM2 là gì? Tại sao dùng PM2 trong production?", a: "PM2 là production process manager cho Node.js — giải quyết auto-restart, clustering, logging, monitoring trong một tool. Ecosystem config (`ecosystem.config.js`): `module.exports = { apps: [{ name: 'api', script: 'dist/index.js', instances: 'max', exec_mode: 'cluster', env: { NODE_ENV: 'production', PORT: 3000 }, max_memory_restart: '500M', error_file: 'logs/err.log', out_file: 'logs/out.log' }] }` — `pm2 start ecosystem.config.js`. Zero-downtime reload: `pm2 reload api` restart từng worker một (rolling restart), không như `pm2 restart` kill tất cả cùng lúc — dùng reload cho deploys. Monitoring dashboard: `pm2 monit` real-time CPU/RAM per process; `pm2 status` overview tất cả processes. Log management: `pm2 logs api --lines 100` xem logs; `pm2 flush` clear logs; tích hợp với logrotate để tránh disk full. Startup scripts: `pm2 startup` generate systemd/init script để PM2 tự start khi server reboot; `pm2 save` lưu current process list. `max_memory_restart`: tự restart process khi vượt ngưỡng RAM — safety net cho memory leaks. Pitfall: PM2 cluster mode dùng shared nothing — sessions/cache phải ở Redis; `pm2 reload` không graceful nếu app không handle SIGINT/SIGTERM." },

  // === DATABASE: SQL Cơ Bản (701-715) ===
  { id: 701, category: "Database", subcategory: "SQL Cơ Bản", level: "beginner", q: "SQL là gì? Các loại SQL commands chính?", a: "SQL (Structured Query Language) là ngôn ngữ chuẩn để tương tác với cơ sở dữ liệu quan hệ như PostgreSQL, MySQL, SQLite. Được chia thành 4 nhóm lệnh: DDL (Data Definition Language) định nghĩa cấu trúc — `CREATE TABLE`, `ALTER TABLE`, `DROP TABLE`; DML (Data Manipulation Language) thao tác dữ liệu — `SELECT`, `INSERT`, `UPDATE`, `DELETE`; DCL (Data Control Language) phân quyền — `GRANT SELECT ON users TO readonly_user`; TCL (Transaction Control Language) quản lý giao dịch — `BEGIN`, `COMMIT`, `ROLLBACK`. Trong thực tế hàng ngày, dev dùng DML 90% thời gian, DDL khi migration, còn DCL và TCL do DBA hoặc DevOps quản lý. Hiểu phân loại này giúp debug lỗi quyền truy cập và thiết kế migration scripts đúng cách." },
  { id: 702, category: "Database", subcategory: "SQL Cơ Bản", level: "beginner", q: "Câu lệnh SELECT cơ bản trong SQL như thế nào?", a: "Thứ tự thực thi SQL (quan trọng để hiểu tại sao không dùng alias trong WHERE): FROM → JOIN → WHERE → GROUP BY → HAVING → SELECT → DISTINCT → ORDER BY → LIMIT/OFFSET. Câu query thực tế: `SELECT u.name, COUNT(o.id) AS order_count FROM users u LEFT JOIN orders o ON u.id = o.user_id WHERE u.created_at > '2024-01-01' GROUP BY u.id, u.name HAVING COUNT(o.id) > 5 ORDER BY order_count DESC LIMIT 20`. Aliasing: `SELECT price * 0.9 AS discounted_price` — alias trong SELECT không dùng được trong WHERE (chưa được tính), nhưng dùng được trong ORDER BY (PostgreSQL cho phép). DISTINCT: `SELECT DISTINCT city FROM users` loại trùng lặp — có sorting overhead, dùng GROUP BY khi cần performance tốt hơn. SELECT *: không dùng production — lấy data thừa, break khi thêm column, không dùng được covering index. Pitfall: LIMIT không có ORDER BY → kết quả non-deterministic, mỗi query trả về rows khác nhau." },
  { id: 703, category: "Database", subcategory: "SQL Cơ Bản", level: "beginner", q: "INSERT, UPDATE, DELETE trong SQL hoạt động như thế nào?", a: "Bulk INSERT: `INSERT INTO users (name, email) VALUES ('A', 'a@x.com'), ('B', 'b@x.com'), ('C', 'c@x.com')` — một round-trip thay vì N trips, nhanh hơn 10-100x với lượng lớn. RETURNING clause (PostgreSQL): `INSERT INTO users (name) VALUES ('Dinh') RETURNING id, created_at` — lấy generated values ngay không cần query thêm. ON CONFLICT (upsert): `INSERT INTO settings (user_id, key, value) VALUES (1, 'theme', 'dark') ON CONFLICT (user_id, key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW()` — atomic upsert không race condition. Safe UPDATE: luôn chạy SELECT với WHERE condition trước để verify rows affected; `UPDATE users SET role = 'admin' WHERE id = 5 RETURNING *` confirm kết quả. Safe DELETE: `BEGIN; DELETE FROM users WHERE created_at < '2020-01-01'; SELECT COUNT(*); ROLLBACK;` — dry run trong transaction để kiểm tra trước khi COMMIT. Pitfall: `UPDATE users SET active = false` không có WHERE → update toàn bộ bảng, không thể undo nếu không có backup; dùng `sql_safe_updates` mode hoặc review trước khi execute." },
  { id: 704, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "Các loại JOIN trong SQL: INNER JOIN, LEFT JOIN, RIGHT JOIN, FULL OUTER JOIN khác nhau như thế nào?", a: "Visualize bằng Venn diagrams: INNER JOIN = phần giao (chỉ rows có match cả 2 bảng); LEFT JOIN = toàn bộ vòng trái + phần giao (right side NULL nếu không match); RIGHT JOIN = ngược lại (hiếm dùng, viết lại thành LEFT JOIN cho dễ đọc); FULL OUTER JOIN = cả 2 vòng (NULL ở bên không có match); CROSS JOIN = Cartesian product M×N rows (nguy hiểm với bảng lớn). Use case thực tế: INNER JOIN khi chỉ muốn users CÓ orders; LEFT JOIN khi muốn TẤT CẢ users kể cả không có orders (NULL check để tìm users chưa mua: `WHERE o.id IS NULL`). Performance: JOIN trên indexed foreign keys rất nhanh; JOIN trên non-indexed columns → Seq Scan + Hash Join chậm. Interview trap: `SELECT * FROM A LEFT JOIN B ON A.id = B.a_id WHERE B.col = 'x'` — WHERE filter trên B column biến LEFT JOIN thành INNER JOIN vì NULL rows bị lọc ra; phải dùng `AND B.col = 'x'` trong ON clause để giữ NULL rows. Self JOIN: `SELECT e.name, m.name as manager FROM employees e LEFT JOIN employees m ON e.manager_id = m.id` — join bảng với chính nó để resolve hierarchical data." },
  { id: 705, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "WHERE và HAVING trong SQL khác nhau như thế nào?", a: "Execution order là chìa khóa: WHERE chạy TRƯỚC GROUP BY (lọc individual rows), HAVING chạy SAU (lọc groups). WHERE không dùng được aggregate vì aggregation chưa xảy ra — `WHERE COUNT(*) > 5` là syntax error. HAVING dùng được aggregate: `HAVING COUNT(*) > 5`, `HAVING SUM(amount) > 1000`. Ví dụ rõ ràng: `SELECT dept, COUNT(*) FROM employees WHERE salary > 50000 GROUP BY dept HAVING COUNT(*) > 3` — WHERE loại employees lương thấp trước, GROUP BY nhóm, HAVING giữ dept có > 3 employees lương cao. Performance: WHERE lọc trước GROUP BY → ít rows phải aggregate → nhanh hơn đáng kể với bảng lớn; luôn đẩy filters không cần aggregate vào WHERE. Sai lầm phổ biến: `HAVING dept = 'Engineering'` thay vì `WHERE dept = 'Engineering'` — hoạt động nhưng scan + group toàn bộ bảng rồi mới lọc; HAVING không dùng được index trên dept." },
  { id: 706, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "GROUP BY trong SQL dùng để làm gì? Cho ví dụ?", a: "GROUP BY nhóm rows có cùng giá trị thành groups, mỗi group trả về một row. Quy tắc bắt buộc: mọi column trong SELECT phải hoặc là trong GROUP BY hoặc là aggregate function — `SELECT dept, name, COUNT(*) GROUP BY dept` lỗi vì `name` không trong GROUP BY và không phải aggregate (PostgreSQL strict, MySQL lenient). Ví dụ thực tế: `SELECT category, COUNT(*) as total, AVG(price) as avg_price, MAX(price) as max_price FROM products GROUP BY category ORDER BY total DESC`. Group by nhiều columns: `GROUP BY year, month` tạo group riêng cho mỗi cặp year-month. ROLLUP cho subtotals: `GROUP BY ROLLUP(dept, team)` tự động thêm rows tổng hợp cho mỗi dept và grand total — dùng cho báo cáo. CUBE: tất cả combinations của dimensions — `GROUP BY CUBE(dept, year)` tạo subtotals cho dept, year, và cả hai. GROUPING SETS: chỉ định chính xác những groupings cần: `GROUP BY GROUPING SETS ((dept), (year), ())` — flexible hơn ROLLUP/CUBE. Pitfall: GROUP BY column không có index → full scan + sort — cân nhắc thêm index." },
  { id: 707, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "Aggregate functions trong SQL là gì? Các hàm phổ biến?", a: "Aggregate functions gộp nhiều rows thành một giá trị. NULL behavior quan trọng: COUNT(*) đếm tất cả rows kể cả NULL; COUNT(col) bỏ qua NULL — `COUNT(phone)` cho biết bao nhiêu users có số điện thoại; SUM/AVG/MAX/MIN đều bỏ qua NULL. DISTINCT trong aggregates: `COUNT(DISTINCT city)` đếm số cities duy nhất, `SUM(DISTINCT amount)` tổng các giá trị không trùng. STRING_AGG (PostgreSQL): `STRING_AGG(tag, ', ' ORDER BY tag)` nối values thành string trong group — `SELECT post_id, STRING_AGG(tag_name, ',') FROM post_tags GROUP BY post_id`. ARRAY_AGG: `ARRAY_AGG(email ORDER BY created_at)` tạo array từ group values. Conditional aggregation với FILTER: `COUNT(*) FILTER (WHERE status = 'active') AS active_count, COUNT(*) FILTER (WHERE status = 'inactive') AS inactive_count` — pivot-style aggregation trong một query thay vì nhiều subqueries. PERCENTILE: `PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY salary)` tính median — không bị ảnh hưởng bởi outliers như AVG." },
  { id: 708, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "Index trong SQL là gì? Tại sao cần thiết?", a: "B-tree index: cấu trúc cây cân bằng, mỗi node chứa sorted keys và pointers — tìm kiếm O(log n) thay vì O(n) full scan. Bảng 10 triệu rows: full scan ~10s, B-tree index ~1ms. Covering index: index chứa TẤT CẢ columns cần cho query → database chỉ đọc index, không cần đọc table (Index Only Scan) — `CREATE INDEX idx_users_email_name ON users(email, name)` cover `SELECT name FROM users WHERE email = ?`. Partial index: index chỉ trên subset rows — `CREATE INDEX idx_active_users ON users(email) WHERE deleted_at IS NULL` nhỏ hơn, nhanh hơn full index nếu query luôn có `WHERE deleted_at IS NULL`. Khi KHÔNG nên index: bảng < 1000 rows (full scan nhanh hơn), columns ít cardinality (boolean, status với 2-3 values), bảng write-heavy (mỗi write phải update tất cả indexes). Index maintenance: REINDEX để rebuild index bị bloated; `pg_stat_user_indexes` xem index usage — drop indexes không được dùng. Pitfall: function trên indexed column bypass index — `WHERE LOWER(email) = ?` không dùng index trên `email`; tạo functional index `CREATE INDEX ON users(LOWER(email))` thay thế." },
  { id: 709, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "Subquery trong SQL là gì? Khi nào dùng subquery vs JOIN?", a: "Uncorrelated subquery chạy một lần, kết quả dùng cho outer query: `SELECT * FROM products WHERE price > (SELECT AVG(price) FROM products)`. Correlated subquery tham chiếu outer query và chạy lại cho MỖI ROW của outer query — O(n²) complexity, rất chậm với bảng lớn: `SELECT * FROM employees e WHERE salary > (SELECT AVG(salary) FROM employees WHERE dept = e.dept)`. EXISTS vs IN: `EXISTS (SELECT 1 FROM orders WHERE user_id = u.id)` dừng ngay khi tìm thấy match đầu tiên (short-circuit), tốt cho large subsets; `IN (SELECT user_id FROM orders)` load toàn bộ list vào memory — `NOT IN` với NULL trong subquery trả về empty result set (NULL pitfall). Scalar subquery trong SELECT: `SELECT name, (SELECT COUNT(*) FROM orders WHERE user_id = u.id) AS order_count FROM users u` — tương đương LEFT JOIN nhưng thường chậm hơn vì chạy N lần. Lateral join (PostgreSQL): `FROM users u, LATERAL (SELECT * FROM orders WHERE user_id = u.id ORDER BY created_at DESC LIMIT 3) o` — như correlated subquery nhưng có thể reference multiple columns và return multiple rows, optimizer xử lý tốt hơn. Khi subquery tốt hơn JOIN: EXISTS checks, khi JOIN tạo fan-out (duplicate rows do one-to-many), scalar aggregates." },
  { id: 710, category: "Database", subcategory: "SQL Cơ Bản", level: "advanced", q: "Window functions trong SQL là gì? Ví dụ về ROW_NUMBER, RANK?", a: "Window functions tính toán trên window (tập rows liên quan) nhưng KHÔNG collapse rows như GROUP BY — mỗi row giữ nguyên và nhận thêm computed value. OVER clause: `PARTITION BY` chia thành sub-windows (như GROUP BY nhưng không collapse), `ORDER BY` xác định thứ tự trong window. ROW_NUMBER(): số thứ tự duy nhất, không ties. RANK(): ties được cùng số, bỏ số sau ties (1,1,3). DENSE_RANK(): ties cùng số, không bỏ số (1,1,2). LAG/LEAD: `LAG(salary, 1) OVER (ORDER BY hire_date)` lấy giá trị row trước — tính month-over-month growth. Running totals: `SUM(amount) OVER (PARTITION BY user_id ORDER BY created_at ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW)` — cumulative sum. Frame specification: `ROWS BETWEEN 2 PRECEDING AND CURRENT ROW` (3-row moving average), `RANGE BETWEEN INTERVAL '7 days' PRECEDING AND CURRENT ROW` (rolling 7-day window). FIRST_VALUE/LAST_VALUE: giá trị đầu/cuối của window. Practical use case: `SELECT *, ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY created_at DESC) AS rn FROM orders` → `WHERE rn = 1` lấy order mới nhất của mỗi user — pattern deduplication phổ biến." },
  { id: 711, category: "Database", subcategory: "SQL Cơ Bản", level: "advanced", q: "EXPLAIN và EXPLAIN ANALYZE trong PostgreSQL dùng để làm gì?", a: "EXPLAIN hiển thị execution plan mà planner dự định dùng mà không chạy query. EXPLAIN ANALYZE thực sự chạy query và so sánh estimated vs actual — dùng trên production cẩn thận với DML. `EXPLAIN (ANALYZE, BUFFERS, FORMAT JSON)` cho thêm buffer hit/miss info. Đọc plan từ trong ra ngoài, từ dưới lên trên — node trong cùng chạy trước. Cost: `(startup_cost..total_cost)` là planner estimate, không phải milliseconds — dùng để so sánh tương đối. Actual time: `(actual time=0.043..1.2 rows=100)`. Plan nodes quan trọng: Seq Scan — đọc toàn bộ table, tốt cho large % of rows hoặc small tables; Index Scan — dùng index rồi fetch table rows (random I/O); Index Only Scan — chỉ đọc index, không cần table (covering index, rất nhanh); Bitmap Index Scan + Bitmap Heap Scan — batch random reads thành sequential, tốt cho medium % of rows; Hash Join — build hash table từ smaller relation, probe với larger; Nested Loop — tốt khi outer là nhỏ và inner có index; Merge Join — tốt khi cả hai đã sorted. Red flags: estimated rows vs actual rows chênh lệch lớn (stale statistics → `ANALYZE table`); Seq Scan trên bảng lớn trong WHERE condition → thiếu index; high Buffers read → data không trong cache." },
  { id: 712, category: "Database", subcategory: "SQL Cơ Bản", level: "beginner", q: "NULL trong SQL là gì? Cách kiểm tra NULL?", a: "NULL trong SQL đại diện cho giá trị không xác định hoặc thiếu — hoàn toàn khác với số 0, chuỗi rỗng `''`, hay `false`. Đây là nguồn gốc của nhiều bug khó phát hiện. Kiểm tra NULL phải dùng `IS NULL` / `IS NOT NULL`, tuyệt đối không dùng `= NULL` vì `NULL = NULL` trả về NULL (không phải TRUE), khiến WHERE clause không match gì cả. Aggregate functions như `SUM()`, `AVG()`, `MAX()` tự động bỏ qua NULL — `AVG(score)` chỉ tính trung bình các hàng có giá trị, không tính NULL là 0. Xử lý NULL khi select: `COALESCE(phone, 'N/A')` trả về giá trị đầu tiên không NULL. Pitfall trong JOIN: nếu foreign key có NULL, `INNER JOIN` sẽ loại bỏ hàng đó — dùng `LEFT JOIN` và kiểm tra NULL trong kết quả." },
  { id: 713, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "UNION và UNION ALL trong SQL khác nhau như thế nào?", a: "UNION deduplicate bằng cách sort + compare toàn bộ result set — O(n log n) overhead, chậm với large results. UNION ALL giữ tất cả rows kể cả duplicates, không sort — luôn nhanh hơn, dùng khi biết không có duplicates hoặc duplicates là intentional. Column compatibility: cùng số columns và compatible (không nhất thiết identical) types — `SELECT id, name FROM users UNION SELECT order_id, product_name FROM orders` hợp lệ nếu types compatible. Column names lấy từ SELECT đầu tiên. ORDER BY chỉ được đặt ở cuối toàn bộ UNION, không được đặt trong từng SELECT — `(SELECT ... ORDER BY x) UNION (SELECT ...)` là error trong nhiều databases. INTERSECT: rows xuất hiện trong CẢ HAI queries — `SELECT user_id FROM premium_users INTERSECT SELECT user_id FROM active_users`. EXCEPT (MINUS trong Oracle): rows trong query đầu nhưng không có trong query thứ hai — `SELECT email FROM all_users EXCEPT SELECT email FROM unsubscribed`. Practical use case: `SELECT 'income' as type, amount FROM income UNION ALL SELECT 'expense', -amount FROM expenses ORDER BY date` — combine two different tables for unified report." },
  { id: 714, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "CTEs (Common Table Expressions) trong SQL là gì? Lợi ích?", a: "CTE (WITH clause) là named temporary result set tồn tại trong scope của query — `WITH active_users AS (SELECT * FROM users WHERE deleted_at IS NULL), premium AS (SELECT user_id FROM subscriptions WHERE plan = 'premium') SELECT u.* FROM active_users u JOIN premium p ON u.id = p.user_id`. Lợi ích: dễ đọc hơn nested subqueries, có thể reference nhiều lần trong query chính, hỗ trợ chaining CTEs. Materialization behavior (PostgreSQL): mặc định CTEs được materialized (tính một lần, lưu temp) — optimizer không thể push predicates vào CTE, đôi khi chậm hơn subquery; thêm `NOT MATERIALIZED` để optimizer inline: `WITH cte AS NOT MATERIALIZED (...)`. Recursive CTE — org hierarchy example: `WITH RECURSIVE org AS (SELECT id, name, manager_id, 0 AS depth FROM employees WHERE manager_id IS NULL UNION ALL SELECT e.id, e.name, e.manager_id, o.depth + 1 FROM employees e JOIN org o ON e.manager_id = o.id) SELECT * FROM org ORDER BY depth` — tìm toàn bộ cây tổ chức. CTE vs subquery performance: trong PostgreSQL < 12, CTE luôn materialized (optimization fence); PostgreSQL 12+ thông minh hơn. CTE trong DML: `WITH deleted AS (DELETE FROM logs WHERE created_at < NOW() - INTERVAL '90 days' RETURNING *) INSERT INTO archive SELECT * FROM deleted` — atomic delete + archive." },
  { id: 715, category: "Database", subcategory: "SQL Cơ Bản", level: "advanced", q: "Composite index là gì? Column ordering trong index quan trọng như thế nào?", a: "Composite index trên (a, b, c): có thể dùng cho filter trên (a), (a,b), (a,b,c) — leftmost prefix rule. KHÔNG dùng được cho (b) alone, (c) alone, hay (b,c) vì b không phải leftmost prefix. Ví dụ thực tế: index (status, created_at) — query `WHERE status = 'active' ORDER BY created_at DESC` dùng được hoàn toàn; query `WHERE created_at > '2024-01-01'` không dùng được vì bỏ qua status. Index skip scan (PostgreSQL 13+): trong một số cases optimizer có thể skip leading columns nếu cardinality thấp — nhưng không nên rely on. Thứ tự cột tối ưu: (1) equality conditions trước (=), (2) range conditions sau (>, <, BETWEEN), (3) ORDER BY columns cuối — vì sau range condition, index không hỗ trợ sort nữa. Ví dụ: `WHERE user_id = ? AND status = ? AND created_at > ?` → index (user_id, status, created_at). Covering composite index: `CREATE INDEX idx_orders_user_status_date ON orders(user_id, status, created_at, amount)` cover `SELECT created_at, amount FROM orders WHERE user_id = ? AND status = ?` — Index Only Scan, không đọc table. Pitfall: index (a, b) và index (b, a) là hai indexes khác nhau phục vụ different query patterns — đừng nhầm lẫn." },

  // === DATABASE: Database Design (716-725) ===
  { id: 716, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Normalization trong database là gì? Tại sao quan trọng?", a: "Normalization loại bỏ redundancy và update anomalies. 1NF: mỗi cell atomic, không repeating groups — vi phạm: `tags: 'nodejs,react'` một cell nhiều values → tách thành bảng `user_tags(user_id, tag)`. 2NF (composite PK): mọi non-key column depend vào TOÀN BỘ PK — vi phạm: `order_items(order_id, product_id, product_name)` — product_name chỉ depend vào product_id → tách ra bảng `products`. 3NF: không có transitive dependency — vi phạm: `employees(id, dept_id, dept_name)` — dept_name depend vào dept_id chứ không phải id → tách thành bảng `departments`. Tại sao quan trọng: update anomaly — đổi tên department phải update N rows, dễ inconsistency; insert anomaly — không thể thêm department nếu chưa có employee; delete anomaly — xóa employee cuối xóa luôn thông tin dept. Thực tế: normalize đến 3NF là standard; BCNF/4NF cho edge cases; denormalize có chủ đích khi có profiling evidence." },
  { id: 717, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Primary key và Foreign key là gì? Vai trò trong database?", a: "Primary key: uniquely identifies mỗi row, NOT NULL, UNIQUE, immutable — thường là surrogate key (serial/UUID). Composite PK: `PRIMARY KEY (order_id, product_id)` trong junction tables. Foreign key: đảm bảo referential integrity — không thể insert `orders.user_id = 999` nếu users.id = 999 không tồn tại; không thể delete user nếu còn orders tham chiếu (trừ khi có CASCADE). FK constraint options: `RESTRICT` (default, block delete/update nếu có children), `CASCADE` (propagate delete/update xuống children), `SET NULL` (set FK = NULL khi parent deleted — cần FK column nullable), `SET DEFAULT` (set FK = default value), `NO ACTION` (like RESTRICT nhưng deferred). Indexing: PK tự động có index; FK column nên index để JOIN và DELETE parent nhanh — thiếu index trên FK gây full scan child table mỗi khi delete/update parent. Pitfall: FK constraints enforce data integrity nhưng có overhead mỗi INSERT/UPDATE/DELETE — một số teams disable FK trong high-throughput systems và enforce integrity ở application layer (trade-off consistency vs performance)." },
  { id: 718, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Các loại relationships trong database design là gì?", a: "One-to-One: mỗi record A liên kết đúng một record B — implement bằng UNIQUE FK: `user_profiles.user_id REFERENCES users(id) UNIQUE`. Dùng để: tách optional/sensitive data (user + user_payment_info), tách heavy columns ít dùng, polymorphic extension tables. One-to-Many: một A có nhiều B — FK trên bảng Many: `posts.user_id REFERENCES users(id)`. Phổ biến nhất trong relational design. Many-to-Many: cần junction table với composite PK hoặc surrogate PK: `enrollments(student_id, course_id, enrolled_at, grade)` — junction table nên có thêm attributes liên quan đến relationship. Self-referential: `employees.manager_id REFERENCES employees(id)` — org hierarchy, category tree, comment threads. Polymorphic associations (anti-pattern trong SQL): `comments(id, content, commentable_type, commentable_id)` — commentable_id có thể tham chiếu posts hoặc videos — không có FK constraint, hard to maintain; prefer multiple FK columns với CHECK constraint, hoặc separate junction tables per type. Pattern chọn: xác định cardinality trước, sau đó FK đặt ở phía Many, junction table cho M:N." },
  { id: 719, category: "Database", subcategory: "Database Design", level: "intermediate", q: "ER Diagram (Entity-Relationship Diagram) là gì? Các thành phần chính?", a: "ER Diagram trực quan hóa database schema trước khi implement — bắt buộc với schema phức tạp để tránh costly refactoring sau. Thành phần: Entities (bảng, hình chữ nhật), Attributes (columns, hình oval — key attribute gạch chân), Relationships (hình thoi nối entities), Cardinality notation. Crow's Foot notation phổ biến hơn Chen notation trong practice: ký hiệu trên đường relationship — `|` (one), `O` (zero), `<` hoặc `>` (many). Ví dụ đọc Crow's Foot: `users ||--o{ orders` = một user có không hoặc nhiều orders; `orders }|--|{ products` = many-to-many với mandatory participation. Tools: dbdiagram.io (code-based, version control friendly), draw.io, Lucidchart, ERDPlus. Prisma schema → auto-generate ERD với Prisma Studio. Bước thiết kế: (1) identify entities từ business requirements, (2) xác định attributes và PK cho mỗi entity, (3) xác định relationships và cardinality, (4) resolve M:N thành junction tables, (5) review với team trước khi viết DDL." },
  { id: 720, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Cascade trong foreign key constraint là gì? ON DELETE CASCADE hoạt động thế nào?", a: "Cascade propagate action từ parent xuống child table tự động. ON DELETE CASCADE: xóa user → tự xóa tất cả orders, comments, sessions — tiện nhưng nguy hiểm nếu dùng nhầm. ON DELETE SET NULL: xóa category → products.category_id = NULL, products vẫn tồn tại — dùng khi child có thể tồn tại độc lập. ON DELETE RESTRICT (default): block delete parent nếu còn child — safe nhất, application phải xử lý explicitly. ON DELETE SET DEFAULT: set FK về default value. ON UPDATE CASCADE: hữu ích khi PK có thể thay đổi (natural keys) — ít dùng với surrogate keys vì chúng immutable. Cascade chains: `A → B → C` với CASCADE, xóa A tự xóa B rồi C — có thể không nhận ra. Kiểm tra cascade impact: `SELECT * FROM information_schema.referential_constraints WHERE unique_constraint_schema = 'public'`. Khi nào dùng CASCADE: ownership relationship rõ ràng (user → sessions, order → order_items — items không có nghĩa gì nếu không có order). Khi không nên: shared resources (xóa author không nên xóa books nếu books có value độc lập). Soft delete + CASCADE: khi dùng soft delete thì CASCADE không kích hoạt — phải implement cascade logic trong application." },
  { id: 721, category: "Database", subcategory: "Database Design", level: "advanced", q: "Denormalization là gì? Khi nào nên denormalize database?", a: "Denormalization cố ý thêm redundant data để eliminate expensive JOINs — chỉ làm sau khi có profiling evidence, không phải premature optimization. Patterns thực tế: (1) Duplicate column — lưu `orders.user_email` dù đã có `users.email` → report queries không cần JOIN users; (2) Computed/cached column — `users.post_count` update khi insert/delete post thay vì `COUNT(*)` mỗi lần; (3) Materialized view — pre-computed result set refresh định kỳ, PostgreSQL `CREATE MATERIALIZED VIEW` + `REFRESH MATERIALIZED VIEW CONCURRENTLY`; (4) Flatten nested — embed thông tin address vào orders thay vì JOIN addresses (order history cần snapshot tại thời điểm mua, không phải địa chỉ hiện tại); (5) Duplicate table cho different access patterns — `user_feeds` pre-computed thay vì JOIN users+posts+follows mỗi lần load feed. Trade-off: faster reads, slower writes, storage overhead, consistency risk — mỗi write phải update redundant data; dùng DB trigger hoặc application logic để maintain consistency. Khi nào: analytics/reporting queries với phức tạp JOINs, read > 100:1 write ratio, response time requirement không đáp ứng được sau indexing." },
  { id: 722, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Surrogate key và Natural key khác nhau như thế nào?", a: "Natural key: dữ liệu thực có business meaning — email, SSN, ISBN, phone. Ưu: không cần join thêm để lấy giá trị, tự nhiên unique. Nhược: có thể thay đổi (user đổi email → phải update tất cả FKs), có thể không unique thực tế (SSN có thể duplicate do lỗi), lộ business data trong URLs. Surrogate key: ID nhân tạo không có business meaning — SERIAL/BIGSERIAL (auto-increment integer), UUID. Ưu: immutable (không bao giờ thay đổi), stable FK references, không lộ business info, đơn giản. Nhược: cần thêm UNIQUE constraint trên natural key nếu cần enforce uniqueness. Best practice: luôn dùng surrogate PK + UNIQUE constraint trên natural key nếu cần — `id BIGSERIAL PRIMARY KEY, email TEXT UNIQUE NOT NULL`. Candidate key: bất kỳ column/set nào có thể làm PK (unique + not null) — chọn một làm PK, còn lại add UNIQUE constraint." },
  { id: 723, category: "Database", subcategory: "Database Design", level: "advanced", q: "Soft delete là gì? Ưu và nhược điểm so với hard delete?", a: "Soft delete: thêm `deleted_at TIMESTAMPTZ` (preferred hơn `is_deleted BOOLEAN` vì biết thêm thời điểm xóa), không xóa record. Implementation: mọi query phải thêm `WHERE deleted_at IS NULL` — dùng partial index để tối ưu: `CREATE INDEX idx_users_active ON users(email) WHERE deleted_at IS NULL`, query chỉ scan active records. Prisma middleware tự động add filter: `prisma.$use(async (params, next) => { if (params.action === 'findMany') params.args.where = { ...params.args.where, deletedAt: null }; return next(params); })`. Ưu điểm: undelete/recovery, audit trail (ai xóa khi nào), foreign key references không bị broken, GDPR right-to-erasure cần thêm bước anonymize. Nhược điểm: tất cả queries phải nhớ filter `deleted_at IS NULL` — dễ quên gây data leak; bảng phình to theo thời gian; UNIQUE constraints vẫn enforce trên deleted records — `email UNIQUE` không cho phép re-register sau khi soft-delete → dùng partial unique index `WHERE deleted_at IS NULL`. Hard delete vẫn cần cho: GDPR erasure requests, sensitive PII, log/audit records cũ sau retention period." },
  { id: 724, category: "Database", subcategory: "Database Design", level: "intermediate", q: "UUID vs Auto-increment ID: khi nào nên dùng loại nào?", a: "Auto-increment (SERIAL/BIGSERIAL): 4/8 bytes, sequential → tốt cho B-tree index locality, dễ debug, nhưng lộ business info (competitors đoán số records), không an toàn cho distributed systems (cần central counter). UUID v4: 128-bit random, globally unique không cần coordination — perfect cho microservices/distributed; nhưng random → B-tree index fragmentation (random inserts vào random positions → page splits, bloat), 16 bytes (4x lớn hơn int), khó đọc/debug. UUID v7 (RFC 9562, 2024): time-ordered UUID — 48-bit Unix timestamp milliseconds prefix + random suffix → sequential như auto-increment nhưng globally unique. Lợi ích v7: B-tree friendly (sequential inserts → không fragmentation), globally unique, có thể sort by creation time, không lộ total count. PostgreSQL 17+ có `gen_random_uuid()` v4 built-in; v7 cần extension `pg_uuidv7` hoặc generate ở app layer (`uuidv7` npm package). CUID2/NanoID: alternatives — shorter, URL-safe, random nhưng không có timestamp prefix. Khi nào dùng UUID: public-facing IDs (URLs, APIs — tránh enumeration attacks), distributed systems, IDs cần generate ở client/app trước khi DB insert. Khi dùng BIGINT: internal tables không expose ra ngoài, performance-critical tables với many JOINs." },
  { id: 725, category: "Database", subcategory: "Database Design", level: "advanced", q: "Database migration là gì? Tại sao quan trọng trong CI/CD?", a: "Migration là versioned scripts thay đổi schema một cách có kiểm soát — mỗi migration có `up` (apply) và `down` (rollback), được track trong `_migrations` table. Tools: Prisma Migrate (`prisma migrate dev` tạo migration từ schema diff, `prisma migrate deploy` apply trong production); Knex.js migrations (manual SQL-like JS); Flyway (Java ecosystem nhưng dùng được với bất kỳ DB, file-based SQL migrations `V1__init.sql`, `V2__add_users.sql`); Liquibase (XML/YAML/SQL, enterprise features). CI/CD flow: migrations chạy tự động trước khi deploy new code — đảm bảo schema sẵn sàng cho code mới. Zero-downtime migrations: thêm column nullable trước (backward compatible) → deploy code mới đọc column mới → backfill data → add NOT NULL constraint → remove old column (multi-step, mỗi step là separate deploy). Nguy hiểm: `ALTER TABLE` với `NOT NULL` không có default trên bảng lớn → lock toàn bộ bảng trong PostgreSQL (dùng `NOT VALID` + validate separately); `DROP COLUMN` không rollback được nếu đã có data. Best practices: migrations idempotent, không bao giờ edit migration đã deploy, test down migration trước khi merge, review migrations cẩn thận như code review — schema change là irreversible." },

  // === DATABASE: NoSQL & ORM (726-740) ===
  { id: 726, category: "Database", subcategory: "NoSQL", level: "beginner", q: "NoSQL là gì? Các loại NoSQL databases phổ biến?", a: "NoSQL (Not Only SQL) là nhóm databases không dùng relational model và SQL truyền thống, được thiết kế để giải quyết những bài toán mà SQL databases xử lý kém: schema linh hoạt, horizontal scaling, và throughput cao. Bốn loại chính với use case khác nhau: Document stores (MongoDB, CouchDB) — lưu JSON documents, phù hợp content management, user profiles; Key-Value stores (Redis, DynamoDB) — truy cập O(1) theo key, phù hợp caching và session; Column-family stores (Cassandra, HBase) — write-heavy workloads, time-series data ở quy mô lớn; Graph databases (Neo4j) — dữ liệu có quan hệ phức tạp như mạng xã hội, recommendation engine. Pitfall khi chọn NoSQL: không phải lúc nào cũng tốt hơn SQL — nếu data có quan hệ rõ ràng và cần ACID transactions, PostgreSQL thường là lựa chọn tốt hơn MongoDB." },
  { id: 727, category: "Database", subcategory: "NoSQL", level: "beginner", q: "MongoDB là gì? Document-based database hoạt động như thế nào?", a: "MongoDB lưu data dưới dạng BSON (Binary JSON) — superset của JSON hỗ trợ thêm types như Date, ObjectId, Binary. Mỗi document tự động có _id field với ObjectId gồm 12 bytes: 4 bytes timestamp + 3 bytes machine ID + 2 bytes PID + 3 bytes counter, đảm bảo uniqueness mà không cần central coordinator. Thay vì tables dùng collections, thay vì rows dùng documents — mỗi document trong cùng collection có thể có schema khác nhau. Flexible schema giúp khi data structure thay đổi thường xuyên (product catalog với attributes khác nhau per category), nhưng gây hại khi cần consistency — ví dụ field age có thể lưu string '25' hay number 25 tùy document dẫn đến bugs khó phát hiện. Pitfall phổ biến: thiếu indexes dẫn đến full collection scan. MongoDB 3.6+ hỗ trợ schema validation với $jsonSchema để enforce structure khi cần." },
  { id: 728, category: "Database", subcategory: "NoSQL", level: "intermediate", q: "So sánh MongoDB và PostgreSQL: khi nào chọn cái nào?", a: "Chọn PostgreSQL khi: data có quan hệ rõ ràng, cần ACID transactions, schema cố định, complex queries với JOINs. PostgreSQL còn có JSONB type — lưu JSON với GIN index, query JSON fields nhanh — là middle ground khi cần vừa relational vừa flexible. Chọn MongoDB khi: data có cấu trúc variable/nested, cần horizontal scaling đơn giản, document-centric (content, catalog, user profiles). Performance: MongoDB nhanh hơn cho document retrieval không cần JOINs; PostgreSQL mạnh hơn cho complex aggregation nhiều bảng. Ecosystem: Mongoose (ODM) cho MongoDB vs Prisma/TypeORM cho PostgreSQL. Decision criteria thực tế: nếu team đã quen SQL, cần transactions phức tạp, hoặc data có many-to-many relations — chọn PostgreSQL; nếu cần schema evolution nhanh, team Node.js, data hierarchy sâu — chọn MongoDB. Pitfall: nhiều team chọn MongoDB vì 'flexible' rồi implement manual joins trong code — tệ hơn cả SQL." },
  { id: 729, category: "Database", subcategory: "ORM", level: "intermediate", q: "ORM (Object-Relational Mapper) là gì? Lợi ích và nhược điểm?", a: "ORM là layer ánh xạ database tables thành objects trong code, cho phép thao tác database bằng programming language thay vì SQL. Hai patterns chính: Active Record (model tự chứa DB logic, ví dụ Rails, Sequelize) và Data Mapper (tách domain object khỏi DB logic, ví dụ TypeORM DataMapper mode, Prisma). Lợi ích: type-safety, migration management (version-controlled schema changes), database abstraction (switch DB dễ hơn), boilerplate reduction. Nhược điểm: abstraction leaky — ORM generate SQL không optimal, ví dụ Prisma đôi khi tạo subquery thay vì JOIN hiệu quả hơn; N+1 query problem nếu không cẩn thận; khó debug khi cần hiểu SQL được generate; overhead runtime. Raw query escape hatch quan trọng: Prisma có $queryRaw, Sequelize có sequelize.query() — nên dùng cho queries phức tạp cần kiểm soát. Migration management: Prisma Migrate, Flyway, Liquibase giúp track và apply schema changes theo đúng thứ tự." },
  { id: 730, category: "Database", subcategory: "ORM", level: "intermediate", q: "Prisma ORM là gì? Tại sao phổ biến trong Node.js/TypeScript ecosystem?", a: "Prisma là ORM thế hệ mới cho Node.js/TypeScript với schema-first approach. Điểm mạnh: Prisma Client auto-generated từ schema.prisma — mỗi lần chạy `prisma generate` tạo ra TypeScript types hoàn toàn accurate với database schema; Prisma Migrate cho migrations với SQL migration files có thể review; Prisma Studio là GUI để browse data. Internals quan trọng: Prisma dùng query engine viết bằng Rust (binary được download khi install) — giúp performance tốt và type-safe query builder. Preview features như Prisma Accelerate (connection pooling + query caching ở edge) và Prisma Pulse (real-time database events). So với Sequelize/TypeORM: Prisma có DX tốt hơn, type safety mạnh hơn (không cần decorators), nhưng không hỗ trợ tốt complex inheritance patterns. Khi schema thay đổi, phải chạy `prisma generate` để sync TypeScript types — bước quan trọng trong CI/CD pipeline." },
  { id: 731, category: "Database", subcategory: "ORM", level: "intermediate", q: "Prisma schema file hoạt động như thế nào?", a: "schema.prisma là single source of truth với ba sections: datasource (kết nối DB), generator (config Prisma Client), và models. Relations syntax: @relation('PostToUser', fields: [authorId], references: [id]) cho foreign key; implicit M2M relations dùng junction table tự động. Enums được định nghĩa trực tiếp và map đến DB enums hoặc strings. @map/@db directives quan trọng: @map('user_name') đổi field name trong DB trong khi giữ camelCase trong code; @db.VarChar(255) chỉ định DB-specific type. Multi-schema support (preview): datasource db { schemas: ['public', 'auth'] } cho multi-tenant apps. prisma format tự động format và sort fields. `prisma migrate dev` tạo SQL migration files có thể review và edit trước khi apply — quan trọng khi cần migration phức tạp như data migration." },
  { id: 732, category: "Database", subcategory: "ORM", level: "intermediate", q: "N+1 query problem trong ORM là gì? Cách giải quyết trong Prisma?", a: "N+1 problem: query 1 lần lấy list N items (1 query), rồi loop qua từng item để fetch related data (N queries) — tổng N+1 queries. Ví dụ: lấy 100 users rồi lấy posts của từng user = 101 queries thay vì 1. Cách phát hiện: enable query logging trong Prisma với `log: ['query']` trong PrismaClient constructor — đếm số queries per request. Giải quyết trong Prisma: dùng `include` để eager load (prisma.user.findMany({ include: { posts: true } })) — Prisma chạy 2 queries và merge; dùng `select` với nested select để lấy chỉ fields cần thiết; Prisma fluent API: user.posts() chạy lazy load — tránh trong loops. DataLoader pattern cho GraphQL: batch nhiều individual loads thành một query duy nhất, ví dụ DataLoader của Facebook group tất cả userId requests trong một tick rồi batch fetch. Prisma chưa có built-in DataLoader nhưng có thể dùng @paljs/plugins hoặc tự implement." },
  { id: 733, category: "Database", subcategory: "ORM", level: "intermediate", q: "Sequelize là gì? So sánh với Prisma?", a: "Sequelize là ORM lâu đời cho Node.js, hỗ trợ MySQL, PostgreSQL, SQLite, MSSQL, MariaDB. Migration system: sequelize-cli tạo migration files với up/down functions — mạnh nhưng verbose. Hooks (lifecycle events): beforeCreate, afterCreate, beforeUpdate, beforeDestroy — dùng cho audit logging, password hashing. Scopes: defaultScope (applied to all queries), named scopes như User.scope('active') — tái sử dụng query conditions. Transaction support: sequelize.transaction(async (t) => { await Model.create({...}, { transaction: t }) }). Tại sao teams migrate away: TypeScript types không accurate (cần sequelize-typescript), verbose model definitions với decorators, runtime errors khó debug, DX kém so với Prisma. Nên dùng Sequelize khi maintain legacy codebase hoặc cần tính năng như polymorphic associations mà Prisma chưa hỗ trợ." },
  { id: 734, category: "Database", subcategory: "ORM", level: "intermediate", q: "Mongoose là gì? Schema trong Mongoose hoạt động như thế nào?", a: "Mongoose là ODM (Object Document Mapper) cho MongoDB trong Node.js, giúp thêm structure vào schemaless MongoDB. Middleware (hooks) có 4 loại: document middleware (pre/post save, validate, remove — `this` là document), query middleware (pre/post find, findOne, update — `this` là query), aggregate middleware (pre/post aggregate), model middleware. Virtuals: computed properties không lưu trong DB — ví dụ fullName computed từ firstName + lastName, hay URL computed từ slug; có thể include trong JSON với toJSON({ virtuals: true }). Populate: thay thế ObjectId references bằng actual documents — populate('author') fetch User document; nhưng cẩn thận N+1, dùng populate với select để limit fields. lean(): trả về plain JavaScript objects thay vì Mongoose documents — nhanh hơn 2-3x vì bỏ overhead của Mongoose document methods; dùng khi chỉ cần read-only data. Pitfall: Mongoose buffering commands trước khi kết nối — cần handle connection errors properly." },
  { id: 735, category: "Database", subcategory: "NoSQL", level: "intermediate", q: "Redis là gì? Use cases phổ biến của Redis?", a: "Redis là in-memory data store với rich data structures và persistence tùy chọn. Data structure use cases cụ thể: Sorted Set (ZADD, ZRANGE) cho leaderboard — score tự động sorted, query top-N O(log N); Pub/Sub (SUBSCRIBE, PUBLISH) cho real-time notifications và chat; List (LPUSH/RPOP) cho job queue hoặc activity feed; HyperLogLog cho approximate unique count với fixed memory; Streams (XADD, XREAD) cho event sourcing, message queue có consumer groups. Persistence: RDB (snapshot tại intervals — nhanh hơn cho restart, có thể mất data nếu crash giữa snapshots); AOF (Append-Only File — log mọi write operation, recovery tốt hơn nhưng file lớn hơn); RDB+AOF kết hợp cho best of both worlds. Redis Cluster: horizontal sharding tự động với 16384 hash slots, minimum 3 master nodes — đảm bảo availability khi node fail. Redis Sentinel: high availability cho single-master setup với automatic failover." },
  { id: 736, category: "Database", subcategory: "NoSQL", level: "intermediate", q: "Khi nào nên dùng Redis làm cache?", a: "Dùng Redis cache khi: data đọc nhiều hơn ghi, computation expensive (complex DB queries, API calls), cần reduce database load, data có thể stale trong thời gian ngắn. Chiến lược: Cache-aside/Lazy loading (check cache → miss → fetch DB → write cache); Write-through (write cache + DB đồng thời — consistent nhưng write latency cao); Write-behind/Write-back (write cache → async write DB — nhanh nhưng risk data loss). Cache stampede problem: nhiều requests hit cache cùng lúc khi cache expire, all go to DB — giải quyết bằng mutex lock (SET key value NX EX 30 để lock), hoặc probabilistic early expiration (expire sớm với xác suất nhỏ trước TTL thật). Memory management: maxmemory-policy quan trọng — allkeys-lru (evict least-recently-used) cho cache, volatile-lru (chỉ evict keys có TTL), noeviction (trả error khi full — dùng cho session storage). Monitoring: redis-cli INFO stats để xem hit rate, connected clients, memory usage; target cache hit rate >80% là healthy." },
  { id: 737, category: "Database", subcategory: "NoSQL", level: "advanced", q: "MongoDB aggregation pipeline là gì?", a: "Aggregation pipeline là series of stages xử lý documents tuần tự, output của stage này là input của stage tiếp theo. Stages phổ biến: $match (filter — đặt đầu pipeline để tận dụng index), $group (group và aggregate với $sum, $avg, $push), $project (reshape, add computed fields), $sort/$limit/$skip, $lookup (LEFT JOIN với collection khác). Pipeline optimization: đặt $match và $project sớm nhất có thể để giảm số documents xử lý ở stages sau; $match sau $unwind là anti-pattern. $facet: chạy nhiều pipeline stages song song trên cùng input, trả về multiple result sets trong một query — phù hợp faceted search (count by category + count by price range simultaneously). $graphLookup: recursive lookup cho graph/tree data, ví dụ organizational hierarchy hay category tree với maxDepth control. Atlas Aggregation Builder: GUI tool trong MongoDB Atlas cho phép build pipeline visually và export code. Explain plan: db.collection.aggregate([...]).explain('executionStats') để kiểm tra query plan và indexes used." },
  { id: 738, category: "Database", subcategory: "ORM", level: "advanced", q: "Database transactions trong Prisma: cách sử dụng?", a: "Prisma hỗ trợ hai loại transactions: Sequential transactions với prisma.$transaction([op1, op2]) — chạy tuần tự, rollback toàn bộ nếu bất kỳ operation nào fail, không có conditional logic. Interactive transactions với prisma.$transaction(async (tx) => { const user = await tx.user.create({...}); if (user.role === 'admin') { await tx.adminProfile.create({...}); } }) — cho phép conditional logic, dùng tx thay cho prisma để operations nằm trong cùng transaction. Isolation levels: Prisma hỗ trợ chỉ định isolation level prisma.$transaction([...], { isolationLevel: Prisma.TransactionIsolationLevel.Serializable }). Nested writes như implicit transactions: prisma.user.create({ data: { profile: { create: {...} } } }) tự động wrap trong transaction. Timeout configuration: prisma.$transaction([...], { timeout: 5000 }) mặc định 5s — tăng khi cần. Distributed transaction limitations: Prisma không hỗ trợ transactions spanning multiple databases — cần 2-phase commit protocol hoặc saga pattern cho microservices." },
  { id: 739, category: "Database", subcategory: "ORM", level: "intermediate", q: "Drizzle ORM là gì? So sánh với Prisma?", a: "Drizzle là TypeScript ORM nhẹ với SQL-like query builder — viết queries gần với SQL nhưng type-safe: db.select().from(users).where(eq(users.age, 25)).orderBy(desc(users.createdAt)). Schema định nghĩa bằng TypeScript với type inference tự động: const users = pgTable('users', { id: serial('id').primaryKey(), name: text('name').notNull() }). Prepared statements: db.select().from(users).where(eq(users.id, sql.placeholder('id'))).prepare('getUserById') — compile một lần, execute nhiều lần với different params, nhanh hơn. Migration generation: drizzle-kit generate tạo SQL migration từ schema changes, drizzle-kit push để apply. Edge runtime compatibility: không có native binary như Prisma engine — bundle size nhỏ hơn nhiều (~100KB vs Prisma ~40MB), chạy tốt trên Cloudflare Workers, Vercel Edge. Performance: benchmark cho thấy Drizzle nhanh hơn Prisma 2-5x cho simple queries do ít abstraction layers. Hạn chế: DX kém hơn Prisma (verbose hơn), community nhỏ hơn, một số advanced features còn thiếu." },
  { id: 740, category: "Database", subcategory: "NoSQL", level: "intermediate", q: "Document embedding vs referencing trong MongoDB: khi nào dùng cái nào?", a: "Embedding (nested document): dùng khi data được truy cập cùng nhau thường xuyên (one query, no joins), quan hệ 1:1 hoặc 1:few, data ít thay đổi, subdocuments không cần exist độc lập. Giới hạn quan trọng: MongoDB document size limit là 16MB — embedding quá nhiều dẫn đến hit limit. Referencing (separate documents với ObjectId): dùng khi data lớn, quan hệ many-to-many, data được truy cập/update độc lập — nhưng cần $lookup (LEFT JOIN) hoặc application-side join, tốn thêm round trip. Data duplication trade-off: embedding duplicate data (ví dụ user info trong mỗi order document) — read nhanh hơn nhưng update tốn công (phải update nhiều documents). Schema design patterns: Bucket pattern — nhóm time-series data vào buckets (ví dụ nhóm sensor readings theo giờ thay vì một document per reading) để giảm document count; Outlier pattern — handle edge cases riêng khi 90% documents nhỏ nhưng 10% có thể rất lớn (ví dụ celebrity posts có millions of likes). $lookup performance: thêm index trên lookup field, tránh $lookup trong large collections không có index." },

  // === DATABASE: Advanced (741-750) ===
  { id: 741, category: "Database", subcategory: "Advanced", level: "advanced", q: "ACID properties trong database là gì?", a: "ACID đảm bảo database transactions đáng tin cậy. Atomicity: transaction thành công toàn bộ hoặc rollback toàn bộ — ví dụ bank transfer trừ $100 từ account A và cộng $100 vào account B phải là một đơn vị; nếu bước 2 fail, bước 1 phải rollback. Consistency: data luôn ở trạng thái hợp lệ theo constraints — ví dụ foreign key constraint đảm bảo không thể tạo order với non-existent userId. Isolation: concurrent transactions không thấy intermediate state của nhau — mức độ isolation khác nhau (READ COMMITTED, SERIALIZABLE). Durability: committed data không mất dù server crash — PostgreSQL dùng WAL (Write-Ahead Log) để ghi log trước khi apply changes, có thể replay để recover. Implementation khác nhau: PostgreSQL full ACID; MySQL InnoDB hỗ trợ ACID, MyISAM không; MongoDB 4.0+ ACID multi-document transactions nhưng performance cao hơn single-document operations. BASE (Basically Available, Soft state, Eventual consistency) là alternative cho NoSQL systems như Cassandra — ưu tiên availability và performance over strict consistency, phù hợp cho hệ thống cần scale cực lớn." },
  { id: 742, category: "Database", subcategory: "Advanced", level: "advanced", q: "Database transactions là gì? Cách sử dụng trong SQL?", a: "Transaction là nhóm operations thực hiện như một đơn vị atomic. Cú pháp: BEGIN; UPDATE accounts SET balance = balance - 100 WHERE id = 1; UPDATE accounts SET balance = balance + 100 WHERE id = 2; COMMIT; — hoặc ROLLBACK nếu có lỗi. Savepoints cho partial rollback: SAVEPOINT sp1; ... nếu lỗi ROLLBACK TO SAVEPOINT sp1; — có thể rollback về điểm giữa trong transaction mà không rollback toàn bộ, hữu ích trong stored procedures phức tạp. Transaction log (WAL — Write-Ahead Log): PostgreSQL ghi changes vào WAL trước khi apply vào actual data files — đảm bảo durability và cho phép Point-in-Time Recovery. Long-running transaction risks: giữ locks lâu dẫn đến lock escalation (row locks upgrade lên table lock), blocking other transactions, tăng replication lag, vacuum bị block trong PostgreSQL gây table bloat. Deadlock detection: database tự detect deadlock (circular wait), kill một transaction và trả error 40P01 trong PostgreSQL — application phải retry. Best practice: keep transactions ngắn, không làm I/O operations (HTTP calls, file reads) bên trong transaction." },
  { id: 743, category: "Database", subcategory: "Advanced", level: "advanced", q: "Transaction isolation levels là gì? Các levels là gì?", a: "Isolation levels kiểm soát visibility giữa concurrent transactions và loại anomaly có thể xảy ra. Dirty Read (READ UNCOMMITTED): transaction A đọc data chưa committed của transaction B — B sau đó rollback, A đã đọc data sai; không có DB production nào recommend dùng. Non-repeatable Read (READ COMMITTED — default PostgreSQL): transaction A đọc row, transaction B update và commit, A đọc lại cùng row thấy giá trị khác. Phantom Read (REPEATABLE READ — default MySQL InnoDB): transaction A query với WHERE condition, B insert row mới thỏa condition và commit, A query lại thấy row mới (phantom). SERIALIZABLE: không có anomaly nào — transactions chạy như tuần tự, highest isolation, lowest concurrency. PostgreSQL implementation dùng MVCC (Multi-Version Concurrency Control): mỗi transaction thấy snapshot của database tại thời điểm bắt đầu — readers không block writers và ngược lại; PostgreSQL MVCC giúp READ COMMITTED và REPEATABLE READ không cần shared read locks. Serializable Snapshot Isolation (SSI) trong PostgreSQL: detect serialization conflicts mà không cần exclusive locks — ít deadlocks hơn traditional 2PL. Practical advice: dùng READ COMMITTED cho hầu hết cases, REPEATABLE READ khi cần consistent reads trong transaction, SERIALIZABLE chỉ khi thực sự cần." },
  { id: 744, category: "Database", subcategory: "Advanced", level: "advanced", q: "Database indexing strategies: B-tree index, Hash index, GIN index khác nhau như thế nào?", a: "B-tree (default): balanced tree structure, phù hợp equality (=), range queries (<, >, BETWEEN), ORDER BY, prefix LIKE 'abc%'. Là lựa chọn đúng cho 95% trường hợp. Hash: chỉ equality checks — lý thuyết nhanh hơn B-tree cho equality nhưng không thể dùng cho range, không được replicated trong PostgreSQL cũ (fixed 10+). GIN (Generalized Inverted Index): array containment, full-text search (tsvector), JSONB operators (@>, ?) — mỗi phần tử trong array/document được index riêng, build chậm hơn nhưng queries trên multi-value columns cực nhanh. GiST: geometric data (PostGIS), range types, full-text search — linh hoạt hơn GIN nhưng chậm hơn cho tìm kiếm đơn giản. BRIN (Block Range Index): rất nhỏ, cho time-series data có natural correlation với physical storage (ví dụ timestamp columns trong append-only tables) — index size chỉ vài KB thay vì GB. Expression indexes: CREATE INDEX ON orders (LOWER(email)) — index tính toán expression, hữu ích khi query luôn dùng LOWER(). Partial indexes với WHERE clause: CREATE INDEX ON orders (user_id) WHERE status = 'pending' — index nhỏ hơn, update nhanh hơn, rất hiệu quả khi query luôn filter theo condition cố định. Index on expressions và partial indexes thường bị bỏ qua nhưng có thể improve performance 10-100x cho specific query patterns." },
  { id: 745, category: "Database", subcategory: "Advanced", level: "advanced", q: "Database replication là gì? Primary-replica architecture hoạt động như thế nào?", a: "Replication copy data từ primary sang một hoặc nhiều replicas để scale read throughput và high availability. Streaming replication (PostgreSQL): primary liên tục stream WAL records đến replicas real-time — replica lag thường dưới 1 giây trong normal conditions; đo lag bằng pg_stat_replication view. Logical replication: replicate specific tables hoặc row changes (không toàn bộ WAL) — cho phép selective replication, version upgrades zero-downtime, replicate sang different schema. Synchronous vs asynchronous: sync replication (synchronous_standby_names) đảm bảo replica nhận data trước khi commit confirm — zero data loss nhưng write latency tăng (cần ít nhất một replica online); async replication confirm ngay, replica có thể lag vài giây — risk mất data nếu primary crash. Replication lag measurement: SELECT now() - pg_last_xact_replay_timestamp() trên replica. Failover automation: Patroni là HA solution phổ biến cho PostgreSQL — dùng etcd/ZooKeeper/Consul để distributed consensus, tự động promote replica thành primary khi primary fail, update DNS/HAProxy để redirect traffic. Read-after-write consistency issue: sau khi write đến primary, immediate read từ replica có thể không thấy data mới do replication lag — cần route reads sau writes đến primary hoặc implement lag-aware routing." },
  { id: 746, category: "Database", subcategory: "Advanced", level: "advanced", q: "Database sharding là gì? Khi nào cần sharding?", a: "Sharding là chia data ngang (horizontal partitioning) ra nhiều database servers, mỗi shard chứa một tập con data — scale beyond single server capacity. Shard key selection là quyết định quan trọng nhất: chọn sai gây hot spots (một shard nhận phần lớn traffic). Ví dụ: sharding by user_id với hash — distribute evenly; sharding by country — có thể hot spot nếu US users chiếm 80% traffic. Hot spots: timestamp làm shard key cho time-series data — mọi writes vào shard mới nhất (sequential hotspot); giải quyết bằng add random suffix hoặc dùng hash. Range-based sharding: user 1-1M trên shard 1, 1M-2M trên shard 2 — range queries efficient nhưng dễ hot spot. Hash-based: hash(user_id) % num_shards — distribute evenly nhưng range queries không efficient. Resharding challenges: khi cần thêm shard phải redistribute data — tốn thời gian và có downtime risk; consistent hashing giảm số keys cần redistribute khi thêm/bỏ node. Cross-shard queries: JOIN across shards không native — phải application-level join (scatter-gather), chậm và phức tạp. Alternatives trước khi sharding: vertical scaling (bigger server), read replicas cho read-heavy workloads, caching layer (Redis), table partitioning (same server), archiving old data. Sharding chỉ cần thiết khi dataset thực sự quá lớn (thường >1-2TB hoặc write throughput vượt quá single master)." },
  { id: 747, category: "Database", subcategory: "Advanced", level: "advanced", q: "CAP theorem là gì? Ý nghĩa trong database selection?", a: "CAP theorem: trong distributed database, chỉ có thể đảm bảo tối đa 2 trong 3 properties: Consistency (mọi node thấy data giống nhau), Availability (mọi request nhận response), Partition Tolerance (hoạt động khi network partition). Thực tế P luôn cần, nên chọn CP hoặc AP. MongoDB tùy cấu hình: default gần AP, với writeConcern/readConcern majority → CP. Cassandra thiên AP." },
  { id: 748, category: "Database", subcategory: "Advanced", level: "advanced", q: "Connection pooling trong database là gì? Tại sao quan trọng?", a: "Connection pooling duy trì pool of reusable database connections thay vì tạo connection mới cho mỗi request. Tạo connection tốn 20-100ms (TCP handshake, SSL negotiation, auth, session setup) — với 1000 requests/s việc tạo new connection mỗi lần là catastrophic. PgBouncer: connection pooler phổ biến nhất cho PostgreSQL, đứng giữa app và DB, hỗ trợ 3 modes: Session (connection held for entire client session), Transaction (connection returned to pool after each transaction — recommended), Statement (per-statement, most aggressive nhưng không support multi-statement transactions). Pool sizing formula: connections = (core_count * 2) + effective_spindle_count — ví dụ server 4 cores với SSD: 4*2+1 = 9 connections; lớn hơn không phải lúc nào cũng tốt hơn vì context switching overhead. Prisma connection pool: DATABASE_URL='postgresql://...?connection_limit=10&pool_timeout=20' — connection_limit per Prisma instance. Serverless challenges: mỗi Lambda/Edge function có pool riêng — với 1000 concurrent invocations = 1000 * pool_size connections đến DB, vượt quá PostgreSQL max_connections (default 100). Giải quyết: PgBouncer ở transaction mode, Prisma Accelerate (managed connection pooling), Neon serverless driver với HTTP-based connections không cần persistent TCP." },
  { id: 749, category: "Database", subcategory: "Advanced", level: "advanced", q: "Full-text search trong database là gì? PostgreSQL vs Elasticsearch?", a: "Full-text search tìm kiếm trong text content với stemming (running → run), stop words removal, và relevance ranking. PostgreSQL built-in: tsvector là processed document representation (to_tsvector('english', 'The quick brown fox') → 'brown':3 'fox':4 'quick':2); tsquery là search query (to_tsquery('quick & fox')). GIN index trên tsvector column cho fast lookups: CREATE INDEX ON articles USING GIN(to_tsvector('english', content)). Ranking với ts_rank(tsvector, tsquery) trả về float score. Đủ cho moderate needs (< vài triệu documents, single language, không cần fuzzy matching). Elasticsearch: inverted index — mỗi term map đến list of documents chứa term đó, cực nhanh cho text search. Distributed, horizontal scaling, advanced relevance scoring (BM25 algorithm), rich query DSL (fuzzy, phrase, wildcard, geospatial). Nhưng operational complexity cao: cần maintain Elasticsearch cluster, sync data từ primary DB. Typesense và Meilisearch: alternatives đơn giản hơn Elasticsearch — dễ setup, typo-tolerant search built-in, REST API friendly, tốt cho product search, documentation search. Quyết định: dùng PostgreSQL FTS nếu search là secondary feature và dataset nhỏ; Meilisearch/Typesense cho product search với good DX; Elasticsearch khi cần distributed, advanced analytics, log aggregation (ELK stack)." },
  { id: 750, category: "Database", subcategory: "Advanced", level: "advanced", q: "Optimistic locking vs Pessimistic locking trong database là gì?", a: "Pessimistic locking: lock record khi đọc với SELECT FOR UPDATE — ngăn other transactions modify cho đến khi transaction hiện tại commit/rollback. An toàn nhưng giảm concurrency, risk deadlock nếu không cẩn thận về lock order. Row-level vs table-level: PostgreSQL default là row-level locks (SELECT FOR UPDATE); table-level lock với LOCK TABLE — rất restrictive, tránh dùng. SELECT FOR UPDATE SKIP LOCKED: bỏ qua rows đã locked — pattern quan trọng cho job queue, tránh nhiều workers pick cùng job. Advisory locks: application-level locks không gắn với specific rows — pg_try_advisory_lock(key) trả về boolean, hữu ích cho distributed coordination (ví dụ chỉ một cron job chạy tại một thời điểm). Optimistic locking: không lock, thêm version column (INTEGER) hoặc updated_at timestamp; khi update: UPDATE ... WHERE id = ? AND version = ? — nếu 0 rows affected thì concurrent modification đã xảy ra, retry. Phù hợp read-heavy, low contention. Lock timeout configuration: SET lock_timeout = '5s' tránh query chờ lock vô tận. Monitoring locks trong PostgreSQL: SELECT * FROM pg_locks JOIN pg_stat_activity USING (pid) WHERE NOT granted — thấy queries đang chờ lock; pg_blocking_pids(pid) trả về PIDs đang block query." },

  // === BUILD TOOLS (751-765) ===
  { id: 751, category: "Build Tools", subcategory: "Webpack", level: "intermediate", q: "Webpack là gì? Vai trò trong modern web development?", a: "Webpack là module bundler tổng hợp tất cả assets (JS, CSS, images) thành bundle files tối ưu. Core concepts: Entry — điểm bắt đầu của dependency graph (thường src/index.js); Output — nơi emit bundles (dist/bundle.js); Loaders — transform file types thành modules (babel-loader chuyển JSX, css-loader parse CSS imports); Plugins — can thiệp vào build lifecycle (HtmlWebpackPlugin tạo HTML, MiniCssExtractPlugin tách CSS ra file riêng, DefinePlugin inject constants); Mode (development/production) — tự động apply optimizations. Dev server: webpack-dev-server serve bundles in-memory, HMR thay module mà không reload page. Code splitting với dynamic import(): Webpack tự tạo chunk files, load on demand. Tại sao đang bị thay thế: config quá phức tạp (webpack.config.js dài hàng trăm dòng), dev server chậm vì bundle toàn bộ app khi start và khi HMR — Vite/Turbopack giải quyết vấn đề này với native ESM. Vẫn phổ biến: nhiều enterprise projects, Create React App (eject), custom build pipelines cần flexibility cao." },
  { id: 752, category: "Build Tools", subcategory: "Webpack", level: "intermediate", q: "Loaders và Plugins trong Webpack khác nhau như thế nào?", a: "Loaders transform file types thành modules — hoạt động ở file level trong module resolution pipeline. Execution order: right-to-left (bottom-to-top trong config array) — ví dụ ['style-loader', 'css-loader', 'sass-loader'] chạy sass-loader trước. Loaders phổ biến: babel-loader (ES6+/JSX→ES5), css-loader (parse @import và url()), style-loader (inject CSS vào DOM), sass-loader (SCSS→CSS), file-loader/asset modules (handle images/fonts), ts-loader/swc-loader (TypeScript). Custom loader là function nhận source string, transform, return new string — đơn giản implement. Plugins can thiệp vào Webpack compiler lifecycle qua hooks (beforeRun, emit, done). Plugins phổ biến: HtmlWebpackPlugin (generate HTML với injected script tags), MiniCssExtractPlugin (tách CSS thành files riêng thay vì inject vào JS), TerserPlugin (minify JS), DefinePlugin (thay constants lúc build — NODE_ENV), BundleAnalyzerPlugin (visualize bundle). Custom plugin phức tạp hơn loader: phải implement apply(compiler) method và tap vào compiler hooks. Rule of thumb: cần transform file type → loader; cần can thiệp vào build process rộng hơn → plugin." },
  { id: 753, category: "Build Tools", subcategory: "Vite", level: "beginner", q: "Vite là gì? Tại sao nhanh hơn Webpack trong development?", a: "Vite là build tool thế hệ mới của Evan You. Dev server không bundle — browser request file nào thì Vite transform file đó on-demand qua native ESM, cold start gần như instant bất kể project size. esbuild pre-bundling: lần đầu start, Vite dùng esbuild (Rust-based, 10-100x nhanh hơn JS bundlers) để bundle node_modules thành single module — tránh browser phải request hàng nghìn files nhỏ; result được cache trong node_modules/.vite. Native ESM serving: source files served dưới dạng ES modules trực tiếp, browser handle dependency graph — chỉ transform file cần thiết cho request hiện tại. Production: dùng Rollup để bundle vì Rollup có tree shaking tốt hơn và output nhỏ hơn esbuild cho production; cũng dùng esbuild để minify (nhanh hơn Terser). Plugin ecosystem: Vite plugins compatible với Rollup plugin API — vite-plugin-react (React Fast Refresh), @vitejs/plugin-vue, vite-plugin-pwa. Framework integrations: Vite là foundation cho SvelteKit, Qwik, Astro, và Remix (một phần). HMR: chỉ invalidate module thay đổi và direct importers — không re-process toàn bộ bundle graph." },
  { id: 754, category: "Build Tools", subcategory: "Vite", level: "intermediate", q: "Sự khác biệt giữa Vite dev server và Webpack dev server?", a: "Cold start comparison: Webpack dev server bundle toàn bộ module graph trước khi server ready — project 1000 modules có thể mất 10-30 giây; Vite start trong <1 giây bất kể project size vì không pre-bundle source. Dependency pre-bundling: Vite dùng esbuild pre-bundle node_modules một lần (cached), browser chỉ cần load vài files thay vì hàng nghìn; Webpack bundle tất cả cùng nhau. HMR mechanism differences: Webpack HMR phải re-compile affected module và dependencies, có thể mất 1-10 giây với large modules; Vite HMR chỉ invalidate changed module và propagate lên import chain, thường <100ms. Vite precision: Vite biết chính xác file nào thay đổi và chỉ update đúng phần đó; React Fast Refresh với Vite preserve component state khi update. Trade-off: Vite dev (ESM) và production (Rollup bundled) có thể có behavior khác nhau — potential inconsistencies với circular imports hay module loading order. Large projects: Vite advantage càng rõ khi project lớn hơn — Webpack cold start tăng linear với module count, Vite gần như constant. Turbopack (Next.js 13+): Vercel's Webpack successor viết bằng Rust, cạnh tranh trực tiếp với Vite về speed trong dev mode." },
  { id: 755, category: "Build Tools", subcategory: "Babel", level: "intermediate", q: "Babel là gì? Vai trò trong JavaScript toolchain?", a: "Babel là JavaScript compiler với 3-phase pipeline: Parse (source code → AST via @babel/parser), Transform (plugins traverse và modify AST — ví dụ arrow function plugin chuyển () => {} thành function() {}), Generate (AST → output code via @babel/generator). Polyfills vs transforms: transforms là syntax changes (const → var, class → prototype); polyfills là runtime additions cho missing APIs (Promise, Array.from, fetch) — Babel transforms syntax nhưng không tự polyfill APIs. core-js là polyfill library chuẩn — @babel/preset-env với useBuiltIns: 'usage' tự động import chỉ polyfills cần thiết dựa trên browserslist config. browserslist config (trong package.json hoặc .browserslistrc): target browsers list như '> 0.5%, last 2 versions, not dead' — preset-env compile chỉ những features không được target browsers hỗ trợ natively, giảm output size. Plugin order: plugins chạy trước presets, plugins first-to-last, presets last-to-first (legacy behavior). Babel vs SWC vs esbuild: Babel chậm nhất (JS) nhưng most customizable plugin ecosystem; SWC nhanh hơn 20-70x (Rust), ít plugins hơn; esbuild nhanh nhất nhưng không hỗ trợ custom transforms." },
  { id: 756, category: "Build Tools", subcategory: "SWC", level: "intermediate", q: "SWC là gì? So sánh với Babel?", a: "SWC (Speedy Web Compiler) là Rust-based JS/TS compiler — nhanh hơn Babel 20-70x single-thread, 70x với multi-core parallelization. Next.js adoption: từ Next.js 12, SWC thay thế Babel cho transpilation và Terser cho minification — cold build 5x nhanh hơn, HMR 3x nhanh hơn; tự động detect và migrate từ Babel config khi có .babelrc. Compatibility: SWC hỗ trợ hầu hết Babel transforms — preset-env equivalents, TypeScript, JSX, decorators. Plugin system limitations: SWC plugins viết bằng WebAssembly (WASM) — khó implement hơn Babel plugins (JS), ecosystem nhỏ hơn nhiều; một số advanced Babel transforms (custom macros, babel-plugin-macros) chưa có SWC equivalent. @swc/core dùng trực tiếp trong Node.js scripts, swc-loader cho Webpack, @vitejs/plugin-react có thể dùng SWC. Khi không thể dùng SWC: project phụ thuộc vào Babel plugins đặc biệt (babel-plugin-styled-components transformation, babel-plugin-import for tree shaking), hoặc cần custom transforms. Deno sử dụng SWC internally cho TypeScript transpilation." },
  { id: 757, category: "Build Tools", subcategory: "Package Managers", level: "beginner", q: "pnpm khác npm và yarn như thế nào?", a: "pnpm dùng content-addressable store: mỗi package version lưu một lần trong global store (~/.pnpm-store), tất cả projects symlink đến store — tiết kiệm disk đáng kể (100 projects dùng React chỉ lưu 1 copy). node_modules structure: pnpm tạo non-flat node_modules — mỗi package chỉ thấy dependencies được khai báo trong package.json của nó (strict mode). Phantom dependencies: npm/yarn hoist packages lên root node_modules, code có thể import packages không khai báo trong dependencies — chạy được locally nhưng fail ở nơi khác; pnpm strict mode ngăn phantom deps bằng cách không hoist. Workspace protocol: pnpm-workspace.yaml khai báo workspace packages; 'my-lib': 'workspace:*' trong dependencies để ref local packages — pnpm tự resolve khi install, thay bằng version thật khi publish. Performance: pnpm nhanh hơn npm vì hardlinks, parallel installs; tương đương hoặc nhanh hơn Yarn. Strict mode có thể break legacy code dùng phantom deps — dùng shamefully-hoist: true hoặc .npmrc để workaround. pnpm ngày càng phổ biến cho monorepos (Turborepo + pnpm là stack phổ biến)." },
  { id: 758, category: "Build Tools", subcategory: "CI/CD", level: "intermediate", q: "CI/CD là gì? Sự khác biệt giữa CI và CD?", a: "CI (Continuous Integration): tự động build và test code mỗi khi push hoặc PR, phát hiện lỗi sớm khi còn dễ fix. CD (Continuous Delivery): tự động deploy đến staging sau CI thành công — production deploy cần manual approval; Continuous Deployment: tự động deploy đến production không cần intervention. Pipeline stages điển hình: Lint → Type check → Unit tests → Build → Integration tests → Deploy staging → Smoke tests → Deploy production. Environment promotion: code di chuyển qua dev → staging → production — mỗi stage có environment variables riêng, không share secrets giữa environments. Rollback strategies: blue-green (switch traffic back), feature flags (disable feature không cần redeploy), database migration rollback (down migrations — tại sao mỗi migration cần down script). Feature flags: deploy code mới nhưng disable feature — gradually enable cho users, instant rollback không cần redeploy, A/B testing. Tools: GitHub Actions (tích hợp tốt với GitHub, marketplace), GitLab CI (built-in, tốt cho self-hosted), Jenkins (flexible nhưng phức tạp maintain), CircleCI, Buildkite (fast self-hosted runners). Secrets management: không commit secrets vào code — dùng GitHub Secrets, HashiCorp Vault, AWS Secrets Manager; rotate secrets định kỳ." },
  { id: 759, category: "Build Tools", subcategory: "CI/CD", level: "intermediate", q: "GitHub Actions là gì? Cấu trúc của một workflow file?", a: "GitHub Actions là CI/CD platform tích hợp trong GitHub, trigger bởi events (push, PR, schedule, workflow_dispatch). Workflow YAML trong .github/workflows/ với cấu trúc: on (triggers), jobs (chạy parallel mặc định, dùng needs: để sequential), steps (actions hoặc run commands). Matrix strategy: chạy job với nhiều combinations — matrix: { node: [18, 20], os: [ubuntu-latest, windows-latest] } tạo 4 parallel jobs tự động; dùng để test cross-platform/cross-version. Caching: actions/cache để cache node_modules, build artifacts — key dựa trên hash của package-lock.json để invalidate khi dependencies thay đổi; significant speedup cho install steps. Secrets: lưu trong GitHub repo/org Settings → Secrets, access bằng ${{ secrets.MY_SECRET }} — không bao giờ log secrets. Reusable workflows: workflow A có thể call workflow B với uses: ./.github/workflows/shared.yml — tránh duplicate CI logic across repos. Self-hosted runners: chạy Actions trên máy chủ riêng — tiết kiệm cost cho large workloads, access internal resources, custom hardware (GPU, ARM). OIDC tokens: GitHub Actions có thể auth với AWS/GCP/Azure mà không cần long-lived credentials — best practice cho cloud deployments. Environments với required reviewers: production deployment cần approval từ reviewer trước khi proceed." },
  { id: 760, category: "Build Tools", subcategory: "Docker", level: "intermediate", q: "Docker là gì? Tại sao hữu ích trong development và deployment?", a: "Docker tạo isolated containers chứa app và dependencies. Containers vs VMs: VMs virtualize hardware (heavyweight, có OS riêng, boot minutes); containers share host OS kernel (lightweight, start milliseconds, MB vs GB). Layered filesystem (Union FS): Docker image là stack of read-only layers, container thêm writable layer trên cùng — layers được cache và shared giữa images, kéo image nhanh khi layers đã có. Copy-on-write: khi container modify file từ image layer, Docker copy file lên writable layer trước khi modify. Networking: Bridge network (default, containers communicate qua virtual network); Host network (container dùng host network stack trực tiếp, performance tốt hơn); Overlay network (multi-host, dùng trong Docker Swarm/K8s). Volumes: bind mounts (link host directory vào container cho dev mode); named volumes (Docker-managed storage, persist data cho database); tmpfs mounts (in-memory, không persist). docker-compose: define multi-container apps với YAML — services, networks, volumes; docker-compose up để start toàn bộ stack; essential cho local development với database + app + cache. Production: Docker + Kubernetes (K8s) cho orchestration, auto-scaling, self-healing; Docker + ECS/Cloud Run cho managed container services." },
  { id: 761, category: "Build Tools", subcategory: "Docker", level: "intermediate", q: "Dockerfile là gì? Các instructions cơ bản?", a: "Dockerfile là script định nghĩa cách build Docker image. Layer caching optimization: Docker cache mỗi instruction layer — nếu layer không thay đổi, dùng cache từ previous build. Đặt instructions ít thay đổi trước: FROM → COPY package*.json → RUN npm install → COPY . . — nếu source code thay đổi nhưng package.json không, Docker reuse cached npm install layer (tiết kiệm 1-2 phút). .dockerignore: exclude node_modules, .git, .env, build artifacts — tránh copy không cần thiết vào build context, giảm build time. Security — non-root user: mặc định container chạy root (risk nếu có vulnerability); thêm RUN addgroup -S appgroup && adduser -S appuser -G appgroup; USER appuser trước CMD — principle of least privilege. Health checks: HEALTHCHECK --interval=30s --timeout=3s CMD wget -q -O /dev/null http://localhost:3000/health || exit 1 — Docker/K8s biết container có healthy không để route traffic. CMD vs ENTRYPOINT: ENTRYPOINT định nghĩa executable không thể override (docker run image args — args được pass vào ENTRYPOINT); CMD là default args có thể override; dùng kết hợp ENTRYPOINT ['node'] CMD ['server.js'] — có thể đổi file chạy nhưng không đổi runtime. Multi-line RUN với && và cleanup: RUN apt-get update && apt-get install -y ... && rm -rf /var/lib/apt/lists/* — clean trong cùng layer tránh layer to." },
  { id: 762, category: "Build Tools", subcategory: "Docker", level: "advanced", q: "Multi-stage builds trong Docker là gì? Lợi ích?", a: "Multi-stage builds dùng nhiều FROM statements để tách build environment khỏi runtime image — production image không chứa build tools, source code, dev dependencies. Node.js example: stage 1 (builder): FROM node:20 AS builder; COPY package*.json ./; RUN npm ci; COPY . .; RUN npm run build — compile TypeScript, bundle assets. Stage 2 (runtime): FROM node:20-alpine AS runtime; COPY --from=builder /app/dist ./dist; COPY --from=builder /app/node_modules ./node_modules; USER node; CMD ['node', 'dist/server.js'] — chỉ copy artifacts cần thiết, alpine image (~5MB vs ~900MB full node). Image size reduction: từ 1GB (node:20 với dev deps + source + build tools) xuống 150MB (node:20-alpine với chỉ production deps + built artifacts). Security benefits: attack surface giảm vì không có build tools (TypeScript compiler, webpack, etc.) trong production image — ít potential vulnerabilities hơn. Build arguments: ARG NODE_ENV=production cho phép customize behavior per stage — ARG có thể truyền từ docker build --build-arg. Named stages với AS: có thể copy từ specific stage bằng tên — COPY --from=builder; có thể build đến specific stage: docker build --target builder để debug build issues." },
  { id: 763, category: "Build Tools", subcategory: "Monorepo", level: "advanced", q: "Monorepo là gì? Công cụ phổ biến để quản lý monorepo?", a: "Monorepo là single repository chứa nhiều packages/apps — ngược với polyrepo (mỗi service có repo riêng). Lợi ích: code sharing dễ dàng (shared UI library, utils), atomic commits across packages (thay đổi API và consumer trong một commit), unified tooling và CI, dễ refactor cross-package. Task orchestration: Turborepo và Nx chạy tasks (build, test, lint) song song và theo dependency order — nếu package B depends on package A, A phải build trước B. Affected commands: Nx có nx affected --target=test chỉ chạy tests cho packages bị ảnh hưởng bởi changes — critical cho CI performance trong large monorepos. Caching: Turborepo cache build outputs locally và remotely (Vercel Remote Cache) — nếu inputs không thay đổi, reuse cache thay vì rebuild; có thể chia sẻ cache giữa developers và CI. Internal packages: packages/ui, packages/utils không publish lên npm, chỉ dùng trong repo — workspace:* protocol trong pnpm để reference. Versioning: Changesets tool quản lý versioning và changelogs cho publishable packages. Trade-offs monorepo: repo size lớn, CI phức tạp hơn, cần tooling investment; polyrepo dễ hơn cho independent teams và deployments. Turborepo vs Nx: Turborepo đơn giản hơn, Nx có nhiều features hơn (generators, devtools, cloud)." },
  { id: 764, category: "Build Tools", subcategory: "Webpack", level: "advanced", q: "Tree shaking là gì? Điều kiện để tree shaking hoạt động?", a: "Tree shaking là dead code elimination — loại bỏ unused exports khỏi bundle dựa trên static analysis của import/export statements. Mechanism: bundler build dependency graph, mark exports nào được imported ở đâu, eliminate exports không được referenced — chỉ possible với ES modules (static structure) vì CommonJS require() là dynamic (runtime). Điều kiện để tree shaking hoạt động: phải dùng ES modules (import/export không phải require/module.exports); modules phải side-effect free — library phải khai báo sideEffects: false trong package.json (nếu không Webpack giữ lại toàn bộ module vì không chắc chắn); không có dynamic imports của cùng module. sideEffects field: sideEffects: false nói với bundler 'không có file nào trong package này có side effects khi import' — safe to tree shake; sideEffects: ['*.css', './src/setup.js'] exclude specific files. /*#__PURE__*/ annotation: đánh dấu function call không có side effects — bundler có thể eliminate nếu result không được used: const result = /*#__PURE__*/ createComponent() — phổ biến trong React compiled output. Pitfall: nhiều utility libraries vẫn dùng CommonJS (lodash) — không tree-shakeable; dùng lodash-es (ESM version) hoặc import từ specific path: import debounce from 'lodash/debounce'. Named exports tree-shake tốt hơn default exports vì bundler biết chính xác tên được dùng." },
  { id: 765, category: "Build Tools", subcategory: "CI/CD", level: "advanced", q: "Blue-Green deployment và Canary deployment là gì?", a: "Blue-Green deployment: duy trì hai production environments (blue=current live, green=new version). Deploy lên green, chạy integration tests, rồi switch traffic tại load balancer (nginx upstream, AWS ALB target groups, Kubernetes ingress) — switch instant, không có downtime. Rollback instant: nếu issue phát hiện sau deploy, switch traffic back về blue — green vẫn còn đó. Implementation với load balancer: Nginx upstream block với weight; AWS ALB forward rules; Kubernetes service selector switch. Cost: phải maintain 2 environments song song — expensive cho large infrastructure. Database migrations: challenge lớn nhất — migration phải backward-compatible với cả blue và green code (không thể drop column trong green nếu blue vẫn dùng). Canary deployment: deploy phiên bản mới cho một phần nhỏ users (1-5%), monitor metrics (error rate, latency, business metrics), rồi dần tăng percentage nếu ổn. Metrics cần monitor: error rate tăng đột biến, P99 latency tăng, conversion rate giảm, custom business metrics (orders/minute). Rollback trigger: tự động rollback nếu error rate vượt threshold. Implementation: Kubernetes với Flagger hoặc Argo Rollouts tự động canary với metric-based promotion; feature flags như LaunchDarkly cho canary ở application level. A/B testing vs Canary: A/B test new feature/UI cho subset users để measure business impact; Canary là risk reduction strategy cho infrastructure changes — có thể kết hợp cả hai." },

  // === TESTING (766-780) ===
  { id: 766, category: "Testing", subcategory: "Jest", level: "beginner", q: "Jest là gì? Các tính năng chính của Jest?", a: "Jest là JavaScript testing framework từ Meta, phổ biến nhất trong ecosystem. Zero-config với Create React App và Next.js; TypeScript support qua ts-jest hoặc babel-jest. Test isolation: mỗi test file chạy trong separate Node.js environment (jsdom hoặc node), global state không leak giữa files. Parallel execution: Jest chạy test files song song qua worker pool, isolate failures tốt. Snapshot testing: serialize output và so sánh với .snap files — detect unexpected UI changes. Mocking system: jest.fn(), jest.mock(), jest.spyOn() — mock modules, timers (jest.useFakeTimers), và globals. Code coverage: --coverage flag generate Istanbul reports (statements, branches, functions, lines). Watch mode: --watchAll hoặc --watch chỉ re-run tests affected by changes. Matchers: toBe (===), toEqual (deep), toMatchObject (partial match), toThrow, toHaveBeenCalledWith, resolves/rejects cho async. Setup files: jest.config.js với setupFilesAfterEach để configure Testing Library, mock global APIs. Tích hợp với React Testing Library: render, screen, fireEvent, userEvent — test behavior không implementation details." },
  { id: 767, category: "Testing", subcategory: "Jest", level: "beginner", q: "describe, it/test, expect trong Jest được dùng như thế nào?", a: "describe nhóm related tests thành suite (có thể nest nhiều cấp). it/test định nghĩa test case — tên test nên đọc như documentation: it('should return 404 when user not found'). expect tạo assertion với matchers: toBe (strict ===, dùng cho primitives), toEqual (deep equality, dùng cho objects/arrays), toMatchObject (partial object match — chỉ check specified keys), toContain (array/string contains), toHaveLength, toBeNull/toBeUndefined/toBeTruthy/toBeFalsy, toThrow (function throw error), toHaveBeenCalledWith (mock assertion). Async matchers: await expect(promise).resolves.toBe(value) hoặc await expect(promise).rejects.toThrow(). beforeEach/afterEach chạy trước/sau mỗi test trong describe block — dùng cho setup/teardown (tạo test data, cleanup database, reset mocks). beforeAll/afterAll chạy một lần cho cả describe block — dùng cho expensive setup (start test server, database connection). test.only/describe.only: chỉ chạy selected tests — hữu ích khi debug nhưng đừng commit. test.skip: bỏ qua test tạm thời với reason. test.each: parameterized tests với multiple input/output combinations." },
  { id: 768, category: "Testing", subcategory: "Jest", level: "intermediate", q: "Mocking trong Jest: jest.fn(), jest.mock(), jest.spyOn() dùng như thế nào?", a: "jest.fn() tạo mock function tracking calls, arguments, return values — mockReturnValue(val) cho sync, mockResolvedValue(val) cho Promise, mockRejectedValue(err) cho rejected Promise, mockImplementation(fn) cho custom logic. jest.mock('module-path') auto-mock toàn bộ module (tất cả exports thành jest.fn()); với factory function jest.mock('./api', () => ({ fetchUser: jest.fn() })) cho control toàn diện; hoisting: jest.mock() được hoisted lên đầu file tự động. jest.spyOn(obj, 'method') wrap existing method — vẫn gọi real implementation mặc định, dùng .mockImplementation() để override; quan trọng: phải restore sau test bằng jest.restoreAllMocks() hoặc mockRestore(). Module mock patterns: mock fetch API toàn cục với jest.spyOn(global, 'fetch'); mock environment variables với process.env.MY_VAR = 'test'. Timer mocks: jest.useFakeTimers() replace setTimeout/setInterval/Date; jest.runAllTimers() trigger tất cả pending timers; jest.advanceTimersByTime(ms). Partial mocks: jest.requireActual('module') để mock một phần module và giữ lại real implementation cho phần còn lại. clearMocks vs resetMocks vs restoreMocks: clear (reset calls/instances), reset (clear + remove implementations), restore (reset + restore spies to originals)." },
  { id: 769, category: "Testing", subcategory: "Vitest", level: "intermediate", q: "Vitest là gì? Tại sao là lựa chọn tốt cho Vite projects?", a: "Vitest là test framework xây dựng trên Vite với Jest-compatible API — migrate từ Jest thường chỉ cần đổi import và config. Lợi ích: reuse Vite config và transforms (cùng aliases, plugins, TypeScript setup) — không cần config riêng cho tests; nhanh hơn Jest nhờ esbuild transpilation và native ESM. Watch mode thông minh: chỉ re-run tests liên quan đến changed files, smart dependency tracking qua Vite HMR graph. In-source testing: viết tests trực tiếp trong source file trong if (import.meta.vitest) block — tests bị tree-shaken khỏi production build, hữu ích cho utility functions. Browser mode: chạy tests trong real browser (Chromium/Firefox) thay vì jsdom — accurate DOM behavior, dùng cho component tests. Concurrent tests: test.concurrent() chạy tests trong describe block song song, tăng speed. Snapshot: tương thích với Jest snapshots, có inline snapshots. Coverage: V8 provider (nhanh hơn) hoặc Istanbul. @vitest/ui: browser-based test runner UI để visualize và debug tests. Khác biệt với Jest: Vitest dùng ES modules natively (không transform), config trong vitest.config.ts thay vì jest.config.js, một số globals như __dirname cần config thêm." },
  { id: 770, category: "Testing", subcategory: "Cypress", level: "intermediate", q: "Cypress là gì? Khác gì với Selenium?", a: "Cypress là E2E testing framework chạy trong browser (không qua WebDriver protocol như Selenium). Architecture khác biệt: Cypress chạy trong cùng event loop với app — có thể access application state, intercept network requests, control timers trực tiếp. Time-travel debugging: mỗi command được snapshot, hover qua command list để xem DOM state tại từng bước — exceptional debugging experience. Automatic waiting: Cypress tự retry assertions cho đến khi pass hoặc timeout — không cần manual sleep/waitForElement như Selenium. cy.intercept() cho network stubbing: mock API responses, simulate network errors, wait for specific requests to complete. Component testing: Cypress Component Testing mount individual components trong isolation — alternative cho Jest + Testing Library với real browser. cy.session() để cache và reuse authentication state giữa tests — giảm login overhead. Cypress Cloud: parallel test execution, flaky test detection, video recording. Nhược điểm: chỉ support Chromium-based browsers và Firefox (không có Safari/WebKit); không support multiple tabs trong cùng test; test code phải bất đồng bộ theo Cypress command queue — không dùng async/await thông thường. Thích hợp: rich interactive app testing, khi cần time-travel debugging, single-browser test suites." },
  { id: 771, category: "Testing", subcategory: "Playwright", level: "intermediate", q: "Playwright là gì? So sánh với Cypress?", a: "Playwright là E2E testing framework từ Microsoft, hỗ trợ Chromium, Firefox, WebKit (Safari) — cross-browser coverage thực sự. Parallel test execution built-in: test files chạy song song theo default, có thể config workers; Cypress Cloud tính thêm phí cho parallelization. Multiple tabs/contexts/pages: test multi-tab flows như OAuth popup, new window; browser contexts là isolated sessions (khác profiles). Page Object Model tự nhiên: Playwright khuyến khích tổ chức code theo POM pattern với class-based pages. await/async API: test code dùng standard async/await — dễ đọc và debug hơn Cypress command queue. Network interception: page.route('**/api/**', route => route.fulfill({ json: mockData })) — mạnh và flexible; page.waitForResponse() để wait cho specific API call. Locators: page.getByRole('button', { name: 'Submit' }), getByText(), getByTestId() — semantic locators như Testing Library, auto-retry built-in. Visual regression testing: expect(page).toHaveScreenshot() so sánh screenshots. Tracing: tạo trace.zip với screenshots, network logs, DOM snapshots — mở trong Playwright Trace Viewer để debug CI failures. Playwright Inspector: step-through test execution, pick locators từ browser. So với Cypress: Playwright có better multi-browser support và parallel execution; Cypress có better DX và debugging cho single-browser." },
  { id: 772, category: "Testing", subcategory: "TDD/BDD", level: "intermediate", q: "TDD (Test-Driven Development) là gì? Quy trình Red-Green-Refactor?", a: "TDD viết test trước code — quy trình Red-Green-Refactor: Red (viết test cho behavior mong muốn, test fail vì code chưa có), Green (viết minimum code đủ để test pass — không over-engineer), Refactor (cải thiện code structure, remove duplication trong khi tests vẫn pass). Lợi ích thực tế: buộc suy nghĩ về API/interface trước implementation — kết quả là better-designed, more testable code; coverage cao tự nhiên vì code chỉ được viết khi có test; dễ refactor vì test suite là safety net. Ví dụ: test 'calculateTax(100, 0.1) should return 10' → implement calculateTax → refactor nếu cần. Micro-TDD cycles: mỗi cycle 2-10 phút, test một behavior nhỏ. TDD không phải 'test first' một cách cứng nhắc — nhiều developers làm 'test alongside' (viết test song song với code). Khi TDD khó: legacy code không testable (cần refactor trước), UI-heavy code (E2E tests khó TDD), exploratory code khi chưa biết design. Detroit vs London schools: Detroit (classic TDD, bottom-up, focus on state verification, minimal mocking); London (mockist TDD, top-down với mocks cho collaborators, verify interactions). Practical advice: TDD đặc biệt valuable cho business logic, algorithms, utilities; ít valuable cho simple CRUD và UI layout." },
  { id: 773, category: "Testing", subcategory: "TDD/BDD", level: "intermediate", q: "BDD (Behavior-Driven Development) là gì? Cú pháp Given-When-Then?", a: "BDD là extension của TDD, focus vào behavior từ user/business perspective thay vì technical implementation. Given-When-Then syntax: Given (context/preconditions — 'Given a user with $100 in account'), When (action — 'When they transfer $50'), Then (expected outcome — 'Then the balance should be $50 and recipient has $50'). Gherkin language: human-readable scenarios viết trong .feature files — Given/When/Then/And/But; được Cucumber parse và map đến step definitions trong code. Lợi ích: common language giữa developers, QA, và business stakeholders; scenarios serve as living documentation; non-technical people có thể review và write scenarios. Trong Jest/Vitest: BDD style với describe/it — it('should deduct amount from sender balance when transfer succeeds') đọc như specification. Cucumber.js: feature files → step definitions (JS functions) → actual test code; overkill cho most projects trừ khi business stakeholders thực sự write scenarios. Practical BDD: dùng Given-When-Then naming convention trong unit tests mà không cần Cucumber — captures intent, readable as docs. Pitfall: BDD không phải chỉ về syntax — phải thực sự involve business trong defining behaviors, không chỉ wrap existing tests với Given/When/Then." },
  { id: 774, category: "Testing", subcategory: "Test Pyramid", level: "intermediate", q: "Test pyramid là gì? Ba layers của test pyramid?", a: "Test pyramid của Mike Cohn: base là nhiều unit tests (nhanh <1ms, rẻ, isolated, dễ maintain), giữa là integration tests (test interaction giữa components/services với real dependencies), đỉnh là ít E2E tests (chậm, đắt, brittle — dễ fail vì network, timing, UI changes). Lý do balance 70/20/10: unit tests cho fast feedback và precise error location; integration tests catch boundary bugs unit tests miss; E2E tests verify user journeys nhưng cost cao. Ice cream cone anti-pattern (inverted pyramid): nhiều E2E, ít unit — CI chạy chậm, flaky tests, khó debug khi fail. Testing Trophy (Kent C. Dodds): variation với nhiều integration tests hơn pyramid — 'integration tests give the most confidence per dollar of test cost'. Service layer testing: test business logic through service/use-case layer với real database (integration) thay vì mock everything — catches more real bugs. Practical: không nên có ratio cứng nhắc, phụ thuộc vào project. Smoke tests: minimal E2E tests chạy sau mỗi deployment để verify critical paths hoạt động. Contract tests thay E2E trong microservices. Key insight: fast tests chạy thường xuyên → fast feedback → catch bugs sớm; slow E2E tests chạy ít hơn → feedback chậm." },
  { id: 775, category: "Testing", subcategory: "Jest", level: "intermediate", q: "Snapshot testing trong Jest là gì? Khi nào nên dùng?", a: "Snapshot testing serialize output (component render, JSON object, string) và save vào .snap file — subsequent runs compare với saved snapshot, fail nếu thay đổi. Khi thay đổi là intentional: jest --updateSnapshot (hoặc -u) update tất cả snapshots; jest --updateSnapshot --testNamePattern để update specific. Inline snapshots: toMatchInlineSnapshot() lưu snapshot trong test file thay vì separate .snap file — dễ review hơn trong PRs nhưng clutters test files. Khi nên dùng: stable UI components ít thay đổi (Button, Card, Input), serializable data structures, API response shapes. Khi không nên dùng: frequently changing components (mỗi PR update snapshot không meaningful), dynamic content (timestamps, random IDs — phải mock), complex business logic (unit tests với explicit assertions tốt hơn). Pitfall phổ biến: commit outdated snapshots khi developers chạy update mà không review changes — snapshot tests trở thành rubber stamp. Tốt nhất: kết hợp snapshot tests với explicit assertions cho critical properties. Enzyme vs React Testing Library: Enzyme snapshots test implementation details (component structure); RTL khuyến khích test user-visible output. Custom serializers: jest.addSnapshotSerializer() để format snapshot output đẹp hơn cho custom objects." },
  { id: 776, category: "Testing", subcategory: "Jest", level: "intermediate", q: "Code coverage là gì? Các loại coverage metrics?", a: "Code coverage đo phần trăm code được chạy bởi tests — generated bởi Istanbul (Jest), V8 (Vitest V8 provider). Metrics: Statement coverage (% statements executed — mỗi expression/assignment là statement); Branch coverage (% branches covered — mỗi if/else/ternary/&&/|| tạo 2 branches, phải test cả true và false case); Function coverage (% functions called ít nhất một lần); Line coverage (% lines executed — thường cao nhất, ít meaningful nhất). Branch coverage là metric quan trọng nhất — 100% statement nhưng 70% branch nghĩa là nhiều edge cases chưa được test. 100% coverage không đảm bảo bug-free: test có thể chạy code nhưng không assert correctly; test với wrong inputs không catch bugs với right inputs. Low coverage là red flag: dưới 60-70% thường là warning sign. Coverage thresholds trong jest.config.js: coverageThreshold: { global: { branches: 80, functions: 80 } } — fail CI nếu không đạt. Practical targets: 80-90% cho business logic; 70%+ overall; không chase 100% cho UI components và configuration files. Excluded from coverage: vendor code, generated files, test utilities — dùng coveragePathIgnorePatterns. Coverage reports: text (CI), html (visual inspection), lcov (SonarQube, Codecov). Mutation testing (Stryker): modify code và check nếu tests fail — đo test quality, không chỉ coverage quantity." },
  { id: 777, category: "Testing", subcategory: "Testing", level: "intermediate", q: "Integration testing khác unit testing như thế nào?", a: "Unit testing: test một function/class isolated, mock tất cả external dependencies — nhanh (<1ms), stable, dễ debug khi fail (chính xác biết chỗ nào sai), không cần external services. Tốt cho: algorithms, business logic, pure functions, utilities. Integration testing: test interaction giữa multiple components/services với real hoặc minimal-mock dependencies — ví dụ test API handler với real database (test container), test service với real HTTP client. Chậm hơn (100ms-1s), phát hiện bugs ở boundary (schema mismatch, query lỗi, API contract violation) mà unit tests không thể catch. Supertest pattern (Node.js): const app = express(); const response = await request(app).get('/api/users').expect(200) — test Express routes với real middleware stack, mock chỉ external services. Test containers: spin up real PostgreSQL/Redis trong Docker cho tests — deterministic, isolated, cleanup sau tests. Contract tests thay thế integration tests trong microservices khi services owned bởi different teams. Testing Library philosophy: 'The more your tests resemble the way your software is used, the more confidence they can give you' — integration tests thường cho more confidence per test than unit tests. Mock database vs real database: mock nhanh hơn nhưng có thể miss SQL syntax errors, constraint violations, query performance issues — real DB catches more real-world bugs." },
  { id: 778, category: "Testing", subcategory: "Playwright", level: "advanced", q: "Cách xử lý authentication trong Playwright E2E tests?", a: "Playwright hỗ trợ storageState để save và reuse authentication state giữa tests. Pattern: globalSetup.ts chạy một lần trước tất cả tests — login qua UI hoặc API, save state: await context.storageState({ path: 'auth/user.json' }). Reuse trong playwright.config.ts: use: { storageState: 'auth/user.json' } — mỗi test bắt đầu đã authenticated, không phải login lại. Multiple roles: save different storageStates cho admin, regular user, guest — dùng projects trong config để chạy same tests với different roles. API-based auth nhanh hơn UI login: const response = await request.post('/api/login', { data: { email, password } }); await page.context().addCookies([...]) — avoid UI flakiness. Page Object Model (POM): class LoginPage { constructor(page) {...}; async login(email, pw) { await this.page.fill('#email', email); ... } } — encapsulate page interactions, reusable across tests, easy maintenance khi UI thay đổi. Fixtures trong Playwright: custom fixtures extend base test với pre-setup state — const test = base.extend({ loggedInPage: async ({page}, use) => { await loginUser(page); await use(page); } }) — elegant và composable. Avoid test interdependency: mỗi test phải independent, không phụ thuộc vào state từ test trước — dùng beforeEach để reset state." },
  { id: 779, category: "Testing", subcategory: "Testing", level: "advanced", q: "Contract testing là gì? Tại sao quan trọng trong microservices?", a: "Contract testing verify API contract (format, structure, behavior) giữa service provider và consumer mà không cần cả hai chạy đồng thời — critical trong microservices. Consumer-driven contract testing với Pact: Consumer viết tests định nghĩa expectations về provider responses (pact file); Provider chạy pact file để verify nó thỏa mãn consumer expectations. Pact Broker: central repository cho pact files, track which consumer versions are compatible với which provider versions. Can-I-Deploy tool: query Pact Broker để check nếu service version có thể deploy safely — 'can consumer v2 deploy if provider is v3?'. Tại sao quan trọng hơn E2E tests trong microservices: E2E tests cần tất cả services chạy đồng thời (expensive, slow, flaky); contract tests chạy independently per service — fast, reliable, pinpoint exactly which service broke contract. Breaking change detection: nếu provider thay đổi response schema, pact verification fail ngay trong CI trước khi deploy — không phải phát hiện trong production. Schema registry (Avro, Protobuf) cho event-driven architecture: schema evolution rules, backward/forward compatibility checks — contract testing cho async messaging. OpenAPI contract testing: Dredd, Spectral verify API implementation against OpenAPI spec — simpler than Pact nhưng ít powerful." },
  { id: 780, category: "Testing", subcategory: "Testing", level: "advanced", q: "Test doubles: mock, stub, spy, fake khác nhau như thế nào?", a: "Test doubles là các loại replacements cho real dependencies trong tests — Martin Fowler phân loại trong 'Mocks Aren't Stubs'. Dummy: placeholder object được pass vào nhưng không bao giờ thực sự được dùng — ví dụ pass null hoặc empty object để fulfill parameter requirement. Stub: trả về pre-configured responses cho calls — không verify interactions, chỉ provide canned answers; ví dụ stub database trả về fixed user object. Mock: pre-programmed với expectations về calls mà nó sẽ nhận — verify những interactions này xảy ra; jest.fn() là mock vì có thể assert toHaveBeenCalledWith(); test fail nếu expected calls không xảy ra. Spy: wrap real implementation, record calls — jest.spyOn() by default calls real method, ghi lại arguments; có thể override với mockImplementation khi cần. Fake: có working implementation đơn giản hơn real — fake in-memory database (Map<id, entity>), fake email service (lưu emails vào array thay vì gửi thật), fake message queue. Practical guidance: dùng Stub khi cần control return values; Mock khi muốn verify behavior (dùng đúng dependencies đúng cách); Spy khi muốn observe real implementation; Fake khi cần realistic behavior nhưng không thể/không muốn dùng real service. Overcrowded mocks là code smell: nếu test cần mock quá nhiều dependencies, code đang vi phạm Single Responsibility Principle — refactor code, không thêm mocks." },

  // === PERFORMANCE (781-790) ===
  { id: 781, category: "Performance", subcategory: "Core Web Vitals", level: "intermediate", q: "Core Web Vitals là gì? Ba metrics chính là gì?", a: "Core Web Vitals là bộ metrics của Google đo trải nghiệm người dùng thực tế, ảnh hưởng đến SEO ranking từ 2021. Ba metrics: LCP (Largest Contentful Paint — loading performance, target <2.5s: good, >4s: poor; đo thời gian render phần tử lớn nhất trong viewport); INP (Interaction to Next Paint — thay thế FID từ tháng 3/2024, target <200ms: good, >500ms: poor; đo total delay từ user interaction đến next paint cho tất cả interactions trong session, không chỉ first); CLS (Cumulative Layout Shift — visual stability, target <0.1: good, >0.25: poor; đo mức độ layout shift unexpected). Đo lường: PageSpeed Insights (field data từ Chrome UX Report + lab data từ Lighthouse), Search Console Core Web Vitals report, web-vitals JavaScript library (import { getLCP, getINP, getCLS } from 'web-vitals'). Quan trọng: field data (real users) khác lab data (controlled) — optimize cho field data. TTFB (Time to First Byte) không phải Core Web Vital nhưng ảnh hưởng LCP mạnh; FCP (First Contentful Paint) là diagnostic metric." },
  { id: 782, category: "Performance", subcategory: "Core Web Vitals", level: "intermediate", q: "LCP (Largest Contentful Paint) là gì? Cách cải thiện LCP?", a: "LCP đo thời gian render phần tử lớn nhất trong viewport — thường là hero image, large text block, video poster. Candidates: img, image trong CSS background, video (poster), block-level text. Cải thiện TTFB trước (ảnh hưởng LCP nhất): server response time, CDN, edge caching. Image optimization: serve WebP/AVIF (25-50% nhỏ hơn JPEG), đúng kích thước (không serve 2000px cho 400px container), dùng responsive images với srcset. Preload LCP image: <link rel='preload' as='image' href='hero.webp'> trong <head> — critical vì browser discover image late trong parsing. Không lazy load LCP image: loading='lazy' trên hero image làm tăng LCP đáng kể — chỉ lazy load below-fold. Eliminate render-blocking resources: defer/async non-critical JS, inline critical CSS, preconnect đến third-party domains. fetchpriority='high' attribute trên LCP image hint browser prioritize fetch. Next.js next/image tự động: format conversion, responsive sizes, lazy load by default (priority prop để disable cho LCP image). Thường gặp: LCP image discovered late vì được set bằng CSS background-image — browser không discover cho đến khi parse CSS; dùng <img> thay vì CSS background cho LCP element." },
  { id: 783, category: "Performance", subcategory: "Core Web Vitals", level: "intermediate", q: "CLS (Cumulative Layout Shift) là gì? Nguyên nhân và cách fix?", a: "CLS đo mức độ layout shift unexpected trong quá trình loading — score là sum của (impact fraction * distance fraction) cho mỗi shift. Target <0.1; >0.25 là poor. Nguyên nhân phổ biến và fix: Images/videos không có dimensions — luôn set width/height attributes (aspect-ratio CSS tự tính) hoặc dùng aspect-ratio: 16/9 container; browser reserve space trước khi image load. Fonts gây FOUT (Flash of Unstyled Text) khi web font load — dùng font-display: swap với size-adjust để match fallback font metrics; font-display: optional skip web font nếu không cached (zero CLS nhưng có thể không dùng web font); preload critical fonts. Dynamically injected content (banners, cookie notices, ads) shift content — reserve space trước bằng min-height container; không inject content above existing content sau page load. Dynamic ads: Google Ads có thể gây CLS — fix bằng reserve fixed space cho ad slot. Infinite scroll: thêm items dưới thay vì trên viewport. transform: translateY() thay vì top/margin cho animations — transform không trigger layout. CLS sau interaction (300ms window) không tính vào score — UX vẫn tệ nhưng không penalty. Debugging: Chrome DevTools Performance panel, Layout Shift Regions (Rendering tab)." },
  { id: 784, category: "Performance", subcategory: "Lazy Loading", level: "intermediate", q: "Lazy loading là gì? Cách implement trong React?", a: "Lazy loading trì hoãn loading resources cho đến khi thực sự cần — giảm initial load time và Time to Interactive. Images: <img loading='lazy'> attribute là native browser lazy loading, browser load image khi cần thiết khi scroll đến; không dùng cho LCP image (dùng loading='eager' hoặc priority). Components trong React: const HeavyChart = React.lazy(() => import('./HeavyChart')) kết hợp <Suspense fallback={<Spinner/>}> — chunk được split tự động và load on demand; dùng cho large components, chart libraries, editors. next/dynamic trong Next.js: const DynamicMap = dynamic(() => import('./Map'), { loading: () => <p>Loading...</p>, ssr: false }) — thêm ssr: false để skip server-side rendering cho browser-only components. Route-based lazy loading: React Router <Suspense> + React.lazy() mỗi route là chunk riêng — standard approach. Preloading: sau lazy load, có thể preload chunk trước khi user navigate: import('./HeavyPage') trong onMouseEnter — reduce perceived latency. Intersection Observer API: detect khi element vào viewport để trigger lazy load — basis của nhiều lazy loading libraries. Trade-off: lazy loading adds waterfall (request phải chờ parent component render) — cẩn thận với critical path; chỉ lazy load truly non-critical components." },
  { id: 785, category: "Performance", subcategory: "Code Splitting", level: "intermediate", q: "Code splitting là gì? Các chiến lược code splitting trong web apps?", a: "Code splitting chia bundle thành chunks nhỏ hơn — load initial chunk nhỏ hơn, load thêm chunks on demand. Dynamic import() là foundation: import('./module') trả về Promise, bundler tự tạo separate chunk. Chiến lược: Route-based splitting — mỗi route là chunk riêng, user chỉ download code cho route đang visit; pattern chuẩn với React Router và React.lazy(). Component-based splitting — lazy load heavy components (rich text editor, PDF viewer, 3D rendering) chỉ khi cần. Vendor splitting: tách node_modules thành vendor chunk — ít thay đổi hơn app code, cache lâu hơn; Vite tự động split vendor; Webpack SplitChunksPlugin cấu hình. Shared chunks: code dùng ở nhiều routes tách thành shared chunk — tránh duplicate code trong nhiều chunks. Prefetching và preloading: <link rel='prefetch'> cho next likely navigation (browser idle), <link rel='preload'> cho current route critical resources; Webpack magic comments: import(/* webpackPrefetch: true */ './NextPage'). Analysis: Webpack Bundle Analyzer, vite-bundle-visualizer, source-map-explorer để xem chunk composition và identify optimization opportunities. Pitfall: quá nhiều chunks nhỏ tệ hơn một chunk lớn do HTTP request overhead — HTTP/2 multiplexing giảm vấn đề này nhưng có limits." },
  { id: 786, category: "Performance", subcategory: "Caching", level: "intermediate", q: "HTTP caching hoạt động như thế nào? Cache-Control headers?", a: "HTTP caching giảm bandwidth và latency bằng cách lưu responses tại browser hoặc CDN. Cache-Control directives: max-age=3600 (cache 1 giờ trước khi stale); no-cache (phải revalidate với server trước khi dùng — không phải 'không cache'); no-store (không cache bao giờ, sensitive data); public (CDN có thể cache); private (chỉ browser cache, không CDN); immutable (content không bao giờ thay đổi, skip revalidation kể cả khi max-age expired — dùng với content-hashed assets). Static assets strategy: Cache-Control: public, max-age=31536000, immutable cho files có content hash trong tên (bundle.abc123.js) — cache 1 năm, không bao giờ revalidate. HTML: Cache-Control: no-cache — revalidate mỗi lần nhưng serve từ cache nếu ETag match. Conditional requests: ETag (hash của content) và Last-Modified (timestamp); client gửi If-None-Match/If-Modified-Since trong request; nếu không thay đổi, server trả 304 Not Modified (no body) — tiết kiệm bandwidth. Stale-While-Revalidate: Cache-Control: max-age=60, stale-while-revalidate=300 — serve stale content trong 5 phút trong khi revalidate background; zero latency impact. CDN caching: Cloudflare, Vercel Edge Network cache responses — đặt s-maxage khác max-age để CDN cache lâu hơn browser. Cache busting: thay đổi URL khi content thay đổi (content hash, query string ?v=2)." },
  { id: 787, category: "Performance", subcategory: "Performance", level: "intermediate", q: "Image optimization trong web: các kỹ thuật phổ biến?", a: "Image optimization là một trong các cách hiệu quả nhất để giảm page weight và cải thiện LCP. Modern formats: WebP nhỏ hơn JPEG 25-34%, AVIF nhỏ hơn 50% nhưng encode chậm hơn; dùng <picture> element với fallback cho browser không support. Responsive images: srcset='image-400.webp 400w, image-800.webp 800w' với sizes='(max-width: 600px) 400px, 800px' — browser chọn đúng size cho device; next/image tự động generate. Correct sizing: không serve 2000px image cho 400px container — lãng phí bandwidth 25x; dùng Image CDN (Cloudinary, Imgix) để resize on demand theo URL params. Compression: lossy (JPEG quality 80 thường indistinguishable từ 100), lossless (PNG, WebP lossless); tools: Squoosh, Sharp (Node.js), ImageMagick. Lazy loading: loading='lazy' cho below-fold images; không lazy load LCP image. Preload LCP: <link rel='preload' as='image' href='hero.webp' imagesrcset='...' imagesizes='...'> cho critical images. LQIP (Low Quality Image Placeholder): show tiny blurred placeholder trong khi load — next/image placeholder='blur' prop. CDN và edge: serve images từ locations gần users; modern Image CDNs auto-convert format, resize, compress based on device. Sprites: combine nhiều icons thành một file — giảm HTTP requests; ngày nay SVG sprites hoặc icon fonts phổ biến hơn." },
  { id: 788, category: "Performance", subcategory: "Performance", level: "advanced", q: "Bundle analysis: cách phát hiện và giảm bundle size?", a: "Bundle analysis là bước đầu tiên khi optimize bundle size — không đoán mò, phải đo. Tools: webpack-bundle-analyzer (treemap visualization), vite-bundle-visualizer (rollup-plugin-visualizer), source-map-explorer (analyze actual bundle không phải estimates), bundlephobia.com (check package size trước khi install). Những gì cần tìm: Large dependencies có alternatives nhỏ hơn — moment.js (330KB) → date-fns/dayjs (10KB); lodash (71KB full) → lodash-es + tree shaking hoặc chỉ import specific: import debounce from 'lodash/debounce'; chart.js (200KB) → recharts (160KB) → victory (100KB). Duplicate modules: cùng dependency nhiều versions (webpack deduplication), cùng code ở nhiều chunks. Unexpected large modules: ví dụ icon library import toàn bộ thay vì specific icons — @mui/icons-material 30MB vs import MenuIcon from '@mui/icons-material/Menu' (một file). Giải pháp: Tree shaking (sideEffects: false trong package.json), code splitting + dynamic imports, externals (load React từ CDN thay vì bundle), Module Federation (share dependencies giữa micro-frontends). Compression context: gzip/Brotli reduce bundle size 60-80% — báo cáo compressed size thực tế, không raw. Benchmark: track bundle size trong CI với size-limit package — fail build nếu bundle vượt threshold." },
  { id: 789, category: "Performance", subcategory: "Performance", level: "advanced", q: "Service Worker và caching strategy trong PWA là gì?", a: "Service Worker là JavaScript running trong background thread, intercept network requests giữa app và network — foundation của PWA. Lifecycle: Install (cache precache assets) → Activate (cleanup old caches) → Fetch (intercept requests). Caching strategies: Cache First (check cache trước, fallback network — offline-first, dùng cho static assets, icon fonts); Network First (fetch từ network, fallback cache nếu offline — dùng cho API calls cần fresh data); Stale-While-Revalidate (serve từ cache immediately, fetch từ network để update cache background — balance speed và freshness, tốt cho non-critical data); Cache Only (chỉ cache, không network — precached resources); Network Only (không cache — real-time data). Background Sync: queue failed requests khi offline, retry khi network available — ví dụ submit form offline. Push Notifications: receive push messages từ server kể cả khi app không open — cần permission từ user. Workbox từ Google: abstraction layer cho Service Worker strategies — workbox-strategies, workbox-routing, workbox-precaching; tránh viết Service Worker boilerplate thủ công. vite-plugin-pwa tích hợp Workbox với Vite, tự động generate service worker. Pitfall: Service Worker cache bugs khó debug — phải explicitly update cache version khi deploy; chrome://serviceworker-internals để debug. HTTPS required (localhost exception)." },
  { id: 790, category: "Performance", subcategory: "Performance", level: "advanced", q: "Virtual scrolling (windowing) là gì? Khi nào cần dùng?", a: "Virtual scrolling (windowing) chỉ render DOM nodes cho items visible trong viewport — list 10,000 items chỉ render 20-50 items trong DOM tại bất kỳ thời điểm nào, maintain scroll position qua spacer elements. Mechanism: total height của list được set bằng container (tạo scrollbar đúng size), khi scroll, calculate which items should be visible, render chỉ those items với absolute positioning. Libraries: @tanstack/react-virtual (headless, flexible, không opinionated về UI — phổ biến nhất hiện tại); react-window (Brian Vaughn, smaller, simpler API cho fixed-size items); react-virtuoso (dynamic item heights, auto-measure). Khi cần dùng: list >100-200 items với complex rendering (images, many DOM nodes per item); performance profiling (React DevTools Profiler hoặc Chrome Performance tab) cho thấy list rendering là bottleneck — đừng premature optimize. Pitfall: virtual scrolling phức tạp hơn regular list — khó implement features như 'scroll to item', dynamic item heights, sticky headers; @tanstack/react-virtual có examples cho tất cả cases này. Variable height items: cần measure items sau render để tính scroll position — @tanstack/react-virtual và react-virtuoso handle dynamic heights tốt hơn react-window. Alternative đơn giản hơn khi list không quá dài: pagination hoặc 'load more' button — ít phức tạp, không cần virtual scrolling." },

  // === SECURITY (791-800) ===
  { id: 791, category: "Security", subcategory: "XSS & CSRF", level: "intermediate", q: "XSS (Cross-Site Scripting) là gì? Các loại XSS và cách phòng chống?", a: "XSS (Cross-Site Scripting) cho phép attacker inject và execute malicious scripts trong browser của victim, đánh cắp sessions, redirect users, modify page content. Ba loại: Stored XSS — script được lưu trong DB (comment, profile), mỗi user xem page bị attack; Reflected XSS — script trong URL parameter, server reflect lại trong response (phishing links); DOM-based XSS — client-side code đọc từ URL/storage và inject vào DOM mà không qua server (document.location, window.location.hash → innerHTML). Phòng chống: Context-appropriate encoding — HTML encode khi insert vào HTML, JS encode khi insert vào JavaScript, URL encode khi insert vào URL; React JSX tự động escape — dangerouslySetInnerHTML vẫn nguy hiểm. Không dùng innerHTML với user content — dùng textContent hoặc createElement. DOMPurify: sanitize HTML khi cần render user-provided HTML (rich text editor output) — DOMPurify.sanitize(userHtml). Content Security Policy: block inline scripts và unauthorized external scripts — defense in depth. HttpOnly cookies: JavaScript không thể đọc session cookie dù có XSS. Subresource Integrity (SRI): verify CDN scripts không bị tamper — integrity attribute trên <script>. Template literals và DOM APIs: const div = document.createElement('div'); div.textContent = userInput — safe; div.innerHTML = userInput — unsafe." },
  { id: 792, category: "Security", subcategory: "XSS & CSRF", level: "intermediate", q: "CSRF (Cross-Site Request Forgery) là gì? Cách phòng chống?", a: "CSRF (Cross-Site Request Forgery) exploit việc browser tự động gửi cookies khi request đến domain — attacker tạo form/image trên evil.com gửi request đến bank.com, browser tự động attach session cookie của user. Ví dụ: <img src='https://bank.com/transfer?to=attacker&amount=1000'> — nếu user đang logged in và bank không có CSRF protection, transfer xảy ra. Phòng chống: SameSite cookie attribute là defense chính hiện nay — SameSite=Strict: cookie không gửi trong bất kỳ cross-site request nào (bao gồm link navigation); SameSite=Lax (default Chrome): cookie gửi trong top-level GET navigation nhưng không trong POST/iframe/img — đủ cho hầu hết cases; SameSite=None: phải có Secure, gửi trong tất cả cross-site requests. CSRF tokens: random token lưu trong session, include trong form hidden field và verify server-side — attacker không thể đọc token vì same-origin policy. Double Submit Cookie: gửi token trong cả cookie và request body/header — server verify chúng match; không cần server-side state. Custom request headers (AJAX): XMLHttpRequest và fetch không thể set custom headers cross-origin mà không qua CORS preflight — thêm X-Requested-With: XMLHttpRequest hoặc Content-Type: application/json tự nhiên ngăn CSRF vì attacker không thể tạo cross-origin request với custom headers. Origin header checking: verify Origin/Referer header match expected domain — không đủ một mình vì có thể bị spoof trong một số cases." },
  { id: 793, category: "Security", subcategory: "CSP", level: "advanced", q: "Content Security Policy (CSP) là gì? Cách cấu hình?", a: "CSP (Content Security Policy) là HTTP header whitelist trusted sources cho scripts, styles, images, fonts — defense in depth chống XSS. default-src: fallback cho directives không specify; script-src: chỉ load scripts từ approved sources; style-src, img-src, font-src, connect-src (fetch/XHR), frame-src, form-action. Directives: 'self' (same origin), 'none' (block all), specific domains, 'unsafe-inline' (allow inline — weakens CSP), 'unsafe-eval' (allow eval — dangerous). Strict CSP với nonces: script-src 'nonce-{random}' — mỗi request tạo random nonce, inline scripts chỉ chạy nếu có matching nonce attribute; phòng chống injection tốt hơn domain whitelist. Hash-based: sha256-{base64hash} thay vì nonce cho static inline scripts. Report-Only mode: Content-Security-Policy-Report-Only header — observe violations mà không block, collect reports để debug trước khi enforce. report-uri/report-to: endpoint nhận violation reports dạng JSON — essential để monitor và catch issues sau deploy (ví dụ third-party script bị block). Trusted Types API: ngăn DOM XSS bằng cách enforce typed DOM operations — require-trusted-types-for 'script'. Pitfall: CSP với 'unsafe-inline' và 'unsafe-eval' cho toàn bộ site thực tế vô dụng — common mistake khi copy từ examples mà không hiểu. Bắt đầu với Report-Only, collect violations, fix, rồi enforce." },
  { id: 794, category: "Security", subcategory: "Authentication", level: "intermediate", q: "OAuth 2.0 là gì? Luồng Authorization Code flow hoạt động thế nào?", a: "OAuth 2.0 là authorization framework — delegated authorization (không phải authentication). Phân biệt: OAuth cho authorization (app có quyền gì), OpenID Connect (OIDC) là layer trên OAuth cho authentication (ai đang login, trả về ID token). Authorization Code flow chi tiết: 1) App redirect user đến Authorization Server với client_id, redirect_uri, scope, state (CSRF protection), code_challenge (PKCE); 2) User authenticate và consent; 3) Auth Server redirect về app với authorization code; 4) App exchange code cho access token qua back-channel request (POST, client_secret không expose trong URL); 5) App dùng access token để call protected APIs; 6) Refresh token để get new access token khi expire. PKCE (Proof Key for Code Exchange): app tạo code_verifier (random string), gửi code_challenge = hash(code_verifier) trong step 1, gửi code_verifier trong step 4 — server verify hash match — ngăn authorization code interception attack, bắt buộc cho public clients (SPA, mobile). Implicit flow: deprecated — trả access token trực tiếp trong URL, exposure risk. Client credentials flow: machine-to-machine, không có user — backend service gọi API. Scopes: granular permissions (read:email, write:calendar) — request chỉ scopes cần thiết. Token storage: access token trong memory (SPA), refresh token trong HttpOnly cookie — không dùng localStorage cho sensitive tokens." },
  { id: 795, category: "Security", subcategory: "Authentication", level: "intermediate", q: "HTTPS và TLS là gì? Tại sao bắt buộc phải dùng?", a: "HTTPS là HTTP over TLS (Transport Layer Security) — encrypt toàn bộ communication, verify server identity, đảm bảo data integrity. TLS handshake: Client Hello (supported cipher suites, TLS version) → Server Hello (chosen cipher, certificate) → Client verify certificate với CA (Certificate Authority) → Key exchange (ECDH — không share private key) → Session keys derived → Encrypted communication. Certificate chain: leaf certificate → intermediate CA → root CA (trusted bởi browser/OS); Let's Encrypt cung cấp free certificates tự động renew. HSTS (HTTP Strict Transport Security): Strict-Transport-Security: max-age=31536000; includeSubDomains — browser chỉ kết nối HTTPS trong 1 năm, ngăn SSL stripping attack; HSTS Preload list (chromium preload) — hardcoded trong browsers. TLS 1.3 improvements: 1-RTT handshake (vs TLS 1.2 2-RTT), 0-RTT resumption cho subsequent connections, removed insecure cipher suites. Certificate Transparency: public log của mọi issued certificate — detect unauthorized certificate issuance cho domain của bạn. Mixed content: HTTPS page load HTTP resources — browsers block active mixed content (scripts, XHR), warn về passive (images). Bắt buộc vì: MITM attack prevention, required cho HTTP/2 (browsers only support HTTP/2 over TLS), Service Workers, PWA, getUserMedia, required cho modern browser features; SEO ranking factor; browser 'Not Secure' warning tăng bounce rate." },
  { id: 796, category: "Security", subcategory: "CORS", level: "intermediate", q: "CORS là gì? Tại sao browser enforce same-origin policy?", a: "Same-origin policy ngăn JavaScript từ một origin (scheme+host+port) đọc response từ origin khác — bảo vệ khỏi CSRF và data theft. CORS cho phép server opt-in cho cross-origin requests qua response headers. Simple requests (GET/POST với basic Content-Type) không cần preflight — browser gửi request và check response headers. Preflight (OPTIONS request): cho non-simple requests (custom headers, PUT/DELETE, Content-Type: application/json) — browser gửi OPTIONS trước, server phải respond với allowed methods/headers trước khi browser gửi actual request. Response headers: Access-Control-Allow-Origin: https://trusted.com (hoặc * cho public APIs nhưng không thể dùng với credentials); Access-Control-Allow-Methods: GET, POST, PUT, DELETE; Access-Control-Allow-Headers: Content-Type, Authorization; Access-Control-Max-Age: 86400 (cache preflight 24h, giảm OPTIONS requests); Access-Control-Allow-Credentials: true (để gửi cookies/auth headers — phải specify exact origin, không dùng *). Common mistakes: add CORS headers ở nginx nhưng app cũng trả CORS headers → duplicate headers → browser reject; thêm * nhưng cần credentials → không work; không handle OPTIONS method trong route → 405 error. CORS chỉ restrict browser requests — Postman, curl, server-to-server không bị ảnh hưởng. Credentials mode: fetch(url, { credentials: 'include' }) gửi cookies; cần server set Access-Control-Allow-Credentials: true và exact origin." },
  { id: 797, category: "Security", subcategory: "Headers", level: "intermediate", q: "Security headers quan trọng trong web application là gì?", a: "Security headers là server response headers kiểm soát browser behavior để prevent attacks. Quan trọng nhất: Strict-Transport-Security: max-age=31536000; includeSubDomains (HSTS — force HTTPS, prevent SSL stripping, 1 năm duration); X-Content-Type-Options: nosniff (prevent MIME type sniffing — browser không tự đoán content type khác Content-Type header, ngăn polyglot file attacks); X-Frame-Options: DENY hoặc SAMEORIGIN (prevent clickjacking — page không thể được embed trong iframe của domain khác); CSP frame-ancestors thay thế X-Frame-Options và flexible hơn. Referrer-Policy: no-referrer-when-downgrade (default) hoặc strict-origin-when-cross-origin — control bao nhiêu URL info gửi trong Referer header; no-referrer cho sensitive pages. Permissions-Policy (thay thế Feature-Policy): kiểm soát browser APIs — Permissions-Policy: geolocation=(), camera=(), microphone=() — disable features không dùng đến. X-XSS-Protection: deprecated, browsers modern tự handle — không cần set. Cross-Origin-Opener-Policy: same-origin — isolate browsing context, enable SharedArrayBuffer, required cho high-resolution timers. Cross-Origin-Embedder-Policy: require-corp — cùng với COOP enable process isolation. Helmet.js trong Express: app.use(helmet()) tự động set tất cả headers với sensible defaults, có thể customize per-header. securityheaders.com để test và grade headers của site." },
  { id: 798, category: "Security", subcategory: "Authentication", level: "advanced", q: "SQL Injection là gì? Cách phòng chống trong Node.js?", a: "SQL Injection là attack inject SQL code qua user input để manipulate queries, bypass authentication, extract/delete data, hoặc execute OS commands (xp_cmdshell trong MSSQL). Classic example: username input là ' OR '1'='1' -- → query trở thành SELECT * FROM users WHERE username = '' OR '1'='1' -- ' AND password = '...' — luôn true, bypass login. Second-order injection: input được store vào DB, sau đó dùng trong query khác mà không sanitize — khó phát hiện. Phòng chống chính: parameterized queries/prepared statements — placeholder thay vì string concatenation: db.query('SELECT * FROM users WHERE id = $1', [userId]) — user input không bao giờ được interpret là SQL code. ORM như Prisma, Sequelize, TypeORM tự động parameterize — nhưng raw queries vẫn nguy hiểm nếu dùng template literals: prisma.$queryRaw`SELECT * FROM users WHERE id = ${userId}` (safe với tagged template) vs prisma.$queryRawUnsafe('SELECT * FROM users WHERE id = ' + userId) (unsafe). Stored procedures có thể vẫn bị nếu dùng dynamic SQL bên trong. Input validation là defense in depth nhưng không thể thay thế parameterized queries — validation có thể bị bypass. Principle of least privilege: DB user chỉ có quyền cần thiết — SELECT/INSERT/UPDATE nhưng không DROP TABLE, không xp_cmdshell. WAF (Web Application Firewall) thêm layer bảo vệ nhưng không đủ một mình." },
  { id: 799, category: "Security", subcategory: "Authentication", level: "advanced", q: "Cookie security: HttpOnly, Secure, SameSite attributes là gì?", a: "Cookie security attributes kiểm soát cookie exposure và transmission. HttpOnly: cookie không accessible qua document.cookie hay JavaScript — ngăn XSS đánh cắp session token; vẫn tự động gửi trong HTTP requests. Secure: cookie chỉ gửi qua HTTPS — ngăn network sniffing, bắt buộc trong production. SameSite: Strict (không gửi cookie trong bất kỳ cross-site request nào — kể cả click link từ email đến site của bạn; rất secure nhưng friction cao cho federated services); Lax (gửi trong top-level navigation GET nhưng không trong img/iframe/fetch cross-site — good balance, default Chrome từ 2020); None (gửi tất cả cross-site — phải kết hợp với Secure, dùng cho third-party cookies như OAuth flows, embedded widgets). Best practice cho session cookies: Set-Cookie: sessionId=abc; HttpOnly; Secure; SameSite=Lax; Path=/; Max-Age=3600. Cookie prefixes tăng security: __Secure- prefix (phải có Secure flag, HTTPS only); __Host- prefix (phải có Secure, không có Domain, Path=/ — strongest, pinned to host). Max-Age vs Expires: Max-Age (seconds relative) ưu tiên hơn Expires (absolute datetime) vì không phụ thuộc client clock. Session vs Persistent cookies: session cookie (không có Max-Age/Expires) bị xóa khi browser close; persistent có expiry. Third-party cookies: đang bị phase out bởi browsers — Privacy Sandbox, Storage Access API là alternatives." },
  { id: 800, category: "Security", subcategory: "Security", level: "advanced", q: "Dependency security: cách quản lý vulnerabilities trong npm packages?", a: "Dependency security quản lý supply chain risks — dependencies là attack vector phổ biến (log4shell, event-stream incident, ua-parser-js hijack). npm audit: scan known vulnerabilities trong CVE databases, npm audit --json để parse programmatically; npm audit fix tự fix patch versions, --force cho major versions (cẩn thận breaking changes). Mức severity: critical/high cần fix ngay; moderate/low assess risk trước. Dependabot (GitHub built-in): tự động tạo PRs để update dependencies với changelogs — configure trong .github/dependabot.yml với schedule và allowed update types. Renovate (Mend): alternative mạnh hơn Dependabot, grouping updates, auto-merge với passing CI, monorepo support. Snyk: deeper scanning (không chỉ CVEs), license compliance, container scanning, IaC scanning, IDE plugins. Socket.dev: phân tích behavior của packages (không chỉ known CVEs) — detect typosquatting, suspicious code patterns, permission escalation. Nguyên tắc: lock file (package-lock.json, pnpm-lock.yaml) phải commit — reproducible installs; không run npm install --legacy-peer-deps trong production bừa bãi; review package trước install (bundlephobia size, npm downloads, GitHub activity, last publish); prefer packages ít dependencies (dependency tree nhỏ = attack surface nhỏ). Software Bill of Materials (SBOM): generate list of all dependencies và versions — compliance requirement cho enterprise và government. npm publish với provenance — verify package genuinely published từ specific CI run." },
]
